INSERT INTO course (course_id, name, abbreviation, credits, description, department_id) VALUES
(1, 'Computer Proficiency', 'COE 201', 1, 'This course covers word processing, spreadsheet, presentation software, internet, e-mail, database, and web design.', 1),
(2, 'Computer Programming', 'COE 211', 4, 'This course covers a high-level programming language syntax, structured programming, basic constructs, arrays, object programming, case studies, and projects tailored towards solving engineering and mathematically-oriented problems.', 1),
(3, 'Engineering Programming', 'COE 212', 3, 'This course covers a high-level programming language syntax, structured programming, basic constructs, arrays, object programming, case studies, and projects tailored towards solving engineering and mathematically-oriented problems.', 1),
(4, 'Engineering Programming', 'COE 212H', 3, 'This course covers a high-level programming language syntax, structured programming, basic constructs, arrays, object programming, case studies, and projects tailored towards solving engineering and mathematically-oriented problems.', 1),
(5, 'Data Structures', 'COE 312', 3, 'This course covers the programming principles, stacks and recursion, queues, lists, searching, and sorting algorithms, binary trees, and the introduction to object-oriented programming concepts.', 1),
(6, 'Data Structures Lab', 'COE 313', 1, 'This Lab provides hands-on experience in designing, implementing, and using the most-commonly used data structures including arrays, stacks, queues, linked lists, trees, hash tables, and graphs. Other topics may include sorting algorithms, polymorphism, and recursion.', 1),
(7, 'Logic Design', 'COE 321', 3, 'This course provides an introduction to digital logic circuits and covers binary number representations, combinational logic design, Boolean algebra, arithmetic circuits, regular logic, programmable logic devices, flip flops, registers, counters, sequential state machines, and asynchronous and synchronous logic.', 1),
(8, 'Logic Design Lab', 'COE 322', 1, 'This laboratory course provides hands-on experience implementing digital logic design systems using modern computer-aided design tools, discrete components, breadboards, and digital probes.', 1),
(9, 'Microprocessors', 'COE 323', 3, 'This course covers the internals of the microprocessor and assembly language, storing, manipulating, moving data, basics of control flow, interfacing to other devices, basics of writing good assembly code using the stacks and position independent codes.', 1),
(10, 'Microprocessors Lab', 'COE 324', 1, 'This is a lab course with experiments in microprocessors.', 1),
(11, 'Operating Systems', 'COE 414', 3, 'This course provides an overview of operating systems and provide the basic structure and architecture of some operating systems in the market. This course covers the process creation, management, synchronization, communications, and scheduling. Memory management and protection.', 1),
(12, 'Computer Programming II', 'COE 415', 3, 'This course covers advanced object-oriented programming techniques, including composition, inheritance, and polymorphism. Students will learn to design and implement efficient programs using design patterns. The course also covers algorithmic analysis, testing, exception handling, recursion, and advanced sorting algorithms. By the end of the course, students will have gained practical skills in algorithm design and program development. Pre-requisites: COE211 Computer Programming', 1),
(13, 'Computer Programming II Lab', 'COE 415B', 1, 'Pre-requisites: COE415 Computer Programming II', 1),
(14, 'Software Engineering', 'COE 416', 3, 'This course covers the analysis, development, design and documentation of software.', 1),
(15, 'Database Systems', 'COE 418', 3, 'This course covers the data modeling, relational database, SQL, query languages, object oriented databases, and client-server databases.', 1),
(16, 'Computer Architecture', 'COE 423', 3, 'This course introduces computer components and systems. Topics include evolution of computer systems, bus interconnections, I/O mechanisms, memory management and hierarchy, instruction set design, and basic pipelined techniques.', 1),
(17, 'Digital Systems', 'COE 424', 3, 'This course is an introduction to digital systems design and covers timing concepts, area-delay tradeoffs, pipelining, and synthesis. Register transfer notation and VHDL are introduced to model, simulate, and verify designs. Topics include field-programmable gate arrays, technology mapping, layout synthesis, and routing.', 1),
(18, 'Digital Systems Lab', 'COE 425', 1, 'This laboratory course provides hands-on experience implementing complex digital systems using modern computer-aided design tools, FPGA-based boards, and various I/O devices.', 1),
(19, 'Computer Networks', 'COE 431', 3, 'This course covers the topologies, installation and configuration, testing, modeling and simulation of networks. In addition to: protocols, standards, TCP/IP, and socket programming.', 1),
(20, 'Professionalism in Engineering', 'COE 493', 3, 'This course provides an overview of the nature and scope of engineering profession and the critical role of sustainable development in engineering solutions. It includes working in multidisciplinary team environments, exploring professional and ethical responsibilities, and analyzing the impact of engineering in a global and societal context. Students will engage with the United Nations’ Sustainable Development Goals (SDGs), connecting every course project to one or more SDGs. The course also covers lifelong learning and contemporary issues in engineering. Pre-requisite: Third year standing', 1),
(21, 'Professional Experience', 'COE 498', 6, 'This course entails professional experience through training in the execution of real-life engineering projects.', 1),
(22, 'Embedded Systems', 'COE 521', 3, 'This course provides an introduction to the design of embedded systems including both their hardware and software. Topics ranging from simple circuit design to computer architecture will be discussed. Different types of processors will be presented along with interfacing to memories, I/O devices, and other processors. The 68HC12 or PIC microcontrollers will be used as an example processor for assignments and the course project.', 1),
(23, 'High Performance Computer Architecture', 'COE 522', 3, 'This course covers topics in advanced pipelined techniques and scheduling, instruction level parallelism, and dynamic scheduling. Advanced processor design techniques are introduced such as superscalar, super-pipelined, VLIW, multiprocessing, multithreading, and supercomputing architectures. In addition, relationships between high-performance computing and interconnection networks, embedded systems, advanced storage systems, and cloud computing examples are established.', 1),
(24, 'VLSI Design Automation (Last Offered: Fall 2012)', 'COE 526', 3, 'This course covers the algorithms and methodologies for the synthesis, analysis, and verification of digital systems, silicon compilation, high-level synthesis, logic synthesis, and layout synthesis, hardware description languages and their use in the synthesis process, fault simulation and coverage analysis, and the extensive use of electronic design automation Tools. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 1),
(25, 'VLSI Design (Last Offered: Spring 2019)', 'COE 527', 3, 'This course covers the VLSI design, circuits’ layout, timing, delay, power estimation, use of layout editors and circuit simulation tools, synthesis, and an introduction to electronic design automation. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 1),
(26, 'Testing for Digital Integrated Circuits (previously offered as COE599F)', 'COE 529', 3, '[3-0, 3 cr.] This course covers the essentials of electronic testing for digital ULSI circuits, design methods, and design for testability. Topics include introduction to the testing process, fault modeling and detection, logic and fault simulation, testability measures, test generation for combinational circuits, test generation for sequential circuits, design for testability, built-in self-testing, ATPG-based logic synthesis, Boundary Scan, and system test and core-based design.', 1),
(27, 'Optical Networks (Last Offered: Fall 2011)', 'COE 535', 3, 'This course covers the fundamentals of optical networking. In particular, it touches on the following topics: the building blocks of optical wavelength division multiplexed networks, wavelength division multiplexing (WDM) and its enabling technologies, WDM-based access and metro optical network architectures, wavelength-routed optical wavelength division multiplexed networks used for wide area coverage, optical burst switched networks, and optical packet switched networks. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 1),
(28, 'Intelligent Data Processing and Applications', 'COE 543', 3, 'This course provides an overview on state of the art algorithms and techniques allowing semi-structured and semantic-aware data processing, forming the main building blocks of the Semantic (Intelligent) Web vision. It covers semantic data descriptions and knowledge bases (taxonomies and ontologies), XML-based data representation and manipulation technologies (e.g., SVG, MPEG-7, RDF, OWL, etc.), structure and semantic similarity, Web information retrieval and related applications.', 1),
(29, 'Intelligent Engineering Algorithms', 'COE 544', 3, NULL, 1),
(30, 'Information Security', 'COE 545', 3, 'This course provides an introduction to the topic of information security in the context of network communication. It is intended for students who have some understanding of networks, but not necessarily any background in security. The goal of the course is to provide students with a foundation that will help them to identify, analyze and make appropriate security decisions during the design and deployment of information and network systems.', 1),
(31, 'Machine Learning', 'COE 546', 3, 'This course provides a comprehensive introduction to the field of machine learning, covering fundamental concepts, techniques, and applications. Students will gain a foundation in both theoretical principles and hands-on coding. The course is organized to progressively guide students through various aspects of machine learning, from the basics to more advanced topics in machine learning.', 1),
(32, 'Deep Learning', 'COE 547', 3, 'This course provides a comprehensive introduction to the field of deep learning, covering fundamental concepts, techniques, and applications. Students will gain a foundation in both theoretical principles and hands-on coding. The course is organized to progressively guide students through various aspects of deep learning, from the basics to more advanced topics.', 1),
(33, 'Large Language Models', 'COE 548', 3, 'Foundations of natural language processing (NLP); deep learning and neural networks basics; transformer models and attention mechanisms; advancements in LLMs; application-specific tuning; practical exercises with off-the-shelf and open-source LLMs; addressing scalability and ethical considerations in AI. This course combines theoretical knowledge with practical applications, providing a comprehensive overview of current LLM technologies and their impact.', 1),
(34, 'Advanced Large Language Models', 'COE 549', 3, NULL, 1),
(35, 'Reinforcement Learning', 'COE 550', 3, 'This course introduces the core principles and algorithms of Reinforcement Learning, focusing on how agents learn optimal behavior through interaction with an environment to maximize cumulative rewards. Students will build a foundation in Markov decision processes, dynamic programming, Monte Carlo methods, and temporal-difference learning. The course also covers topics such as exploration strategies, multi-armed bandits, policy gradient methods, Deep Reinforcement Learning, and Reinforcement Learning from Human Feedback. Pre-requisites : (GNE331 or MTH305) and (COE211 or COE212) and fourth-year standing.', 1),
(36, 'Computer Vision and Deep Learning (last offered: Fall 2022)', 'COE 554', 3, 'This course is concerned with understanding the fundamentals of computer vision and deep learning with applications in visual classification and processing.', 1),
(37, 'Queuing Theory (Last Offered: Spring 2020)', 'COE 555', 3, 'This course introduces two modeling techniques, namely simulation and queuing modeling techniques. The following topics are discussed in this regard: single queue Markovian systems, semi-Markovian queuing systems, open queueing networks, closed queueing networks, pseudo-random number generation, estimation techniques for analyzing endogenously created data, and validation of a simulation design. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 1),
(38, 'Computer Engineering Applications', 'COE 593', 3, 'This course allows COE graduates to acquire the technical skills that are required to match a specific industry-related need. In particular, it exposes students to the techniques, which can improve their chances of gaining employment in jobs aligned with the considered need. This exposure is reinforced by an extensive hands-on experience that is brought into classroom through small-scale projects pertaining to problems inspired from the identified need.', 1),
(39, 'Undergraduate Research Project (Last Offered: Spring 2023)', 'COE 594', 3, 'Engagement in a research project under the direction of a faculty member with emphasis on problem identification, formulation and solution. Requires a formal research report in the form of a paper. This course is considered as a technical elective (ECE elective).', 1),
(40, 'Undergraduate Research Project (Last Offered: Spring 2023)', 'COE 594H', 3, 'Engagement in a research project under the direction of a faculty member with emphasis on problem identification, formulation and solution. Requires a formal research report in the form of a paper. This course is considered as a technical elective (ECE elective).', 1),
(41, 'Capstone Design Project I', 'COE 595', 3, 'The course is devoted to the solution of open-ended engineering design projects with functional specifications and realistic constraints. This project provides a study of multiple solutions for a major design experience while accounting for multiple realistic constraints and relevant standards. The study is concluded by a written report and an oral presentation providing a course of action for the fulfilment of the project. This course is the first part of a two course sequence (COE595 and COE596). Restrictions: Fifth year standing', 1),
(42, 'Capstone Design Project II', 'COE 596', 3, 'The course is devoted to the solution of open-ended engineering design projects with functional specifications and realistic constraints. This project provides a culminating major design experience that is concluded by a written report and an oral presentation. This course is the final part of a two course sequence (COE595 and COE596).', 1),
(43, 'Research Methods', 'COE 598H', 3, 'Introduction to methods for improving and developing research skills; including: principles of scientific research, ethics, writing skills, methods for compiling scientific literature, identification of research questions and specific hypotheses, presentation of research results, writing research papers, proposal preparation, preparation of grant proposals, thesis and dissertation.', 1),
(44, 'Topics in Computer Engineering', 'COE 599', 3, 'This course covers the treatment of new developments in various areas of computer engineering.', 1),
(45, 'Topics: Programming for Data Science', 'COE 599E', 3, 'This course introduces the essential elements of data science: importing, cleaning, manipulating, and visualizing data. Students also work on different datasets to learn the statistical and machine learning techniques needed to perform hypothesis testing and build predictive models. Students will gain experience using the Python programming language and Jupyter notebooks. This is a computing course focused on programming and algorithms.', 1),
(46, 'High Performance Computer Architecture (Offered with COE522)', 'COE 723', 3, 'This course covers topics in advanced pipelined techniques and scheduling, instruction level parallelism, and dynamic scheduling. Advanced processor design techniques are introduced such as superscalar, super-pipelined, VLIW, multiprocessing, multithreading, and supercomputing architectures. In addition, relationships between high-performance computing and interconnection networks, embedded systems, advanced storage systems, and cloud computing examples are established.', 1),
(47, 'VLSI Design (Offered with COE527)', 'COE 725', 3, 'This course covers the VLSI design, circuits’ layout, timing, delay, power estimation, use of layout editors and circuit simulation tools, synthesis, and an introduction to electronic design automation. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 1),
(48, 'VLSI Design Automation (Last Offered: Fall 2012)', 'COE 726', 3, 'This course covers the algorithms and methodologies for the synthesis, analysis, and verification of digital systems, silicon compilation, high-level synthesis, logic synthesis, and layout synthesis, hardware description languages and their use in the synthesis process, fault simulation and coverage analysis, and the extensive use of electronic design automation Tools. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 1),
(49, 'ULSI Testing (Last Offered: Fall 2013)', 'COE 728', 3, 'This course covers the problems of testing of Ultra Large Scale Integrated Circuits (ULSI), the design of circuits for testability, the design of built-in self-testing circuits, and the use of the IEEE Boundary Scan Standards. Topics include introduction to the testing process, fault modeling and detection, logic and fault simulation, testability measures, test generation for combinational circuits, test generation for sequential circuits, design for testability, built-in self-test, delay testing, current testing, ATPG-based logic synthesis, system test, and core-based design, and testing a system-on-a-chip (SOC). Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 1),
(50, 'Testing for Digital Integrated Circuits (Offered with COE529)', 'COE 729', 3, 'This course covers the essentials of electronic testing for digital ULSI circuits, design methods, and design for testability. Topics include introduction to the testing process, fault modeling and detection, logic and fault simulation, testability measures, test generation for combinational circuits, test generation for sequential circuits, design for testability, built-in self-testing, ATPG-based logic synthesis, Boundary Scan, and system test and core-based design.', 1),
(51, 'Networks Security (Last Offered: 2010)', 'COE 732', 3, 'This course is an introduction to network security, including developing an understanding of security engineering, cryptography, mechanisms to protect private communication over public network, and techniques to protect networked computer systems. This course considers the technical, operational, and managerial issues of computer systems, and network security in an operational environment. The course will address the threats to computer security, including schemes for breaking security, and techniques for detecting and preventing security violations. Emphasis will be on instituting safeguards, examining the different types of security systems, and applying the appropriate level of security for the perceived risk. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 1),
(52, 'Optical Networks (Offered with COE535)', 'COE 733', 3, 'This course covers the fundamentals of optical networking. In particular, it touches on the following topics: the building blocks of optical wavelength division multiplexed networks, wavelength division multiplexing (WDM) and its enabling technologies, WDM-based access and metro optical network architectures, wavelength-routed optical wavelength division multiplexed networks used for wide area coverage, optical burst switched networks, and optical packet switched networks. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 1),
(53, 'Artificial Intelligence', 'COE 741', 3, 'This course is an introduction to artificial intelligence concepts, heuristic search, clause form logic, knowledge representation, reasoning and inference, an overview of the computer vision, planning, natural language, Lisp, and Prolog. Subjects covered may include unification and resolution in first order logic, graph search algorithms, planning, game playing, heuristic classifiers, knowledge engineering, and uncertainty management. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 1),
(54, 'Intelligent Data Processing and Applications (Offered with COE543)', 'COE 743', 3, 'This course provides an overview on state of the art algorithms and techniques allowing semi-structured and semantic-aware data processing, forming the main building blocks of the Semantic (Intelligent) Web vision. It covers semantic data descriptions and knowledge bases (taxonomies and ontologies), XML-based data representation and manipulation technologies (e.g., SVG, MPEG-7, RDF, OWL, etc.), structure and semantic similarity, Web information retrieval and related applications.', 1),
(55, 'Intelligent Engineering Algorithms (Offered with COE544)', 'COE 744', 3, NULL, 1),
(56, 'Information Security (Offered with COE545)', 'COE 745', 3, 'This course provides an introduction to the topic of information security in the context of network communication. It is intended for students who have some understanding of networks, but not necessarily any background in security. The goal of the course is to provide students with a foundation that will help them to identify, analyze and make appropriate security decisions during the design and deployment of information and network systems.', 1),
(57, 'Machine Learning (Offered with COE546)', 'COE 746', 3, 'This course provides a comprehensive introduction to the field of machine learning, covering fundamental concepts, techniques, and applications. Students will gain a foundation in both theoretical principles and hands-on coding. The course is organized to progressively guide students through various aspects of machine learning, from the basics to more advanced topics in machine learning.', 1),
(58, 'Deep Learning (Offered with COE547)', 'COE 747', 3, 'This course provides a comprehensive introduction to the field of deep learning, covering fundamental concepts, techniques, and applications. Students will gain a foundation in both theoretical principles and hands-on coding. The course is organized to progressively guide students through various aspects of deep learning, from the basics to more advanced topics.', 1),
(59, 'Large Language Models (LLMs) (Offered with COE548)', 'COE 748', 3, 'Foundations of natural language processing (NLP); deep learning and neural networks basics; transformer models and attention mechanisms; advancements in LLMs; application-specific tuning; practical exercises with off-the-shelf and open-source LLMs; addressing scalability and ethical considerations in AI. This course combines theoretical knowledge with practical applications, providing a comprehensive overview of current LLM technologies and their impact.', 1),
(60, 'Advanced Large Language Models', 'COE 749', 3, NULL, 1),
(61, 'Reinforcement Learning', 'COE 750', 3, NULL, 1),
(62, 'Design and Analysis of Algorithms (Last offered: Fall 2011)', 'COE 752', 3, 'This course covers the time and space complexity of algorithms. It looks at the models of computation, the techniques for efficient algorithm design, and the effect of data structure choice on the efficiency of an algorithm, as well as the divide and conquer techniques, greedy methods, dynamic programming, amortized analysis, graph and network algorithms, NP-completeness, and selected advanced algorithms. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 1),
(63, 'Heuristic Optimization', 'COE 753', 3, 'This course covers the basic heuristic optimization techniques in computing. This course describes a variety of heuristic search methods including serial simulated annealing, Tabu search, genetic algorithms, ant algorithms, derandomized evolution strategy, and random walk. Algorithms will be described in serial as well as in parallel fashion. Students can select application projects from a range of application areas. The advantages and disadvantages of heuristic search methods, for both serial and parallel computation, are discussed in comparison to other optimization algorithms. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 1),
(64, 'Queuing Theory (Offered with COE555)', 'COE 755', 3, 'This course introduces two modeling techniques, namely simulation and queueing modeling techniques. The following topics are discussed in this regard: single queue Markovian systems, semi-Markovian queueing systems, open queueing networks, closed queueing networks, pseudo-random number generation, estimation techniques for analyzing endogenously created data, and validation of a simulation design. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 1),
(65, 'Computer Vision and Deep Learning  (Offered with COE554)', 'COE 774', 3, 'This course is concerned with understanding the fundamentals of computer vision and deep learning with applications in visual classification and processing.', 1),
(66, 'Thesis', 'COE 899', 6, 'This is a Master’s thesis research course under the direction of a faculty member.', 1),
(67, 'Electric Circuits', 'ELE 300', 3, 'This course covers resistors, capacitors and inductors; voltage and current sources; voltage and current laws, node and mesh analysis, network theorems, power and energy; ideal operational amplifiers; DC and sinusoidal excitation of circuits, time-domain and frequency-domain response of circuits; transfer functions; transformers, resonant circuits and filter design.', 2),
(68, 'Electrical Circuits Lab', 'ELE 303', 1, 'This is a lab course with experiments in Electrical Circuits II.', 2),
(69, 'Introduction to Electrical Engineering', 'ELE 305', 3, 'This course introduces the concepts of resistors, capacitors and inductors, voltage and current sources, operational amplifiers, voltage and current laws, node and mesh analysis, network theorems, power and energy, three-phase circuits, logic circuits, and binary representations .', 2),
(70, 'Mathematical Methods in Electrical Engineering', 'ELE 391', 3, 'This course introduces foundation knowledge of complex variables and linear algebra with applications to electrical engineering. Topics covered are vector spaces, subspaces, linear dependence/independence, basis; linear transformations and Eigen structure analysis; matrix representations of linear electrical systems; analytic functions of complex variables and contour integrals; Cauchy integral formula.', 2),
(71, 'Electronics I', 'ELE 401', 3, 'Introduction to electronic circuits using operational amplifiers, PN junction diodes, bipolar junction transistors (BJTs), and MOS field-effect transistors (MOSFETs), including: terminal characteristics, large and small-signal models; configuration and frequency response of single-stage amplifiers with discrete biasing.', 2),
(72, 'Electronics I Lab', 'ELE 402', 1, 'This Laboratory explores miscellaneous electronic components. Students perform hands-on experiments to analyze circuits that are based on operational amplifiers, Silicon diodes, Zener diodes, Bipolar Junction Transistors (BJTs), and Metal Oxide Silicon Field Effect Transistors (MOSFETs). Students also evaluate circuits with sensors such as Light-dependent resistors and Photodiodes.', 2),
(73, 'Electromagnetic Fields', 'ELE 411', 3, 'Fundamental concepts of the electromagnetic model, vector analysis, static electric fields, static magnetic fields, steady electric currents, Maxwell’s equations, Coulomb’s law, Gauss’s law, Biot-Savart law, Faraday’s law, Poisson’s and Laplace’s equations, Joule’s law, capacitance calculations, inductance calculations, resistance calculations.', 2),
(74, 'Electromagnetic Waves', 'ELE 413', 3, 'Fundamental concepts of electromagnetic waves, Maxwell’s equations, propagation of plane electromagnetic waves, theory and application of transmission lines, waveguides, antennas.', 2),
(75, 'Electromechanics', 'ELE 420', 3, 'This course covers three-phase circuit concepts; magnetic circuits; magnetic fields and their surroundings; linear DC machines; power transformers and autotransformers; principles of electric AC machines; synchronous generators; three-phase induction motors.', 2),
(76, 'Power Systems', 'ELE 422', 3, 'This course provides students with a working knowledge of power system problems and computer techniques to solve some of these problems. Topics include: review of three-phase analysis, complex power, per-unit system, synchronous machines, transformers, autotransformers, and regulating transformers; calculation of transmission line parameters, evaluation of steady state operation of transmission lines; reactive power compensation; line capability; power flow analysis using Gauss-Seidel and Newton-Raphson methods.', 2),
(77, 'Electric Machines Lab', 'ELE 423', 1, 'This course covers the following experiments to study various aspects of electric machines and power systems: fundamentals of electrical power technology; alternating currents; power and impedance in ac circuits; three-phase circuits; single-phase and three-phase transformers; fundamentals of rotating machines; dc motors and generators; ac induction motors; three-phase synchronous generators and motors.', 2),
(78, 'Signals and Systems', 'ELE 430', 3, 'Signal and system modeling concepts; system modeling and analysis in time domain; the Fourier series; the Fourier transform and its applications; the Laplace transformation and its applications; discrete-time signals and systems; z-transform; analysis and design of digital filters; DFT and FFT.', 2),
(79, 'Control Systems', 'ELE 442', 3, 'This course covers modeling and dynamical systems, transient-response analysis, response of control systems, root locus analysis, and modern control (state space).', 2),
(80, 'Control Systems Lab', 'ELE 443', 1, 'Laboratory experiments in Control Systems. This course introduces students to the implementation of PID- controllers and two-step controllers, first order delay as well as third order delay, such implementation are done using educational PID boards and DC servo boards. Experimentations and analysis use Industrial standard oscilloscopes, and data-acquisition boards interfaced via SIMULINK/MATLAB.', 2),
(81, 'Professionalism in Engineering', 'ELE 493', 3, 'This course provides an overview of the nature and scope of engineering profession and the critical role of sustainable development in engineering solutions. It includes working in multidisciplinary team environments, exploring professional and ethical responsibilities, and analyzing the impact of engineering in a global and societal context. Students will engage with the United Nations’ Sustainable Development Goals (SDGs), connecting every course project to one or more SDGs. The course also covers lifelong learning and contemporary issues in engineering. Restrictions: Third year standing.', 2),
(82, 'Professional Experience', 'ELE 498', 6, 'This course entails professional experience through training in the execution of real-life engineering projects. Restrictions: Final year standing and the consent of the instructor.', 2),
(83, 'Microelectronics', 'ELE 501', 3, 'This course provides students with advanced knowledge of integrated circuit theory. Topics include: Single-stage integrated circuit amplifiers; differential and multi-stage amplifiers, integrated-circuits biasing techniques; non-ideal characteristics; frequency response; feedback amplifiers; output stages; digital CMOS logic circuits.', 2),
(84, 'Electricity Markets & Renewable Energy', 'ELE 520', 3, 'This course focuses on the fundamental concepts of competitive electricity markets and introduces the models and tools that are needed to understand and analyze them. Additionally, it explores how market incentives can be used to promote the development of renewable energy and, in turn, how renewable energy affects the operation of electricity markets.', 2),
(85, 'Electrical Energy Storage Systems', 'ELE 521', 3, 'This course covers different types of electrical energy storage systems. It provides a broad understanding of the operating principles and the sizing techniques based on Ragone relation. Topics covered include energy and power analysis, secondary batteries with a focus on lithium-ion batteries, conventional supercapacitors, hybrid supercapacitors, modelling techniques, and state of charge and state of health estimation methods. Hybrid systems that combine two or more energy storage systems will be also discussed.', 2),
(86, 'Faulted Power Systems', 'ELE 525', 3, 'This course provides students with advanced knowledge of power system evaluation techniques. Topics include: economic load dispatch with generation limits and line losses; impedance model; three-phase symmetrical faults; symmetrical components; and unsymmetrical faults analysis.', 2),
(87, 'Renewable Energy Sources', 'ELE 526', 3, 'This course introduces students to the challenges of sustainable energy development that are addressed under the framework of the UN Sustainable Development Goals (SDGs), which consists of 17 urgent actions by all countries – developed and developing – in a global partnership.  The course introduces renewable energy technologies (e.g., hydropower, wind, solar, etc.) and illustrates how they achieve the targets of SDG7 (Affordable and Clean Energy).  At the conclusion of the course, students will have a solid technical and economic understanding of these renewable energy technologies. Restrictions: Senior Standing.', 2),
(88, 'Design and Operation of Smart Grids', 'ELE 529', 3, NULL, 2),
(89, 'Optical Fiber Communications (Last Offered Fall 2019)', 'ELE 531', 3, 'Basic principles of point-to-point optical fiber communications, waveguiding and signal degradation in optical fibers, optical sources, photodetectors, WDM components, dimensioning of fiber links for analog and digital transmissions, performance of digital optical communication systems in the presence of noise.', 2),
(90, 'Information and Coding Theory', 'ELE 535', 3, 'Information theory applied to communication systems. It covers digital signals and streams, information measures, data compression, error-correcting codes, block codes, convolutional codes, Viterbi algorithm, noise, maximum-entropy, Markov chains, channel capacity formalism and Shannon’s theorem.', 2),
(91, 'Communication Systems', 'ELE 537', 3, 'Basic principles of point-to-point communication link design and analysis, introduction to the theory and principles of modern communication systems, overview of the currently used analog and digital communication techniques and their relative advantages and disadvantages, analog modulation and demodulation, component parts used in analog and digital transceivers.', 2),
(92, 'Noise in Communication Systems', 'ELE 538', 3, 'This course covers physical noise sources, noise calculations in communication systems, stochastic processes, and communication systems performance in the presence of noise.', 2),
(93, 'Telecommunication Systems', 'ELE 539', 3, 'This course covers spread spectrum and data communications, microwave and satellite links, optical fiber, mobile radio systems, the evolution of mobile radio communications including 2G, 2.5G and 3G, cellular concept, and mobile radio propagation including large-scale path loss.', 2),
(94, 'Communication Systems Lab', 'ELE 540', 1, 'This is a lab course with experiments in communication systems. The experiments implement the modulation and the demodulation techniques acquired in the communication system course through modulation and demodulation boards and through MATLAB.', 2),
(95, 'Linear Systems (Last Offered Fall 2010)', 'ELE 548', 3, 'This course covers the canonical realization of transfer functions, state observability and controllability, state feedback and asymptotic observers, reduced order observers, and regulator design. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 2),
(96, 'Digital Image and Video Processing and Compression', 'ELE 552', 3, 'This course is concerned with understanding the fundamentals of digital image and video perception, representation, processing, understanding, and compression.', 2),
(97, 'Reliability Evaluation of Engineering Systems', 'ELE 553', 3, 'This course covers the basic reliability concepts, elements of probability and statistical theory, application of important distributions, reliability in series, parallel and complex systems, application of Markov chains in the evaluation of repairable system reliability, application of Markov processes for reliability evaluation of complex systems, and the utilization of MonteCarlo simulation in basic system reliability evaluation.', 2),
(98, 'Simulation of Electronic Circuits', 'ELE 557', 3, 'This course covers the principles of efficient electronic circuit simulation using numerical methods and techniques. Topics include the formulation of network equations, dc analysis, frequency domain analysis, simulation of nonlinear networks, transient analysis, sensitivity analysis and model order reduction. The simulation of specialized circuits is also considered, including the analysis of radio frequency circuits and high-speed interconnects. In addition, students will learn how to implement circuit simulation methods using mathematical software tools.', 2),
(99, 'Electrical Engineering Applications', 'ELE 593', 3, 'This course allows ELE graduates to acquire the technical skills that are required to match a specific industry-related need. In particular, it exposes students to the techniques, which can improve their chances of gaining employment in jobs aligned with the considered need. This exposure is reinforced by an extensive hands-on experience that is brought into classroom through small-scale projects pertaining to problems inspired from the identified need. Pre-requisite: Fourth-year standing', 2),
(100, 'Undergraduate Research Project (Last Offered: Spring 2023)', 'ELE 594', 3, 'Engagement in a research project under the direction of a faculty member with emphasis on problem identification, formulation and solution. Requires a formal research report in the form of a paper. This course is considered as a technical elective (ECE elective).', 2),
(101, 'Undergraduate Research Project (Last Offered: Spring 2023)', 'ELE 594H', 3, 'Engagement in a research project under the direction of a faculty member with emphasis on problem identification, formulation and solution. Requires a formal research report in the form of a paper. This course is considered as a technical elective (ECE elective).', 2),
(102, 'Capstone Design Project I', 'ELE 595', 3, 'The course is devoted to the solution of open-ended engineering design projects with functional specifications and realistic constraints. This project provides a study of multiple solutions for a major design experience while accounting for multiple realistic constraints and relevant standards. The study is concluded by a written report and an oral presentation providing a course of action for the fulfilment of the project. This course is the first part of a two course sequence (ELE595 and ELE596) . Restrictions: Fifth year standing', 2),
(103, 'Capstone Design Project II', 'ELE 596', 3, 'The course is devoted to the solution of open-ended engineering design projects with functional specifications and realistic constraints. This project provides a culminating major design experience that is concluded by a written report and an oral presentation. This course is the final part of a two course sequence (ELE 595 and ELE 596).This course is the final part of a two course sequence (ELE595 and ELE596).', 2),
(104, 'Topics in Electrical Engineering', 'ELE 599', 3, 'This course covers the treatment of new developments in various areas of Electrical Engineering. Restrictions: Fifth-year standing Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 2),
(105, 'Electricity Markets & Renewable Energy', 'ELE 720', 3, NULL, 2),
(106, 'Electrical Energy Storage Systems (OFFERED WITH ELE521)', 'ELE 721', 3, 'This course covers different types of electrical energy storage systems. It provides a broad understanding of the operating principles and the sizing techniques based on Ragone relation. Topics covered include energy and power analysis, secondary batteries with a focus on lithium-ion batteries, conventional supercapacitors, hybrid supercapacitors, modelling techniques, and state of charge and state of health estimation methods. Hybrid systems that combine two or more energy storage systems will be also discussed.', 2),
(107, 'Faulted Power Systems (Offered with ELE525)', 'ELE 724', 3, 'This course covers the techniques and mathematical tools needed to analyze faulted power systems. Topics include impedance model, analysis of three-phase symmetrical faults, symmetrical components, unsymmetrical faults, and power systems stability. Students will be challenged to draw upon a background of knowledge from earlier studies to explore these topics in a comprehensive manner.', 2),
(108, 'Renewable Energy Sources (Offered with ELE526)', 'ELE 726', 3, 'This course introduces students to the challenges of sustainable energy development that are addressed under the framework of the UN Sustainable Development Goals (SDGs), which consists of 17 urgent actions by all countries – developed and developing – in a global partnership.  The course introduces renewable energy technologies (e.g., hydropower, wind, solar, etc.) and illustrates how they achieve the targets of SDG7 (Affordable and Clean Energy).  At the conclusion of the course, students will have a solid technical and economic understanding of these renewable energy technologies.', 2),
(109, 'Design and Operation of Smart Grids (Offered with ELE529)', 'ELE 729', 3, 'This course focuses on the concept of smart grids. It offers a basic introduction to the different components of a power system and explores its development in the presence of distributed generation, energy storage and electric vehicles. The course also covers the use of ICT technologies in the development of smart grid applications that enhance the operation of the power system.', 2),
(110, 'Optical Fiber Communications (Offered with ELE531)', 'ELE 731', 3, 'This course covers the waveguiding in optical fibers, fiber losses including attenuation, dispersion and nonlinearities, noise, receiver and transmitter design, link analysis, introduction to erbium-doped amplifiers, and time- and wavelength-division-multiplexed networks.', 2),
(111, 'Information and Coding Theory (Offered with ELE535)', 'ELE 735', 3, 'Information theory applied to communication systems. It covers digital signals and streams, information measures, data compression, error-correcting codes, block codes, convolutional codes, Viterbi algorithm, noise, maximum-entropy, Markov chains, channel capacity formalism and Shannon’s theorem.', 2),
(112, 'Linear Systems (Offered with ELE548)', 'ELE 742', 3, 'This course covers the canonical realization of transfer functions, state observability and controllability, state feedback and asymptotic observers, reduced order observers, and regulator design. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 2),
(113, 'Digital Image and Video Processing and Compression (Offered with ELE552)', 'ELE 752', 3, 'This course is concerned with understanding the fundamentals of digital image and video perception, representation, processing, understanding, and compression.', 2),
(114, 'Reliability Evaluation of Engineering Systems (Offered with ELE553)', 'ELE 753', 3, 'This course covers the basic reliability concepts, elements of probability and statistical theory, application of important distributions, reliability in series, parallel and complex systems, application of Markov chains in the evaluation of repairable system reliability, application of Markov processes for reliability evaluation of complex systems, and the utilization of Monte Carlo simulation in basic system reliability evaluation.', 2),
(115, 'Simulation of Electronic Circuits (Offered with ELE557)', 'ELE 757', 3, 'This course covers the principles of efficient electronic circuit simulation using numerical methods and techniques. Topics include the formulation of network equations, dc analysis, frequency domain analysis, simulation of nonlinear networks, transient analysis, sensitivity analysis and model order reduction. The simulation of specialized circuits is also considered, including the analysis of radio frequency circuits and high-speed interconnects. In addition, students will learn how to implement circuit simulation methods using mathematical software tools.', 2),
(116, 'DIGITAL IMAGE AND VIDEO PROCESSING AND COMPRESSION (OFFERED WITH ELE552)', 'ELE 772', 3, 'This course is concerned with understanding the fundamentals of digital image and video perception, representation, processing, understanding, and compression.', 2),
(117, 'Topics: Biomechatronics - offered with MCE540', 'ELE 799D', 3, 'Biomechatronics is the application of mechatronic engineering to human biology . This course will cover state-of-the-art in the field of Biomechatronics including assistive technologies, prosthetic devices, rehabilitation robots, and exoskeletons', 2),
(118, 'Topics: Robotics & Intelligent Systems', 'ELE 799E', 3, 'This course introduces fundamental concepts in Robotics. The course discusses basic concepts, including coordinate transformation, kinematics, dynamics, Laplace transforms, equations of motion, feedback and feedforward control, and trajectory planning. These topics will be exemplified with Matlab/Simulink simulation studies. The second part of the course will introduce intelligent robots, including computer vision and introductory artificial Intelligence.', 2),
(119, 'Topics: Underactuated Robotics', 'ELE 799F', 3, NULL, 2),
(120, 'Topics: Mobile Robotics', 'ELE 799G', 3, NULL, 2),
(121, 'Engineering Graphics', 'MEE 211', 1, 'An introduction in the basics of 2D drafting, sketching and pictorial views, orthographic multiviews, auxiliary and section views, dimensions, drawing layouts and presentations. Basic use of a computer aided drafting software (such as AutoCAD).', 3),
(122, 'Computer Applications in MEE', 'MEE 212', 2, 'This course is designed to introduce students to computational software such as MATLAB and Excel. Students will learn how to write MATLAB programs for Mechanical engineering applications and to use Excel Solver to optimize problems. Array definitions and manipulations, user-defined functions, solution of ordinary and partial differential equations, plotting and several built-in functions will be covered. Excel Data Analysis ToolPak will be used for Design of Experiments analysis and statistical tests. Pre-requisites: COE212 Engineering Programming and GNE333 Engineering Analysis.', 3),
(123, 'Dynamics', 'MEE 241', 3, 'This course covers kinematics, and kinetics of particles, systems of particles, and kinetics of rigid bodies. Pre-requisites: MTH201 Calculus III and CIE200 Statics .', 3),
(124, 'Thermodynamics', 'MEE 301', 3, 'This course covers the basic concepts of work and heat, systems and control volumes, pure substances, equation of state, first law for systems, steady flow energy equation, second law for systems and control volume, and entropy. Pre-requisite: Second-year standing.', 3),
(125, 'Energy Conversion', 'MEE 302', 3, 'This course covers the performance and design considerations of energy conversion systems, the design and performance problems involving steam, gas turbine, and combined cycle power plants, and the reciprocating and rotary engines. Pre-requisite: MEE301 Thermodynamics .', 3),
(126, 'Fluid Mechanics', 'MEE 311', 3, 'This course covers fluid statics, analysis of fluid motion using the continuity, momentum, and energy, relationship, and the introduction to viscous flow. Pre-requisite: MEE241 Dynamics.', 3),
(127, 'Fluid Mechanics Lab', 'MEE 312', 1, 'This course entails laboratory experiments in fluid mechanics.', 3),
(128, 'Strength of Materials', 'MEE 320', 3, 'This course covers mechanical properties and behavior of stressed materials, stress analysis of beams, columns and shafts, statically indeterminate structures, plane stress and strain, and principal stresses. Pre-requisite: CIE200 Statics .', 3),
(129, 'Material Properties and Processes', 'MEE 321', 3, 'This course covers the mechanical and physical properties of engineering materials (metals, ceramics and polymers), which are explained through their structures. Topics include strength and ductility, crystal structures and defects, phases, heat treatment. The course includes a revision of theories and principles of atomic structure and chemical bonding. Pre-requisite: Second-year standing.', 3),
(130, 'Manufacturing Processes', 'MEE 332', 3, 'This course offers a balanced quantitative and qualitative coverage of manufacturing processes: Casting, Material Removal, Deformation, Welding and Assembly. Course presents an overview of engineering materials, primary-manufacturing processes and includes projects tailored towards using manufacturing processes for obtaining functional products. Pre-requisite: MEE321 Material Properties and Processes.', 3),
(131, 'Manufacturing Lab', 'MEE 333', 1, 'Lab provides students with hands-on experience in the use of traditional mechanical workshop equipment and software for manufacturing drawings generation. Students are also introduced to CNC Programming.', 3),
(132, 'Kinematics of Machines', 'MEE 341', 3, 'This course covers kinematics of mechanical devices, displacement, velocity and acceleration of linkages, cams and gear trains, and an introduction to synthesis, design, and computer problems. Pre-requisites: MEE241 Dynamics, MEE351 Computer Aided Design', 3),
(133, 'Computer Aided Design', 'MEE 351', 3, 'This course covers the numerical design chain encompassing conceptual design techniques & methodologies, sketching, geometrical modeling, design specifications and product assembly. Course includes projects tailored towards using CAD software for designing mechanical engineering products. Pre-requisites: MEE211 Engineering Graphics.', 3),
(134, 'Instrumentation and Measurements', 'MEE 391', 3, 'Data acquisition; design of experiments and laboratory safety; selection of instruments for experiments; informal and formal report writing; statistics of large samples applied to fixed and dynamic response of instruments; use of instrumentation software. Pre-requisites: ELE305 Introduction to Electrical Engineering; GNE331 Probability and Statistics.', 3),
(135, 'Machine Shop', 'MEE 392', 1, 'This course provides students with hands-on experience in the use of workshop equipment using modern machine tools, precision measuring tools, and hand tools.', 3),
(136, 'Energy Systems', 'MEE 401', 2, 'This course introduces students to the concept of sustainability in the context of energy use. It stresses on the different aspects involved in our daily-life use of energy: environmental, societal, political, financial, etc. It covers technologies and means used in improving the sustainability of current fossil-fuel (coal, oil and gas) based energy systems, electric and nuclear systems by reducing their environmental and societal impacts. Finally, it introduces different renewable (‘clean’) energy technologies that can be used as alternatives to traditional (‘dirty’) energy systems.', 3),
(137, 'Heat Transfer', 'MEE 403', 3, 'This course covers the transfer of heat by conduction, radiation and convection, and the analysis of steady state, and simple transient heat processes, and the evaporation, boiling, and condensing, heat transfer.', 3),
(138, 'Heat Transfer Lab', 'MEE 404', 1, 'This course entails laboratory experiments in heat transfer.', 3),
(139, 'Internal Combustion Engines', 'MEE 407', 3, 'This course covers the principles, practice, and characteristics, of internal combustion engines, with laboratory demonstrations in engine testing and performance. The laboratory entails experiments in internal combustion engines. Pre-requisite: MEE302 Energy Conversion.', 3),
(140, 'Thermal Systems Design', 'MEE 414', 3, 'This course coves the analysis and design of thermal systems using the principles developed in thermodynamics, fluid mechanics, and heat transfer. Students develop computer programs to solve open-ended thermal design problem. Pre-requisites: MEE403 Heat Transfer and MEE301 Engineering Thermo.', 3),
(141, 'Mechanical Engineering Design', 'MEE 422', 3, 'This course covers application of engineering design process to the design of mechanical components, subsystems and machines, problem-solving techniques, ethics, and patents.', 3),
(142, 'Mechanical Vibrations', 'MEE 442', 3, 'This course covers kinematics and force analysis of machine and machine elements, balancing, critical speed, flywheel design and dynamic measurement, and design and computer problems. Pre-requisites: MEE341 Kinematics of Machines, and MTH304 Differential Equations.', 3),
(143, 'Mechanical Vibrations Lab', 'MEE 443', 1, 'This course entails laboratory experiments in machine dynamics.', 3),
(144, 'Control Systems', 'MEE 445', 3, 'This course covers control system design of mechanical systems, emphasis on thermal, fluid, and motion, systems under feedback control, and classical control topics, including laplace transforms, system modeling, stability theory, and practical applications to professional practice.', 3),
(145, 'Control Systems Lab', 'MEE 446', 1, 'The Control Systems lab provides experiential training of the methods used in modeling, analysis, simulation, and control of engineering systems. Students will design and implement controllers using modern Instruments and software.', 3),
(146, 'Seminar on Contemporary Issues in MEE', 'MEE 491', 2, 'This is a seminar course covering contemporary issues in Mechanical Engineering. Students are asked to research contemporary subjects in the field and present findings to the class. Pre-requisites: Third year standing.', 3),
(147, 'Professional Experience', 'MEE 498', 6, 'This course covers professional experience through training in the execution of real-life engineering projects. Pre-requisites: Fifth-year standing and the consent of the instructor.', 3),
(148, 'Renewable Energy', 'MEE 500', 3, 'A course that covers the principles of emerging renewable technologies, including solar, wind, biomass, geothermal, hydropower and other energy sources. A premise of the course is that a renewable energy technology must both be technically feasible and economically viable. At the conclusion of the course, students will have a solid technical and economic understanding of these energy technologies.', 3),
(149, 'Passive Building Design', 'MEE 502', 3, 'This course centers on issues surrounding the integration of Sustainable and Passive Design principles, into conceptual and practical Building design. Topics will include: solar geometry, climate/regional limitations, natural lighting, passive design and sustainability initiatives, natural ventilation and infiltration, insulating and Energy Storing Material, Bioclimatic concept and design. Case studies will be used as a vehicle to discuss the success/failure of ideas and their physical applications. The course will focus on the use Energy Auditing as a means to both design and evaluate the energy performance of buildings.', 3),
(150, 'Power Plant Engineering', 'MEE 503', 3, 'This course covers the economics of power generation, steam and gas turbine power cycles, combined power plants, Geothermal Power plants, fuel and combustion analysis and mechanisms, steam generators, condensers, Hydro-electrical power plant, diesel engine power plant, Energy and Availability analysis, and field trips.', 3),
(151, 'Solar System Design', 'MEE 505', 3, 'The course covers fundamentals of solar energy and its utilization in photovoltaic (PV) systems. The solar PV systems, from cells to grids, are addressed, with a particular emphasis on the challenges of grid-integration of PV and the development of storage technologies. Projects assist students with understanding solar PV system layouts and costs, calculating PV system size, and identifying appropriate system design for a given electrical demand. The course explores economic considerations and return on investment, touching on solar PV system costs for residential and commercial use.', 3),
(152, 'Vehicle Powertrain Systems', 'MEE 506', 3, 'Fundamentals, design and modeling of conventional and advanced hybrid electric power trains for a sustainable mobility.', 3),
(153, 'Advanced Powertrain Systems', 'MEE 507', 3, 'Fundamentals, design and modeling of advanced hybrid electric powertrains for a sustainable mobility. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 3),
(154, 'Computational Fluid Dynamics', 'MEE 514', 3, 'This course focuses on introducing variety of computational techniques for solving the equations governing the fluid motion, with special emphasis on finite difference and finite volume methods. Theoretical background will be covered with focus on accuracy and stability of numerical schemes, as well as their application in real fluid problems. Students are expected to write their own codes and employ commercial software such as ANSYS Fluent. Applications will cover compressible inviscid and incompressible viscous flows.', 3),
(155, 'Refrigeration and Air-Conditioning', 'MEE 515', 3, 'This course covers principles of vapor compression and absorption refrigeration, heat pumps, psychrometrics, principles of thermal comfort, and environmental aspects, determination of heating and cooling loads, and air conditioning system design and analysis.', 3),
(156, 'Turbo Machinery', 'MEE 517', 3, 'This course introduces the basic principles of modern turbo machinery. Emphasis will be placed on the design of turbines, compressors, pumps and fans. Therefore, applications of the principle of the fluid mechanics, thermodynamics and aerodynamics are vital to this course.', 3),
(157, 'Piping Network and Fire Protection Systems', 'MEE 519', 3, 'This course concentrates on the design and calculations of pipe network, plumbing, and Fire-fighting systems including cold and hot water distribution for building and commercial applications, sanitary systems, rain water systems, sewer pumps and fire suppression systems… The course provides the ME students an opportunity to enhance and learn how to read and draw mechanical plans and specifications based on codes and standards. Troubleshooting techniques will also be introduced and special attention will be paid for fire-fighting techniques .', 3),
(158, 'Composite of Materials', 'MEE 520', 3, 'Introduction to the Mechanics of Composite Materials: Fiber and Matrix Properties, Micro-and Macro-mechanics.', 3),
(159, 'Finite Element Methods', 'MEE 521', 3, 'This course introduces a numerical technique used in the solution of PDE governed problems. Applications cover solid mechanics, fluid dynamics and heat transfer problems in 1D. The course provides an insight on the extension to 2D and 3D problems. Bar, truss, beam and frame elements are covered in solid mechanics applications. Computer program development for the solution of 1D problems. Use of state of the art commercial finite element software (COMSOL Multiphysics). Pre-requisites: GNE333 Engineering Analysis I, and MEE320 Strength of Materials.', 3),
(160, 'Advanced Manufacturing and AI', 'MEE 532', 3, 'This course will cover the new and advanced manufacturing methods. It will cover different scales of manufacturing down to Nano scale. Fuzzy Logic (AI) will be introduced and applied for Manufacturing processes.', 3),
(161, 'Advanced CAD/CAM', 'MEE 533', 3, 'This course covers the application of the design process to design and manufacture engineering products throughout the different steps of specification, behavioral modeling, design analysis, material selection, prototyping, manufacturing and testing. The course requires extensive usage of PLM software packages to the design and manufacturing of a mechanical design problem. Pre-requisite: MEE332 Manufacturing Processes, MEE351 Computer Aided Design; 5th year standing. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 3),
(162, 'Micro & Surface Engineering', 'MEE 535', 3, 'This course centers on the micro world of surface engineering science, emphasizing how modifying material surfaces at micro and nano scales can significantly enhance performance and durability. Techniques such as ceramic coating, micromachining, ultrasonics, and laser pulse treatment are employed to improve surface functionality. These approaches play a crucial role in the innovation of manufactured products at small scales. Applications span across high-tech sensor development, electronics, micro-engines, and hydrophobic surfaces, with relevance to various industries, including biomedical, electronics, aerospace, and ceramic coatings.', 3),
(163, 'Plastics Manufacturing', 'MEE 536', 3, 'Introduction to polymeric materials; categories; morphologies; fillers and additives. Physical and Mechanical properties of plastics. Plastics Testing. Plastics processing: injection molding; extrusion; expansion; thermoforming; blow molding. Injection time cycle; shrinkage of molded plastics. Flow rate calculation of molten plastics. Single and twin-screw extrusion. Extrusion screw elements. Metering flow rate in extrusion Rheology. Fifth year standing', 3),
(164, 'Introduction to Robotics', 'MEE 540', 3, 'This course covers the fundamental concepts in Robotics such as coordinate transformation, forward and inverse kinematics, dynamics, Laplace transforms, equations of motion, feedback and feedforward control, and trajectory planning. It also covers End-of-arm sensing and introduce intelligent robots, including computer vision and introductory artificial Intelligence. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 3),
(165, 'Acoustics and Vibration Control', 'MEE 543', 3, 'This course covers the acoustic momentum, energy and intensity, propagation, reflection and absorption, effects of the physical properties, transmission of sound in real media, forced and free vibration systems, with one or more degrees of freedom, vibration isolation, and transmission applied to problems of rotating, and reciprocating, machinery, and design problems on vibration isolation systems, and absorbers. Pre-requisite: MEE442 Mechanical Vibrations', 3),
(166, 'Robotics and Intelligent Systems', 'MEE 547', 3, 'This course introduces fundamental concepts in Robotics. The course discusses basic concepts, including coordinate transformation, kinematics, dynamics, Laplace transforms, equations of motion, feedback and feedforward control, and trajectory planning. These topics will be exemplified with Matlab/Simulink simulation studies. The second part of the course will introduce intelligent robots, including computer vision and introductory artificial Intelligence. Pre-requisites: MEE341 Kinematics and Dynamics of Linkages, MEE445 Control System', 3),
(167, 'Automotive Dynamics', 'MEE 549', 3, 'Vehicle Classification; Longitudinal Vehicle Dynamics; Vehicle Load Transfer; Vehicle Acceleration Performance; Vehicle Braking Performance; Road Loads; Vehicle Aerodynamics; Tire Dynamics; Steady-State Cornering; Suspensions; Steering System. Pre-requisites: MEE241 Dynamics; MEE311 Fluid Mechanics; MEE351 Computer-Aided Design', 3),
(168, 'CFD for Wind Energy Engineering', 'MEE 570', 3, 'This is an introductory course to computational fluid dynamics (CFD) techniques for modelling, simulating, and analyzing practical problems related to wind engineering. The course covers theoretical background associated with both CFD tools and wind turbines, including real-world applications using commercial software packages used in industry. Pre-requisite: MEE 311 Fluid Mechanics; Fifth year standing Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 3),
(169, 'Energy Audit', 'MEE 590', 3, 'This course covers the survey of energy sources, cost analysis, alternatives, environmental issue, audit techniques, and technical reporting. Pre-requisite: MEE403 Heat Transfer.', 3),
(170, 'Project I', 'MEE 591', 3, 'This course covers selected engineering project using acquired technical knowledge, formal report, and presentation. Pre-requisites: Fifth year standing and MEE332 Manufacturing Processes.', 3),
(171, 'Project II', 'MEE 592', 3, 'This course covers advanced engineering project, using acquired technical knowledge, formal report, and presentation. Pre-requisites: Fifth year standing and MEE591 Project I', 3),
(172, 'Capstone Engineering Design', 'MEE 593', 1, 'Course reinforces and integrates topics covered in other courses in the curriculum and used in engineering design. Topics covered include need identification and problem definition, managing the design process, team behavior and group dynamics, design research and information gathering, concept generation and evaluation, risk, reliability, and safety, legal and ethical issues in design, communicating the design.', 3),
(173, 'Undergraduate Research Project', 'MEE 594', 3, 'This course covers advanced engineering undergraduate research project, using acquired technical knowledge, formal report, and Presentation. Pre-requisites: Final year standing and the consent of the instructor.', 3),
(174, 'Undergraduate Research Project', 'MEE 594H', 3, 'This course covers advanced engineering undergraduate research project, using acquired technical knowledge, formal report, and Presentation. Pre-requisites: Final year standing and the consent of the instructor.', 3),
(175, 'Research Methods', 'MEE 598H', 3, 'Introduction to methods for improving and developing research skills; including: principles of scientific research, ethics, writing skills, methods for compiling scientific literature, identification of research questions and specific hypotheses, presentation of research results, writing research papers, proposal preparation, preparation of grant proposals, thesis and dissertation. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 3),
(176, 'Topics in Mechanical Engineering', 'MEE 599', 3, 'This course covers the treatment of new development in various areas of mechanical engineering. Pre-requisites: Fifth-year standing Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 3),
(177, 'Tp: Industrial Automation Systems', 'MEE 599AN', 3, 'This course examines the various dimensions and determinants of health and wellbeing. An emphasis is placed on public health as well as the social and mental health aspects of wellbeing. An interdisciplinary approach is used to address present and future challenges to physical and mental wellbeing of the public. This course will rely on case studies as well as other active learning strategies to enhance students’ problem-solving skills and wellbeing based on applied, day-to-day examples.', 3),
(178, 'Green Engineering', 'MEE 599AO', 3, 'This course explores the pivotal role of innovative green engineering practices in enhancing product value, minimizing pollution, and reducing costs. It covers key topics including the Green Economy, Green Business, Green Marketing, Green Finance, Green Design, and Green Cities. Additionally, the course examines Economic Efficiency versus Profitability, methods for Quantifying Internal and External Costs, Assessing Environmental Degradation Costs, and the integration of ESG (Environmental, Social, and Governance) principles and CSR (Corporate Social Responsibility) strategies. Pre-requisites: 5 th year Standing', 3),
(179, 'Aerospace Processes, Materials and Applications', 'MEE 599AP', 3, 'Modern aerospace and automotive sectors require advanced materials that meet demands for strength, low weight, durability, and reliability. This course explores recent advances in materials and processing methods, as well as their applications in aerospace and high-performance automotive engineering. Topics include polymer and metallic composites, highlighting their high-strength and lightweight, use in aircraft structures, spacecraft, and next-generation vehicles. Powder metallurgy is addressed with emphasis on the processing and application as in turbine engines and racing systems. Fracture mechanics and failure analysis are introduced to assess fatigue life and durability in demanding environments. The course also reviews PCB materials and fabrication techniques for aerospace / automotive applications. Hands-on projects and industry case studies support practical understanding of these technologies.', 3),
(180, 'Renewable Energy', 'MEE 700', 3, 'A course that covers the principles of emerging renewable technologies, including solar, wind, biomass, geothermal, hydropower and other energy sources. A premise of the course is that a renewable energy technology must both be technically feasible and economically viable. At the conclusion of the course, students will have a solid technical and economic understanding of these energy technologies.', 3),
(181, 'Energy Audit', 'MEE 701', 3, 'This course covers the survey of  energy sources, cost analysis, alternatives, environmental issue, audit techniques, and technical reporting. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 3),
(182, 'Passive Building Design', 'MEE 702', 3, 'This course centers on issues surrounding the integration of Sustainable and Passive Design principles, into conceptual and practical Building design. Topics will include: solar geometry, climate/regional limitations, natural lighting, passive design and sustainability initiatives, natural ventilation and infiltration, insulating and Energy Storing Material, Bioclimatic concept and design. Case studies will be used as a vehicle to discuss the success/failure of ideas and their physical applications. The course will focus on the use Energy Auditing as a means to both design and evaluate the energy performance of buildings. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 3),
(183, 'Power Plant Engineering', 'MEE 703', 3, 'This course covers the economics of power generation, steam and gas turbine power cycles, combined power plants, Geothermal Power plants, fuel and combustion analysis and mechanisms, steam generators, condensers, Hydro-electrical power plant, diesel engine power plant, Energy and Availability analysis, and field trips.', 3),
(184, 'Applied Solar Energy', 'MEE 704', 3, 'The course covers fundamentals of solar energy and its utilization in thermal and photovoltaic systems. This includes review of basic heat transfer concepts, solar energy availability, solar thermal collectors, thermal and photovoltaic systems’ design. It will also include an introduction to wind energy resources and utilization. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 3),
(185, 'Internal Combustion Engines', 'MEE 705', 3, 'This course covers the principles, practice, and characteristics, of internal combustion engines, with laboratory demonstrations in engine testing and performance. The laboratory entails experiments in internal combustion engines.', 3),
(186, 'Vehicle Powertrain Systems', 'MEE 706', 3, 'Fundamentals, design and modeling of conventional and advanced hybrid electric power trains for a sustainable mobility.', 3),
(187, 'Advanced Powertrain Systems', 'MEE 707', 3, 'Fundamentals, design and modeling of advanced hybrid electric powertrains for a sustainable mobility. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 3),
(188, 'Intro to Sustainable Energy', 'MEE 708', 3, 'This course provides a comprehensive introduction to sustainable energy systems, covering renewable energy technologies, energy efficiency, and storage solutions. It explores the environmental and economic impacts of energy use, smart grid integration, and policy frameworks driving the transition to sustainable energy. Real-world case studies will highlight applications in power generation, transportation, and industry. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 3),
(189, 'Sustainable Architecture', 'MEE 709', 3, 'This course covers issues surrounding the integration of energy-sustainable and passive design principles into conceptual and practical building designs. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 3),
(190, 'Advanced Fluid Mechanics', 'MEE 710', 3, 'The course covers the principals and methods of fluid mechanics. Topics include kinematics of fluids, conservation equations, two-dimensional potential flow theory, circulation and vorticity theorems, free shear layer and boundary layer stability, boundary layer and flow separation. Laminar-turbulent boundary layer transition, secondary flows, introduction to turbulent flow, steady and unsteady stall. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 3),
(191, 'Boundary Layer Theory', 'MEE 711', 3, 'This course covers the effect of viscosity in near-wall flows. Topics include continuum fluid mechanics, exact solutions of Navier-Stokes equations, creeping flows, laminar and turbulent boundary layers, exact and approximate solutions of the steady state boundary layer equations, boundary layer control, stability of laminar flows, transition, fundamentals of turbulent flows. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 3),
(192, 'Solar System Design', 'MEE 712', 3, 'The course covers fundamentals of solar energy and its utilization in photovoltaic (PV) systems. The solar PV systems, from cells to grids, are addressed, with a particular emphasis on the challenges of grid-integration of PV and the development of storage technologies. Projects assist students with understanding solar PV system layouts and costs, calculating PV system size, and identifying appropriate system design for a given electrical demand. The course explores economic considerations and return on investment, touching on solar PV system costs for residential and commercial use.', 3),
(193, 'Gas Turbines', 'MEE 713', 3, 'This course covers the design, operation, and performance characteristics of both stationary and propulsion gas turbines. Students will learn about the fundamental principles of thermodynamics, fluid mechanics, and combustion processes related to gas turbine technology. Key topics include component design, efficiency analysis, and emissions control strategies of gas turbines used in power generation and aerospace propulsion. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 3),
(194, 'Computational Fluid Dynamics', 'MEE 714', 3, 'This course focuses on introducing variety of computational techniques for solving the equations governing the fluid motion, with special emphasis on finite difference and finite volume methods. Theoretical background will be covered with focus on accuracy and stability of numerical schemes, as well as their application in real fluid problems. Students are expected to write their own codes and employ commercial software such as ANSYS Fluent. Applications will cover compressible inviscid and incompressible viscous flows.', 3),
(195, 'Turbo Machinery', 'MEE 717', 3, 'This course introduces the basic principles of modern turbo machinery. Emphasis will be placed on the design of turbines, compressors, pumps and fans. Therefore, applications of the principle of the fluid mechanics, thermodynamics and aerodynamics are vital to this course.', 3),
(196, 'Turbulence Modeling', 'MEE 718', 3, 'This course covers the basic definitions and characteristics of turbulent flows and provides an overview of concepts used in turbulence modeling. Topics include, Reynolds averaged Navier-Stokes (RANS) equations, turbulent scales, hierarchy of turbulence simulations, zero-equation and half-equation models, one-equation models, two-equation models, multi-equation and scale models, nonlinear mode/second-moment models, transition-sensitive models, Scale-Adaptive Simulation (SAS), Large Eddy Simulation (LES), Detached Eddy Simulation (DES), Direct Numerical Simulation (DNS). The course includes applications using commercial software such as ANSYS Fluent. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 3),
(197, 'Piping Network and Fire Protection Systems', 'MEE 719', 3, 'This course concentrates on the design and calculations of pipe network, plumbing, and Fire-fighting systems including cold and hot water distribution for building and commercial applications, sanitary systems, rain water systems, sewer pumps and fire suppression systems… The course provides the ME students an opportunity to enhance and learn how to read and draw mechanical plans and specifications based on codes and standards. Troubleshooting techniques will also be introduced and special attention will be paid for fire-fighting techniques.', 3),
(198, 'Composite Materials', 'MEE 720', 3, 'Introduction to the Mechanics of Composite Materials: Fiber and Matrix Properties, Micro-and Macro-mechanics. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 3),
(199, 'Finite Element Methods', 'MEE 721', 3, 'This course introduces a numerical technique used in the solution of PDE governed problems. Applications cover: Solid Mechanics, Fluid Dynamics and Heat Transfer Problems in 1D. The course provides an insight on the extension to 2D and 3D problems. Bar, Truss, Beam and Frame elements are covered in solid mechanics applications. Computer program development for the solution of 1D problems. Use of state-of-the -art commercial finite element software (COMSOL Multiphysics).', 3),
(200, 'Innovative Engineering & Design', 'MEE 722', 3, 'In this course, you will learn the methodology behind producing great designs. You will learn to communicate with high emotional and intellectual impact. This course will begin with ideation, to design, to usability testing, and iterative design, before arriving at a product ready for commercialization. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 3),
(201, 'Lean Manufacturing', 'MEE 730', 3, 'This is an introduction course for all engineering disciplines. The course focuses on the concepts, principles, tools and techniques of Lean Manufacturing. Examples from the manufacturing environment and administrative functions will be utilized to explain key concepts. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 3),
(202, 'Six Sigma', 'MEE 731', 3, 'This is an introduction course for engineering disciplines.  The course focuses on the concepts, principles, tools and techniques of Six Sigma. Examples from the manufacturing environment and administrative functions will be utilized to explain key concepts. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 3),
(203, 'Advanced Manufacturing & AI', 'MEE 732', 3, 'New technologies are introduced in modern plants (as 3D Additive printing and Nano scale manufacturing). Most manufactured parts in industry require different quality parameters. The requirements are often to achieve the better quality with the least time and or cost. For that end, new manufacturing methods are becoming more and more commonly used. The course is a focus on New / Advanced and unconventional  manufacturing . Other innovative/new trend manufacturing methods which are having interest will be covered, as :  Nano  scale manufacturing (& sensors). Now that we lie in an environment where sensors are present in our daily life, industries are realizing the importance of Nano scale, and how it can become a game changing strategy when considering manufacturing at this scale, and the benefits associated with it. Many manufacturers commonly agree that manufacturing will involve more and more 3D printing (additive manufacturing)   in the near future. Currently major aerospace & some ', 3),
(204, 'Micro & Surface Engineering', 'MEE 735', 3, 'This course centers on the micro world of surface engineering science, emphasizing how modifying material surfaces at micro and nano scales can significantly enhance performance and durability. Techniques such as ceramic coating, micromachining, ultrasonics, and laser pulse treatment are employed to improve surface functionality. These approaches play a crucial role in the innovation of manufactured products at small scales. Applications span across high-tech sensor development, electronics, micro-engines, and hydrophobic surfaces, with relevance to various industries, including biomedical, electronics, aerospace, and ceramic coatings.', 3),
(205, 'Plastics Manufacturing', 'MEE 736', 3, 'Introduction to polymeric materials; categories; morphologies; fillers and additives. Physical and Mechanical properties of plastics. Plastics Testing. Plastics processing: injection molding; extrusion; expansion; thermoforming; blow molding. Injection time cycle; shrinkage of molded plastics. Flow rate calculation of molten plastics. Single and twin screw extrusion. Extrusion screw elements. Metering flow rate in extrusion Rheology.', 3),
(206, 'Introduction to Robotics', 'MEE 740', 3, 'This course covers the fundamental concepts in Robotics such as coordinate transformation, forward and inverse kinematics, dynamics, Laplace transforms, equations of motion, feedback and feedforward control, and trajectory planning. It also covers End-of-arm sensing and introduce intelligent robots, including computer vision and introductory artificial Intelligence. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 3),
(207, 'Control of Electrified Vehicles', 'MEE 741', 3, 'This course covers the powertrain control of hybrid and electric vehicles. It entails a thorough understanding and analysis of the different vehicle energy needs and the power-split problem, and provides real-time-implementable energy management strategies and other optimal control strategies, using several numerical solutions based on dynamic programming and the maximum principle. Pre-requisites: MEE707 Advanced Powertrain Systems. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 3),
(208, 'Smart Materials and Structures', 'MEE 742', 3, 'This course covers the operating principles and the constitutive modeling of smart materials including piezoceramics, magnetostrictives, shape memory alloys, magnetorheological fluids, and electroactive polymers. Constitutive and system-level modeling. Current approaches for designing and implementing smart structures in real-world applications will be reviewed. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 3),
(209, 'Advanced Dynamics', 'MEE 743', 3, 'This course covers the kinematics and kinetics of particles, system of particles and rigid bodies. Linear and angular impulse and momentum. Lagrangian and Hamiltonian methods. Orbital motion. Euler angles. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 3),
(210, 'Vehicle Motor Drives and Storage Systems', 'MEE 744', 3, 'This course covers the description and analysis of electric motor drives and energy storage systems for automotive applications. It provides an insight for system-level modeling of power electronic converters, electric machines, the various electrical loads as well as battery technology for conventional, hybrid and electric vehicle applications. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 3),
(211, 'Theory of Vibration', 'MEE 745', 3, 'This course covers the analysis and modeling of vibrating systems, focusing on multi-degree-of-freedom and continuous structures. It explores the derivation of equations of motion using analytical mechanics principles and the application of time-domain and frequency-domain techniques in vibration analysis. Topics include modal analysis, natural frequency determination, and mode shapes. Fourier series and transforms are employed to examine periodic and non-periodic vibrations, while the vibration characteristics of continuous systems such as bars, beams, and membranes are also investigated. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 3),
(212, 'Nonlinear Dynamics and Chaos', 'MEE 746', 3, 'Introduction to nonlinear dynamics, with applications to physics, engineering, biology, and chemistry. Emphasizes analytical methods, concrete examples, and geometric thinking. Topics include one-dimensional systems; bifurcations; phase plane; nonlinear oscillators; and Lorenz equations, chaos, strange attractors, fractals, iterated mappings, period doubling. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 3),
(213, 'Robotics and Intelligent Systems', 'MEE 747', 3, 'This course introduces fundamental concepts in Robotics. The course discusses basic concepts, including coordinate transformation, kinematics, dynamics, Laplace transforms, equations of motion, feedback and feedforward control, and trajectory planning. These topics will be exemplified with MATLAB/Simulink simulation studies. The second part of the course will introduce intelligent robots, including computer vision and introductory artificial Intelligence.', 3),
(214, 'Automotive Dynamics', 'MEE 749', 3, 'Vehicle Classification; Longitudinal Vehicle Dynamics; Vehicle Load Transfer; Vehicle Acceleration Performance; Vehicle Braking Performance; Road Loads; Vehicle Aerodynamics; Tire Dynamics; Steady-State Cornering; Suspensions; Steering System.', 3),
(215, 'CAD of Advanced Mechanical Systems', 'MEE 750', 3, 'This course covers the use of advanced computer-aided design software packages, including systems for computer-aided drafting, solid modeling, finite element analysis, and computer-aided manufacturing, and design projects including: fabrication of physical prototypes generated with numerically controlled machines. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 3),
(216, 'Mechatronics System Design I', 'MEE 760', 3, 'This course introduces the basic mechatronic system components, design principles, and implementation combining hardware and software approaches with project-based learning.  The course focuses on essential topics in mechatronics including electronics, sensors and actuators, hydraulic and pneumatic systems, mechanical and electrical drawings, programming of various digital controllers and processors widely used in robotics and industrial automation.', 3),
(217, 'Intro to Plant Design', 'MEE 761', 3, 'This is an introductory course to chemical plant design for mechanical engineers. The main objective of this course is to give mechanical engineers a survey of some of the methods and practices that chemical engineers employ in plant design. The course covers topics employed normally by chemical engineers for designing chemical plants, which include the structure of chemical processes, economic evaluation, process circuit analysis and some fundamental chemical engineering calculations, and an introduction to flowsheet synthesis. These concepts will be illustrated on some selected plant design case studies. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 3),
(218, 'Pump Design for Oil & Gas', 'MEE 762', 3, 'The design and operation of well fluid artificial lift systems, including: sucker rod pumping, progressing cavity pumps (PCPs), electric submersible pumps (ESPs), downhole hydraulic pumps, and gas lift. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 3),
(219, 'Mechatronics System Design II', 'MEE 763', 3, 'This course introduces design and real-time implementation principles of mechatronic systems combining hardware and software approaches with project-based learning. The course focuses on essential topics in mechatronics including advanced digital controllers, sensors and actuators, modeling and simulation of mechatronic systems as well as feedback control considering unconventional control techniques such as Fuzzy logic. The course also discusses modern trends in engineering and their integration in Mechatronics System Design.', 3),
(220, 'CFD for Wind Energy Engineering', 'MEE 770', 3, 'This is an introductory course to computational fluid dynamics (CFD) techniques for modelling, simulating, and analyzing practical problems related to wind engineering. The course covers theoretical background associated with both CFD tools and wind turbines, including real-world applications using commercial software packages used in industry. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 3),
(221, 'Energy Storage & Charging Systems in Automobile Applications', 'MEE 780A', 3, 'This course introduces students to energy storage and charging systems in electric and electrified vehicle applications. It shows the market situation as of today and compares the different adopted storage technologies. The sizing of these storage systems is also detailed. Furthermore, this course shows the importance of the battery management system while focusing on battery cell balancing and battery pack thermal management. Charging systems are also covered in details. Finally, smart grid and vehicle to grid energy transfer concept is presented. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 3),
(222, 'Advanced Thermodynamics in Automobile', 'MEE 780B', 3, 'This course offers an introduction to principles of exergy analysis applied for thermodynamic energy converters. Today, the extended range hybrid electric vehicle (EREV) powertrains, based on series hybrid electric powertrains offer the advantages of both thermal (long range, low cost) and electric (zero emissions, fun to drive, low maintenance cost) powertrains. The fuel consumption of this EREV depends mainly on the energy converter performances in terms of efficiency and power to weight ratio. In this course, we will apply exergy analysis to identify the best thermodynamic configurations for EREV. The study will be performed on gas turbine system since it offers many vehicles intrinsic benefits such as, series powertrain compatibility, multi fuel capability, low noise and vibrations, low maintenance cost, compactness among others. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 3),
(223, 'Vehicle Motor Drives', 'MEE 780C', 3, 'This course offers an introduction to principles of electric machines and the closely related area of adjustable speed drives. Nowadays, the most widely used motors are classic direct current (DC) and alternating current (AC) motors such as induction motor and synchronous motor. To control these motors efficiently, we will do a comprehensive study of fundamental operating principles and related control theories. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 3),
(224, 'Thesis', 'MEE 791', 6, 'This research-based thesis course involves independent work performed by students, and leading to original contribution to knowledge. Topic selection is to be agreed upon in consultation with a Faculty Advisor. The student is limited to one thesis course per degree.', 3),
(225, 'Aerospace Processes, Materials and Applications', 'MEE 799A', 3, NULL, 3),
(226, 'Topic: Industrial Refrigeration', 'MEE 799AM', 3, 'A course that examines the fundamentals of refrigeration systems adopted in industrial applications. Topics include multistage refrigeration cycles, compressors characterization and selection, compressors cooling and lubrication, evaporator coil performance and selection, humidity control, frosting and methods of defrost, performance of air and water-cooled condensers, balancing and solenoid valves selection and their impact on system performance.', 3),
(227, 'Statics', 'CIE 200', 3, 'Review of vector algebra; force system resultants; equilibrium of a particle and rigid body; internal forces and applications to beams, trusses and frames; shear and moment diagrams for beams; centroid and moment of inertia. Pre-requisite: MTH102  Calculus II and PHY111  Mechanics.', 4),
(228, 'Mechanics of Materials', 'CIE 202', 3, 'Review of equilibrium principles; types of stress and linear stress-strain relationships; axial, shear, torsion, and bending deformations; shear force and bending moment diagrams; and deflection of beams by integration. Pre-requisite: CIE200 Statics.', 4),
(229, 'Mechanics of Materials – LAB', 'CIE 205', 1, NULL, 4),
(230, 'Computer Programming for Civil Engineers', 'CIE 212', 3, 'Fundamentals of computer programming and its application to solve civil engineering problems using MATLAB/MathCAD. Use of variables, arrays, conditional statements, loops, functions, and plots for numerical analysis in civil engineering and visualization of results. Pre-requisite: CIE200 Statics, COE201 Computer Proficiency and MTH201 Calculus III', 4),
(231, 'Structural Analysis', 'CIE 302', 3, 'Classification of statically determinate/ indeterminate structures; deflections using the principle of virtual work; introduction to matrix algebra, analysis of statically indeterminate structures using Flexibility Method and Stiffness Method.', 4),
(232, 'Structural Analysis – Soft', 'CIE 303', 1, 'Structural analysis using commercial software; computational model for trusses and frames: load cases, supports, linear static analysis. Results visualizations and assessment: axial force, shear force and bending moment diagrams; deformed shapes.', 4),
(233, 'Concrete Structures', 'CIE 306', 3, 'Analysis and design of reinforced concrete members according to ACI code including: singly reinforced beams, T-beams, doubly reinforced beams, solid and ribbed one-way slabs, short columns, including development length and anchorage.', 4),
(234, 'Concrete Structures – Soft', 'CIE 307', 1, 'Concrete design using commercial software according to established codes. Results visualization and assessment for beams, slabs, columns and footings: concrete section, reinforcement, development length, reinforcement layout.', 4),
(235, 'Construction Materials', 'CIE 308', 3, 'Introduction to the geological origins of construction materials and the effects of geological processes. General considerations on the use of materials in construction, required properties, selection, testing, design, and quality control of civil engineering materials. Design and testing of ordinary Portland cement concrete, asphaltic concrete, masonry, steel, and wood; Overview of the adverse environmental impact of using conventional construction materials; overview of emerging sustainable construction materials. Pre-requisite: CIE202 Mechanics of Materials and COE201 Computer Proficiency.', 4),
(236, 'Construction Materials – Lab', 'CIE 309', 1, 'Laboratory demonstration of materials testing and evaluation methods with emphasis on aggregate, concrete, and steel reinforcement testing as per national and international standard methods and specifications.', 4),
(237, 'Fluid Mechanics', 'CIE 320', 3, 'Properties of fluids; hydrostatics and kinematics; basic equations and conservation laws: mass, energy and momentum; Reynolds Transport Theorem; steady laminar and turbulent pipe flow; dimensional analysis and similitude, flow measurements. Pre-requisite: CIE200 Statics or GNE212 Engineering Mechanics', 4),
(238, 'Fluid Mechanics – Lab', 'CIE 321', 1, 'Laboratory applications in fluid mechanics including fluid measurements and properties; flow in pipes; Reynolds number; forces on gates; orifices; weirs; open channel flow; and pumps.', 4),
(239, 'Hydraulics', 'CIE 322', 3, 'Review of governing equations, design of municipal water supply and distribution systems, flow in pipes and flow regimes; methods of flow measurements; open channel flow and gradually varied flow computations; hydraulic machinery introduction to spillways.', 4),
(240, 'Hydraulics – Soft', 'CIE 323', 1, 'Analysis and design using commercially available software: municipal water distribution systems including pipes, reservoir, pumps and losses. Results visualizations and assessment: pressure, velocity, head losses.', 4),
(241, 'Surveying', 'CIE 361', 2, 'Basic measuring procedures for distances, elevations, angles, bearings, azimuths; theory of measurements and errors, leveling, mapping; construction and topographic surveys, traverses, adjustment and closure, subdivision of Land; area and volumes computations, road surveys: coordinate systems, triangulation. Pre-requisite: MEE211 Engineering Graphics', 4),
(242, 'Surveying - Lab', 'CIE 362', 1, 'Students will apply in the field concepts learned in class including basic measuring procedures for distances, elevations, angles, bearings, azimuths; theory of measurements and errors, leveling, mapping; construction and topographic surveys, traverses, adjustment and closure, area and volumes computations.', 4),
(243, 'Steel Structures', 'CIE 400', 3, 'Introduction to the AISC-LRFD design philosophy; discussion of the behavior, analysis and design of steel structures; design of tension members, simple bolted connections, introduction to welded connections, compression members, laterally supported beams, beams under torsion, and lateral torsional loading, members under combined compression and bending loads.', 4),
(244, 'Water Distribution and Treatment', 'CIE 424', 3, 'Physical, chemical and biological water quality parameters and standards; water quantity, population estimation and use factors; methods of distribution and design criteria and periods; stresses in pipes and pipe materials, distribution system related appurtenances; water treatment techniques including sedimentation,  coagulation/flocculation processes and basin design, filtration, disinfection, and effects   of climate change on water supply. Pre-requisite: CIE322 Hydraulics and CIE323 Hydraulics - Soft', 4),
(245, 'Environmental Engineering – Lab', 'CIE 425', 1, 'Fundamental quantities, titration, standards, physical, chemical and biological water and wastewater characteristics and parameter determination using standard methods, data reduction, analysis and interpretation. Pre-requisite: CHM205 Chemical Principles.', 4),
(246, 'Wastewater Collection and Treatment', 'CIE 426', 3, 'Design of sanitary and storm sewers and related appurtenances,   mass balances and hydraulic flow regimes; reaction order and rates, analysis of experimental data, attached and suspended growth biological wastewater treatment systems including: activated sludge and its variations, aerated lagoons, SBR, trickling filters, RBC; basic nitrification-denitrification processes; oxygen requirements; effects of climate change on wastewater treatment.', 4),
(247, 'Environmental Engineering – Soft', 'CIE 427', 1, 'Analysis and design of wastewater treatment processes/ plants using commercially available software: sizing of tanks; and effluent concentration. Results visualizations and assessment.', 4),
(248, 'The Civil Engineering Profession', 'CIE 434', 2, 'This course introduces students to the history and heritage of civil engineering and its specialized sub-disciplines. It emphasizes professionalism, professional registration, engagement in professional societies, and the importance of lifelong learning. Students examine the impact of historical and contemporary issues on the identification, formulation, and solution of engineering problems. The course highlights the societal, economic, environmental, and political impacts of engineering solutions with focus on innovation and infrastructure, sustainable cities and communities, and partnerships for the goals. Team-based projects engage students in research on contemporary engineering challenges such as climate change, sustainability, and global cooperation in infrastructure development. Pre-requisite: fifth-year standing .', 4),
(249, 'Detailing for Civil Engineers', 'CIE 436', 2, 'An introduction to computer-aided drafting techniques and design drawings using a CAD program and sketching to generate two and three dimensional drawings based on the conventions of engineering graphical communication, applications to different Civil Engineering areas of specialty.  A required team effort project introduces the preparation of working design drawings and consideration of production methods. Pre-requisites: MEE211 Engineering Graphics and fifth-year standing.', 4),
(250, 'Soil Mechanics', 'CIE 444', 3, 'Formation and types of soils, field testing and soil classification, permeability and seepage analysis in saturated soils, stresses in a soil mass, total and effective stress analysis, stress-strain relationships and strength properties of soils, failure criteria, and theory of consolidation. Pre-requisite: CIE308 Construction Materials and CIE309 construction Materials - Lab', 4),
(251, 'Soil Mechanics – Lab', 'CIE 445', 1, 'Laboratory testing for properties and characteristics of soils including: classification tests, soil compaction and relative density, hydraulic conductivity, shear strength tests, and consolidation test.', 4),
(252, 'Foundation Engineering', 'CIE 446', 3, 'Analysis, design and construction aspects of foundations including: subsurface exploration and soil characterization; design of shallow foundations based on bearing capacity and settlement calculations; earth pressure theories and design of typical retaining structures; introduction to deep foundations design.', 4),
(253, 'Foundation Engineering – Soft', 'CIE 447', 1, 'Geotechnical analysis and design using commercial software including design of foundations and lateral earth retaining systems. Results visualizations and assessment.', 4),
(254, 'Highway Engineering', 'CIE 460', 3, 'Planning, design, and operation of transportation systems. Theory and practice of the geometric design of streets and highways including horizontal and vertical curves, traffic flow modeling, analysis, control, and safety. Introduction to the design of intersections, interchanges, and pavements. Introduction to Intelligent Highway Systems.', 4),
(255, 'Highway Engineering – Soft', 'CIE 461', 1, 'Highway design using commercial software integrating alignment planning and various geometric design elements. Results visualizations and assessment.', 4),
(256, 'Transportation Systems Engineering', 'CIE 465', 3, 'Road vehicle performance, analysis and design of infrastructure systems, components of highway systems; planning and design of freeway interchanges, highway capacity and quality of service using High Capacity Manual methodologies, fundamentals of traffic flow theory and queuing analysis, traffic control and analysis of intersections, travel demand and forecasting.', 4),
(257, 'Traffic Simulation – Soft', 'CIE 466', 1, 'Modelling and simulation of traffic control systems and components while accounting for macroscopic, microscopic and mesoscopic traffic models using static and dynamic network models. Use of traffic simulation programs, such as CORSIM, Synchro, VISSIM as tools for evaluating the effectiveness of alternative roadway and intersection designs.', 4),
(258, 'Civil Engineering Management Fundamentals', 'CIE 480', 3, 'Organizational behavior and management theory, leadership principles,  understanding of business fundamentals  including forms of business ownership  and public policy making. Introduction to different types of construction projects and construction contracting processes, identification of the different constituents involved in public private construction, phases of a construction project from design to execution, bonds and insurance requirements,  types of delays and change order, dispute resolution processes, and professional ethics. The course also fosters awareness about sustainable management practices and green buildings. Pre-requisite: INE320 Engineering Economy.', 4),
(259, 'Construction Planning and Scheduling', 'CIE 485', 3, 'Quantity take-off and price estimating, proposal preparation, scheduling methods and networks, budgeting, cost control and update; application of construction control tools such as: CPM, PERT, repetitive scheduling method, and overlapping networks; resource allocation and leveling; time-cost tradeoff.', 4),
(260, 'Construction Planning & Scheduling - Soft', 'CIE 486', 1, 'Use of commercial software for the operations, scheduling, planning, resource allocation, budgeting and control of construction projects.', 4),
(261, 'Professional Experience', 'CIE 498', 6, 'Professional experience through training in the execution of real-life engineering projects. Pre-requisite: GNE301 Professional Communication, fifth-year standing and consent of instructor.', 4),
(262, 'Capstone Design Project', 'CIE 499', 3, 'This course provides students with a design experience that is as close as possible to real-life design projects; students will work on multidisciplinary teams according to a team work plan and under the supervision of full-time faculty; each team meets separately with their advisors as needed to complete the work on the project but not less than three times during the semester; students choose from a set of predefined projects that have been approved by the department.', 4),
(263, 'Pre-stressed Concrete Design', 'CIE 501', 3, 'Introduction to the analysis and design of pre-tensioned and post-tensioned reinforced concrete members, and designing these members into the integral structure. Pre-requisite: CIE 306 Concrete Structures I', 4),
(264, 'Design of Hydraulics Structures', 'CIE 502', 3, 'Introduction to the analysis and design of culverts and bridge openings, dam appurtenances, intakes, aprons, chute blocks, spillways and drop structures. It also covers dam safety, stability and protection against scour. Pre-requisites: CIE322 Hydraulics and CIE306 Concrete Structures. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 4),
(265, 'Case Histories in Structural and Geotechnical Engineering', 'CIE 504', 3, 'Case histories in structural and geotechnical engineering, exposing the failures and limitations of the current practice and exploring state of the art solutions. Site visits and visiting lecturers. Pre-requisites: CIE302 Structure Analysis and CIE444 Soil Mechanics . Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 4),
(266, 'Structural Dynamics', 'CIE 506', 3, 'Dynamic response of structures, equations of motion, natural periods of vibration, damping, response spectral analysis, linear systems. Computer applications. Pre-requisite: CIE302 Structural Analysis and Fourth-year standing . Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 4),
(267, 'Seismic Design of Structures', 'CIE 507', 3, 'Introduction to earthquakes, seismological and faulting mechanisms, earthquake loading on structures, design of constructed facilities and infrastructural systems under earthquake loads, risk assessment and case studies. Pre-requisites: CIE 306 Concrete Structures, CIE506 Structural Dynamics, and GNE331 Probability and Statistics. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 4),
(268, 'Applied Elasticity', 'CIE 508', 3, 'Introduction to tensor notation, analysis of stress, two-dimensional elasticity, bending and torsion of prismatic bars, asymmetrically loaded members, beams on elastic foundations and elastic stability. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 4),
(269, 'Concrete Foundation Structures', 'CIE 509', 3, 'Design of reinforced concrete footings, retaining walls, mat foundations, pile caps, shell structures, in addition to other topics. Pre-requisites: CIE306 Concrete Structures and CIE446 Foundation Engineering.', 4),
(270, 'Finite Element Method', 'CIE 510', 3, 'Stress analysis of solids: shape function, displacement interpolation, linear constitutive relations, element stiffness-matrix, direct stiffness method, assessment of model adequacy, error estimation. Stress analysis using commercial software. Pre-requisite: CIE202 Mechanics of Materials and Fourth-year standing.', 4),
(271, 'Pavement Design', 'CIE 511', 3, 'The beam on elastic foundation, rigid and flexible pavements, highway and airport pavements, pavement performance and pavement systems management and maintenance. Pre-requisites: CIE460 Highway Engineering and CIE444 Soil Mechanics .', 4),
(272, 'Concrete Building Structures', 'CIE 512', 3, 'Design of: deep beams, torsion in beams, stair cases, slender columns, bi-axial bending of columns, two-way slabs, shear walls, and load bearing walls.', 4),
(273, 'Reinforced Masonry Design', 'CIE 513', 3, 'Properties, specifications, and construction requirements for structures incorporating clay brick, concrete block, and mortar; analysis and design of masonry structures including diaphragm/shear wall masonry structure design. Pre-requisite: CIE306 Concrete Structures and Fourth-year standing. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 4),
(274, 'Advanced Steel: Design and Behavior', 'CIE 516', 3, 'Design and analysis of moment connections, plate girders, and composite beams. Plastic analysis and designs of beams and frames. Buckling and stability problems, and fatigue of structural steel members. Pre-requisite: CIE400 Steel Structures. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 4),
(275, 'Advanced Structural Analysis for Gravity and Lateral Loads', 'CIE 518', 3, 'Gravity and lateral loads that act on building structures. Load distribution and load paths through building structures to the supporting soil. Comprehensive study of live loads, dead loads, snow loads, wind loads, and seismic loads. Pre-requisite: CIE302 Structural Analysis and Fourth-year standing. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 4),
(276, 'Advanced Reinforced Concrete Behavior', 'CIE 519', 3, 'Advanced behavioral concepts in reinforced concrete structures, including design philosophy, material behavior, confinement in concrete, short and slender columns, bi-axial loading, shear, strut and tie concepts, and bond and anchorage. Pre-requisite: CIE512 Concrete Building Structures Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 4),
(277, 'Solid Waste Management', 'CIE 520', 3, 'Quantity and quality of municipal and industrial solid wastes, collection, transfer, disposal, treatment and recovery of solid wastes, hazardous and non-hazardous residues, solid waste management principles and processes, environmental legislation and risk, and pollution control management. Pre-requisite: Fourth-year standing .', 4),
(278, 'Hydrology', 'CIE 521', 3, 'Occurrence of water, precipitation, interception, depression storage, infiltration, evaporation, transpiration, stream flow, data sources, instrumentation, runoff and hydrographs, hydrologic hydrograph routing, probability in hydrologic design and frequency analysis, and introduction to hydrologic modeling; Pre-requisite: Fourth-year standing.', 4),
(279, 'Environmental Impact Assessment', 'CIE 522', 3, 'Study and evaluation of the impacts of large scale projects on the quality of the physical, biological, and socio-economic environment taking into account environmental laws and regulations and EIA guidelines, identification of impacts, quantification methods, mitigation measures, and monitoring plans. Case study involving the preparation of an EIA report including sustainability impact assessment and effects of climate change. Pre-requisite: Consent of instructor or Fourth-year standing.', 4),
(280, 'Water Resources Planning and Management', 'CIE 523', 3, 'Introduction to the planning and management of water resource systems, and the techniques — such as linear programming, dynamic programming and nonlinear programming — that are used to solve them. Practical problems in water resource systems such as water allocation, water quality management, reservoir operations, flood control, water resources management, basin modelling and flood and drought forecasting demonstrated are discussed with system analysis methods. Pre-requisite: CIE721 Hydrology . Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 4),
(281, 'Air Quality Management', 'CIE 524', 3, 'Analysis of air pollution sources and methods for controlling emissions, with a focus on transportation-related air pollution. The fundamental chemical and physical processes governing pollutant behavior, and a quantitative overview of the characterization and control of air pollution problems. Analysis of key elements of the air pollution system. Pre-requisites: Fourth-year standing . Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 4),
(282, 'Environmental Policy and Management', 'CIE 525', 3, 'This course examines the development and analysis of environmental policy taking into consideration social, political and economic factors. The key elements of environmental management will also be covered. Special attention will be given to the evolution of environmental laws and implementation over the past few decades. Pre-requisite: Fourth-year standing .', 4),
(283, 'Environmental Remediation', 'CIE 526', 3, 'This course covers physico-chemical and biological processes used to remediate contaminated waters and soil media. The control, optimization and monitoring of remediation is discussed as well as the environmental and economic factors. In-situ, ex-situ applications and alternatives remedial actions will be covered. Pre-requisite: Fourth-year standing .', 4),
(284, 'Environmental Microbiology', 'CIE 527', 3, 'Introduction to environmental microbiology and the behavior of microorganisms in engineered and natural environments. Microbial interactions across the three major domains (Eucaryota, Archaea and Bacteria). Microorganisms responsible for biodegradation of organic matter, nutrient cycling, and waste treatment. Introduction to analysis tools for microbial ecology and engineered biological processes. Pre-requisite: Fourth-year standing', 4),
(285, 'Hydrogeology', 'CIE 529', 3, 'Introduction to the distribution of water, hydro-geological structures, movement and storage of water; methods of investigation, collection of samples, observation of water levels, measurement of aquifer properties, speed and direction of ground water flow, and hydro-geological models. Pre-requisite: CIE521 Hydrology. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 4),
(286, 'Irrigation and Drainage', 'CIE 530', 3, 'Irrigation practices and application systems, soil-plant-water relationships, irrigation system types, scheduling, effluent reuse, case studies, quantity and quality of stream flow generated in a drainage basin, and surface, and subsurface, drainage systems. Pre-requisite: CIE322 Hydraulics and Fourth-year standing . Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 4),
(287, 'Groundwater Engineering', 'CIE 533', 3, 'Flow of incompressible fluids through porous media, groundwater movement, Darcy’s law. Introduction to groundwater production, recharge, quality, saltwater intrusion, aquifer management. Differential equations governing the flows. laboratory and field methods of hydraulic conductivity measurements, confined and unconfined flow, and graphical flow nets; seepage control in earth structures, soil stabilization, drainage, geo-textiles, and construction dewatering. Pre-requisite: CIE444 Soil Mechanics. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 4),
(288, 'Computational Hydraulics', 'CIE 534', 3, 'Introduction to the formulation of ordinary and partial differential equations related to flow and transport problems such as flood waves, tidal propagation, shallow waves and transport of pollutants. Numerical solutions using  a commercial software package. Pre-requisite: CIE322 Hydraulics. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 4),
(289, 'Groundwater Hydrology and Pollution', 'CIE 535', 3, 'Provides a thorough understanding of the subsurface environment as it pertains to the distribution and movement of groundwater and the movement and interactions of contaminants. Pre-requisite: Fourth-year standing Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 4),
(290, 'Advanced Geotechnical Engineering', 'CIE 540', 3, 'Advanced topics in geotechnical engineering including: Load and Resistance Factor Design (LRFD); design of deep foundations for axial and lateral loading; two-dimensional limiting equilibrium methods of slope stability analysis; design of shoring systems such as diaphragm walls, sheet-pile walls, anchored walls, and braced excavations. Pre-requisite: CIE446 Foundation Engineering.', 4),
(291, 'Geotechnical Aspects of Earthquake Engineering', 'CIE 544', 3, 'Causative mechanisms of earthquakes; ground motion parameters; seismic hazard analysis; wave propagation and dynamic properties of soils; site response analysis; liquefaction of soil deposits. Pre-requisite: CIE444 Soil Mechanics and Fourth-year standing.', 4),
(292, 'Corrosion Engineering', 'CIE 546', 3, 'Introduction to the principles of corrosion engineering starting from the basic principles of electrochemistry and chemical thermodynamics until prevention and control of corrosion. Case studies from chemical and oil and gas industries are covered. Pre-requisite: Fifth year standing', 4),
(293, 'Traffic Engineering', 'CIE 561', 3, 'Introduction to the effect of vehicular characteristics and human behavior on highway traffic flow and accidents. Traffic regulations, accident prevention, improving traffic flow on existing facilities, planning traffic systems, and terminal problems. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 4),
(294, 'Airport Planning and Design', 'CIE 562', 3, 'This course covers a broad spectrum of airport planning and design issues. Introduction to issues that arise in planning airport systems and the development of new and existing airports, as well as the design of airport facilities to handle aircraft demand: aircraft runway performance and airport interaction, planning the airport system, and analysis methods used in airport engineering. Pre-requisites: CIE465 Transportation Systems Engineering. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 4),
(295, 'Transportation Planning and Land Use', 'CIE 563', 3, 'Interaction between transportation and land use variables, including modeling requirements, impacts, and data needs within the context of good community planning and economic development; transportation management, administration, finance, system evaluation, implementation, and integration as well as incorporation of climate change in planning. Pre-requisites: CIE465 Transportation Systems Engineering and GNE 331 Probability and Statistics.', 4),
(296, 'Mass Transit Systems', 'CIE 564', 3, 'An overview of mass transit systems; transit system planning including demand and cost analysis and evaluation; transit system design including route design, scheduling, and fare policy; transit networks and marketing; Para transit systems; future trends in mass transit. Pre-requisites: INE320 Engineering Economy and CIE465 Transportation Systems Engineering.', 4),
(297, 'Highway Design and Management', 'CIE 566', 3, 'Introduction to highway networks, their engineering and management characteristics, and their maintenance and performance issues, financing and cost recovery methods, and integrated solutions and information technology tools. Pre-requisites: CIE460 Highway Engineering, INE320 Engineering Economy, and Fourth-year standing . Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 4),
(298, 'Infrastructure Management', 'CIE 582', 3, 'General methods of engineering systems management and the different types of infrastructure. Application of different methods for the planning and analysis of complex infrastructure projects considering possible financing alternatives, engineering solutions, and overall management issues during the life cycle of the project. Review of selected case studies from the Arab Gulf countries; climate change and global environmental issues. Pre-requisite: CIE485 Construction Planning & Scheduling. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 4),
(299, 'Sustainable Construction', 'CIE 583', 3, 'Green building delivery system as an emerging paradigm in the design, construction, and operation of buildings. Theory, principles, history, certification process, economic and environmental benefits, and challenges of sustainable construction. Examples of best practices and latest technologies from around the world. Pre-requisite: Fourth-year standing Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 4),
(300, 'Quality Management Systems', 'CIE 584', 3, 'Introduction to quality management systems, ISO 9000, 14000, Total Quality Management, and the applications of QMS to engineering and management of large projects, systems, and organizations. Pre-requisite: Fourth-year standing. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 4),
(301, 'Risk and Natural Hazard Management', 'CIE 585', 3, 'Types, frequency, effects of natural hazards, calculation of return period, planning and designing engineering systems to survive natural events, mitigation of damage. Pre-requisite: GNE331 Probability and Statistics and Fourth-year standing.', 4),
(302, 'Construction Decisions Under Uncertainty', 'CIE 586', 3, 'Application of decision analysis theory to construction project and organization decisions under uncertainty; decision trees and sensitivity analysis, utility assessment, multi-attribute utility theory, multiple sampling and decision strategies; bidding theory and use of probabilistic modeling and Monte-Carlo simulation to determine optimal bidding strategies. Pre-requisites: CIE480 Civil Engineering Management Fundamentals and GNE331 Probability and Statistics.', 4),
(303, 'Construction Cost Engineering', 'CIE 587', 3, 'Construction financial accounting for construction organizations, projects, and operations, generally accepted accounting principles, preparation of financial statements, project progress monitoring and cost controlling, break even analysis, profit, earned value, construction accounts and end-of-period closing; cost indices, parametric estimates, and analysis of financial ratios. Pre-requisite: CIE485 Construction Planning & Scheduling.', 4),
(304, 'Construction Estimating I', 'CIE 588', 3, 'Quantity takeoff for residential and commercial construction projects Including methods  of organizing  a project estimate and  quantity takeoff techniques and methods for earthwork, concrete, masonry, metals and structural steel, wood, doors and windows, finishes, mechanical and electrical.', 4),
(305, 'Construction Methods and Equipment', 'CIE 589', 3, 'Advancement study of the application and analysis of construction equipment and methods. Topics include earthmoving materials and operations, soil characteristics and classification, rock excavation techniques including drilling and blasting, shoring systems, soil stabilization methods, types of foundations, dewatering methods, concrete form design, and equipment economics. Pre-requisites: CIE306 Concrete structures, CIE308 Construction Materials and CIE446 Foundation Engineering.', 4),
(306, 'GIS and Remote Sensing', 'CIE 590', 3, 'Fundamentals of data acquisition and SIS, digital image processing, pattern recognition, feature extraction, and the use of geographic information systems in various applications. Use of GIS and remote sensing in mapping the effects of climate change. Pre-requisite: CIE361 Surveying and Fourth-year standing . Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 4),
(307, 'Construction Safety', 'CIE 593', 3, 'Construction safety issues, concerns, requirements and procedures. OSHA construction industry requirements of safety and loss control regulations. Safety training, planning, administration, inspection, prevention, and control. OSHA 1926 standards and its corresponding subparts. Pre-requisite: Fourth-year standing.', 4),
(308, 'Life Cycle Assessment', 'CIE 594', 2, 'This course introduces Life Cycle Assessment (LCA), focusing on evaluating the environmental impacts of products and processes from cradle to grave. Students will learn LCA principles, methodologies, and tools through practical applications and case studies. Key topics include goal and scope, system boundaries, flow charts, functional units, allocation, inventory analysis, classification, characterization and weighting. The course equips students with skills to analyze and communicate LCA results for sustainable decision-making.', 4),
(309, 'Life Cycle Assessment – SOFT', 'CIE 595', 1, 'Use of a professional software tool to collect, analyze, and monitor the sustainability performance of products and services. Measurement of environmental impacts across all cycle stages of supply chain from raw materials extraction to manufacturing, distribution, use, and disposal.', 4),
(310, 'Topics in Civil Engineering', 'CIE 596', 3, 'Special topic relevant to civil engineering. Course title and content are announced prior to registration time. Pre-requisite: To be announced prior to registration time.', 4),
(311, 'Research Methods', 'CIE 598', 3, 'Introduction to methods for improving and developing research skills; including: principles of scientific research, ethics, writing skills, methods for compiling scientific literature, identification of research questions and specific hypotheses, presentation of research results, writing research papers, proposal preparation, and preparation of grant proposals. Pre-requisite: Fifth year standing', 4),
(312, 'Research Methods', 'CIE 598H', 3, 'Introduction to methods for improving and developing research skills; including: principles of scientific research, ethics, writing skills, methods for compiling scientific literature, identification of research questions and specific hypotheses, presentation of research results, writing research papers, proposal preparation, and preparation of grant proposals. Pre-requisite: Fifth year standing', 4),
(313, 'Undergraduate Research', 'CIE 599', 3, 'Independent work performed by student with emphasis on research. Selection of topic and progress of work are supervised by a faculty advisor. Formal technical report and presentation are required.', 4),
(314, 'Undergraduate Research', 'CIE 599H', 3, 'Independent work performed by student with emphasis on research. Selection of topic and progress of work are supervised by a faculty advisor. Formal technical report and presentation are required.', 4),
(315, 'Topics in Civil Engineering', 'CIE 600', 3, NULL, 4),
(316, 'Finite Element Methods', 'CIE 701', 3, 'This course covers stress analysis of solids which include: shape function, displacement interpolation, linear constitutive relations, element stiffness-matrix, direct stiffness method, assessment of model adequacy and error estimation. It also covers stress analysis using commercial software. Pre-requisite: Graduate Standing.', 4),
(317, 'Concrete Building Structures', 'CIE 702', 3, 'Design of: deep beams; torsion in beams, stair cases, slender columns, two-way slabs, shear walls, and load bearing walls. Pre-requisite: Graduate Standing.', 4),
(318, 'Case Histories in Structural and Geotechnical Engineering', 'CIE 704', 3, 'This course is a selection of case histories in structural and geotechnical engineering, exposing the failures and limitations of the current practice and exploring state of the art solutions. The course involves site visits and visiting lecturers. Pre-requisite: Graduate Standing Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 4),
(319, 'Structural Dynamics', 'CIE 706', 3, 'Dynamics response of structures, equations of motion, natural periods of vibration, damping, response spectral analysis, linear systems. Computer applications..', 4),
(320, 'Seismic Design of Structures', 'CIE 707', 3, 'Introduction to earthquakes, seismological and faulting mechanisms, earthquake loading on structures, design of constructed facilities and infrastructural systems under earthquake loads, risk assessment and case studies.', 4),
(321, 'Applied Elasticity', 'CIE 708', 3, 'This course covers tensor notation, analysis of stress, two-dimensional elasticity, bending of earns torsion of prismatic bars, asymmetrically loaded members, beams on elastic foundations and elastic stability. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 4),
(322, 'Concrete Foundation Structures', 'CIE 709', 3, 'Design of: reinforced concrete footings, retaining walls, mat foundations, pile caps, shell structures, in addition to other topics.', 4),
(323, 'Pre-stressed Concrete Design', 'CIE 710', 3, 'This course covers the design of pre-stressed concrete structures, with an emphasis on flexural design of beams and slabs. Pre-requisite: Graduate Standing', 4),
(324, 'Pavement Design', 'CIE 711', 3, 'This course covers the beam on elastic foundation, rigid and flexible pavements, highway and airport pavements, pavement performance and pavement systems management and maintenance. Pre-requisite: Graduate Standing', 4),
(325, 'Design of Hydraulics Structures', 'CIE 712', 3, 'This course covers the history and background, function, planning process, types, analysis and design of culverts and bridge openings, dam appurtenances, intakes, aprons, chute blocks, spillways and drop structures. It also covers dam safety, stability and protection against scour. Pre-requisite: Graduate Standing Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 4),
(326, 'Reinforced Masonry Design', 'CIE 713', 3, 'Properties, specifications, and construction requirements for structures incorporating clay brick, concrete block, and mortar; analysis and design of masonry structures including diaphragm/shear wall masonry structure design. Pre-requisite: Graduate Standing', 4),
(327, 'Advanced Structural Analysis for Gravity and Lateral Loads', 'CIE 714', 3, 'Gravity and lateral loads that act on building structures. Load distribution and load paths through building structures to the supporting soil. Comprehensive study of live loads, dead loads, snow loads, wind loads, and seismic loads. Pre-requisite: Graduate Standing Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 4),
(328, 'Advanced Steel: Design and Behavior', 'CIE 716', 3, 'Design and analysis of moment connections, plate girders, and composite beams. Plastic analysis and designs of beams and frames. Buckling and stability problems, and fatigue of structural steel members. Pre-requisite: Graduate Standing', 4),
(329, 'Advanced Reinforced Concrete Behavior', 'CIE 719', 3, 'Advanced behavioral concepts in reinforced concrete structures, including design philosophy, material behavior, confinement in concrete, short and slender columns, bi-axial loading, shear, strut and tie concepts, and bond and anchorage. Pre-requisite: CIE702 Concrete Building Structures Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 4),
(330, 'Solid Waste Management', 'CIE 720', 3, 'This course covers the quantity and quality of municipal and industrial solid wastes; the collection, transfer, disposal, treatment and recovery of solid wastes; hazardous and non-hazardous residues, solid waste management processes, environmental impact assessment, environmental legislation and risk, and pollution control management. Pre-requisite: Consent of the instructor .', 4),
(331, 'Hydrology', 'CIE 721', 3, 'This course covers the occurrence of water, precipitation, interception, depression storage, infiltration, evaporation, transpiration, snow melt, well hydraulics, stream flow, data sources, instrumentation, runoff and hydrographs, urban hydrology, hydrograph routing, probability in hydrologic design and the introduction to hydrologic modeling. Pre-requisite: Graduate Standing', 4),
(332, 'Environmental Impact Assessment', 'CIE 722', 3, 'This course covers the study and evaluation of the impacts of large-scale projects on the quality of the physical, biological and socio-economical environment, taking into account environmental laws and regulations as well as environmental impact assessment guidelines. The course covers the identification of impacts, quantification methods, mitigation measures, and monitoring plans. The course deals with a case study involving the preparation of an environmental impact assessment report. Pre-requisite: Graduate Standing', 4),
(333, 'Water Resources Planning and Management', 'CIE 723', 3, 'This course covers the major issues in the planning and management of water resource systems, and the techniques — such as linear programming, dynamic programming and nonlinear programming — that are used to solve them. Practical problems in water resource systems such as water allocation, water quality management, reservoir operations, flood control, water resources management, basin modelling and flood and drought forecasting demonstrated are discussed with system analysis methods. Pre-requisite: CIE721 Hydrology .', 4),
(334, 'Air Quality Management', 'CIE 724', 3, 'This course covers the analysis of air pollution sources and methods for controlling emissions, with a focus on transportation-related air pollution. The course also encompasses a summary of fundamental chemical and physical processes governing pollutant behavior, and a quantitative overview of the characterization and control of air pollution problems. The analysis of key elements of the air pollution system such as the sources and control techniques, atmospheric transformations, atmospheric transport and  modeling are discussed along with the effects of climate change. Pre-requisite: Graduate Standing', 4),
(335, 'Geo-environmental Engineering', 'CIE 725', 3, 'The geotechnical practice in environmental protection and restoration. The characterization of contaminated sites, preliminary site assessment, site investigation techniques and site cleanup and remediation technologies mitigation of the effects of climate change, as well as the monitoring requirements, are discussed. The course also covers the methods of soil and site characterization for siting of waste repositories, the design of waste containment systems, including landfills, slurry walls and soil stabilization, as well as the applicability and use of geosynthetics. Pre-requisite: Graduate Standing', 4),
(336, 'Environmental Microbiology', 'CIE 727', 3, 'Introduction to environmental microbiology and the behavior of microorganisms in engineered and natural environments. Microbial interactions across the three major domains (Eucaryota, Archaea and Bacteria). Microorganisms responsible for biodegradation of organic matter, nutrient cycling, and waste treatment. Introduction to analysis tools for microbial ecology and engineered biological processes. Pre-requisite: Graduate standing', 4),
(337, 'Fate and Transport of Pollutants in the Environment', 'CIE 728', 3, 'This course emphasizes man-made chemicals, their movement through surface and groundwater, air, soil, and their eventual fate. The course covers the physical transport, as well as chemical and biological sources and sinks, and the linkages to health effects, sources and control and policy aspects. Pre-requisite: Graduate Standing Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 4),
(338, 'Hydrogeology', 'CIE 729', 3, 'This course covers the natural parameters, distribution of water, hydro-geological structures, movement and storage of water; methods of investigation, collection of samples, observation of water levels, measurement of aquifer properties, speed and direction of ground water flow, and hydro-geological models. Pre-requisite: CIE721 Hydrology. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 4),
(339, 'Irrigation and Drainage', 'CIE 730', 3, 'This course covers the irrigation practices application systems, soil-plant-water relationships, irrigation system types, scheduling, effluent reuse, case studies, quantity and quality of stream flow generated in a drainage basin, and surface, and subsurface, drainage systems. Pre-requisite: Graduate Standing', 4),
(340, 'Urban Water Resources', 'CIE 731', 3, 'This course covers the urban climate, urban development effects on catchments responses, design of storm water drainage systems, master plans, management for water pollution, sedimentation, and erosion control, use of models for planning and operation, flood control, reservoir design and operation (linear and dynamic programming, and case studies. Pre-requisite: CIE721 Hydrology . Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 4),
(341, 'Advanced Environmental Engineering', 'CIE 732', 3, 'This course covers reaction kinetics, classes and types of reactions, rates and orders, analysis of experimental data, applications, setup of mass balances, flow analysis of CM and PF regimes, detention time in vessels, flow and quality equalization, system material balances, sludge production in activated sludge systems, nitrogen and phosphorus removal, treatment in ponds and wetlands as well as natural systems, fate and transport of pollutants in natural waters, loading equations for streams, dissolved oxygen variation in a stream. Pre-requisite: Graduate Standing Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 4),
(342, 'Groundwater Engineering', 'CIE 733', 3, 'This course covers the flow of incompressible fluids through porous media, groundwater movement, Darcy’s law, groundwater production, recharge, quality, saltwater intrusion, aquifer management, differential equations governing the flows, laboratory and field methods of hydraulic conductivity measurements, confined and unconfined flow, and graphical flow nets and the use of analogs, as well as seepage control in earth structures, soil stabilization, drainage, geo-textiles, and construction denaturing. Pre-requisite: CIE721 Hydrology .', 4),
(343, 'Computational Hydraulics', 'CIE 734', 3, 'This course covers the formulation of ordinary and partial differential equations related to flow and transport problems such as flood waves, tidal propagation, shallow waves and transport of pollutants. The course also covers the numerical solutions using finite difference (explicit and implicit) schemes, finite element techniques and boundary integral methods. Also, the course comprises the measuring techniques in flow problems, data acquisition and online analysis. Pre-requisite: Graduate Standing Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 4),
(344, 'Groundwater Hydrology and Pollution', 'CIE 735', 3, 'Provides a thorough understanding of the subsurface environment as it pertains to the distribution and movement of groundwater and the movement and interactions of contaminants. Pre-requisite: Graduate standing', 4),
(345, 'Advanced Geotechnical Engineering', 'CIE 740', 3, 'Advanced topics in geotechnical engineering including: Load and Resistance Factor Design (LRFD); design of deep foundations for axial and lateral loading; two-dimensional limiting equilibrium methods of slope stability analysis; design methods for slope stabilization; design of shoring systems such as diaphragm walls, sheet-pile walls, anchored walls, and braced excavations. Pre-requisite: Graduate Standing', 4),
(346, 'Geotechnical Aspects of Earthquake Engineering', 'CIE 744', 3, 'Causative mechanisms of earthquakes and ground motion attenuation relationships; Dynamic properties of soils; geotechnical seismic hazards and their mitigation; response of soils to seismic loading; liquefaction of soil deposits; analysis and design of slopes and embankments for seismic loading. Pre-requisite: Graduate Standing', 4),
(347, 'Traffic Engineering', 'CIE 761', 3, 'This course covers the human and vehicular characteristics, as they affect highway traffic flow, traffic regulations, accident cause and prevention, improving the flow on existing facilities, planning traffic systems, and terminal problems.', 4),
(348, 'Airport Planning and Design', 'CIE 762', 3, 'This course covers a broad spectrum of airport planning and design issues. Introduction to issues that arise in planning airport systems and the development of new and existing airports, as well as the design of airport facilities to handle aircraft demand: aircraft runway performance and airport interaction, planning the airport system, and analysis methods used in airport engineering. Pre-requisite: Graduate Standing', 4),
(349, 'Transportation Planning and Land Use', 'CIE 763', 3, 'Interaction between transportation and land use variables, including modeling requirements, impacts, and data needs within the context of community planning and economic development. Advanced transportation management, administration, finance, system evaluation, implementation, and integration as well as incorporation of climate change in planning. Pre-requisite: Graduate Standing', 4),
(350, 'Mass Transit Systems', 'CIE 764', 3, 'An overview of mass transit systems; transit system planning including demand and cost analysis and evaluation; transit system design including route design, scheduling, and fare policy; transit networks and marketing; Para transit systems; future trends in mass transit. Pre-requisite: Graduate Standing', 4),
(351, 'Highway Design and Management', 'CIE 766', 3, 'This course is an introduction to highway networks, their engineering and management characteristics, and their maintenance and performance issues, financing and cost recovery methods, and integrated solutions and information technology tools (use of HDM tools by the World Road Association PIARC). Pre-requisite: Graduate Standing', 4),
(352, 'Construction Decisions under Uncertainty', 'CIE 780', 3, 'Advanced applications of decision analysis theory to construction project. Decision trees and sensitivity analysis, utility assessment, multi-attribute utility theory, multiple sampling and decision strategies; bidding theory and use of probabilistic modeling and Monte-Carlo simulation to determine optimal bidding strategies. Pre-requisite: Graduate Standing', 4),
(353, 'Construction Estimating I', 'CIE 781', 3, 'Advanced topics in quantity takeoff for residential, commercial and heavy construction projects. Methods to organizing different types of estimates. Quantity takeoff techniques and methods for earthwork, concrete, masonry, metals and structural steel, wood, doors and windows, finishes, mechanical and electrical. Pre-requisite: Graduate Standing', 4),
(354, 'Infrastructure Management', 'CIE 782', 3, 'This course covers the general methods of engineering systems management, and the different types of infrastructure. The course analyzes the possible financing and engineering solutions, and alternatives, as well as the overall management during the life cycle of the project. Pre-requisite: Graduate Standing', 4),
(355, 'Sustainable Construction', 'CIE 783', 3, 'Green building delivery system as an emerging paradigm in the design, construction, and operation of buildings. Theory, principles, history, certification process, economic and environmental benefits, and challenges of sustainable construction. Examples of best practices and latest technologies from around the world. Pre-requisite: Graduate standing', 4),
(356, 'Quality Management Systems', 'CIE 784', 3, 'This course is an introduction to quality management systems, ISO 9000, 14000, Total Quality Management, and the applications of QMS to engineering and management of large projects, systems, and organizations. Pre-requisite: Graduate Standing', 4),
(357, 'Risk and Natural Hazard Management', 'CIE 785', 3, 'This course covers the types, frequency, and the effects of natural hazards, the calculation of the return period, and the planning and designing of engineering systems to survive natural events, as well as the mitigation of damage. Pre-requisite: Graduate Standing', 4),
(358, 'GIS and Remote Sensing', 'CIE 788', 3, 'This course covers the fundamentals of sensing earth resources, data acquisition and sis, aircraft and satellite images, digital image processing, pattern recognition, feature extraction, and the geographic information systems in various applications. Use of GIS and remote sensing in mapping the effects of climate change. Pre-requisite: Graduate Standing', 4),
(359, 'Cost Engineering and Control', 'CIE 789', 3, 'This course covers cost engineering for construction organizations, projects, and operations. It encompasses construction financing, break-even, profit, and cash flow analyses, and capital budgeting, as well as the equipment cost and procurement decisions. Construction financial accounting, cost accounting, cost control systems, and databases are discussed, as well as cost indices, parametric estimates, and unit price proposals, measuring work and settling claims. Pre-requisite: Graduate Standing', 4),
(360, 'Construction Methods', 'CIE 790', 3, 'This course is an advancement study of the application and analysis of construction equipment and methods. Topics include drilling, blasting, tunneling, dewatering foundations, and rigging studies. Pre-requisite: Graduate Standing', 4),
(361, 'Construction Safety', 'CIE 793', 3, 'Construction safety issues, concerns, requirements and procedures. International, governmental, and construction industry requirements of safety and loss control regulations. Safety costs, planning, administration, inspection, prevention, loss control and drug-free workplace. Pre-requisite: Graduate Standing', 4),
(362, 'Special Topics Course', 'CIE 796', 3, 'This course is a special topic course which can be offered in any of the concentration areas. When offered, it is counted towards the Degree requirements as a regular course. Pre-requisite: To be announced prior to registration time . Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 4),
(363, 'Thesis', 'CIE 899', 6, 'This course is an independent work performed by students with emphasis on research, and leading to original contribution to knowledge. The selection of the topic and the progress of the work are supervised by a Faculty Advisor. The student is limited to one thesis course per degree. Pre-requisite: Consent of the instructor .', 4),
(364, 'Chemical Engineering Fundamentals', 'CHE 200', 3, 'Overview of chemical and process engineering, introductory principles of Stoichiometry of chemical reactions, material balances in reactors and separation units, material balances in chemical processes, and energy balances in chemical processes, and introduction to practical engineering problems.', 5),
(365, 'Programing for Chemical Engineering', 'CHE 212', 3, 'Principles of computer programming using MATLAB for acquiring fundamentals knowledge and skills to solve chemical and petroleum engineering problems, use of arrays, matrices, loops, if statements, subroutines functions, ordinarily differential equations (ODEs), finite difference methods, fitting, optimization, sensitivity analysis, plotting and tabulation of output results, case studies for chemical and petroleum engineering.', 5),
(366, 'Transport Phenomena', 'CHE 301', 3, NULL, 5),
(367, 'Organic Chemistry I', 'CHE 313', 3, 'This course is an introduction to the basic concepts of organic chemistry with an emphasis on the relation between structure and properties. It also includes nomenclature, properties and reactions of aliphatic hydrocarbons, alkyl halides and alcohols with an emphasis on mechanistic and stereochemical aspects of organic reactions and their application in organic synthesis. The concept of aromaticity is introduced. Perquisite: CHM201 Chemical Principles', 5),
(368, 'Organic Chemistry I Lab', 'CHE 314', 1, 'This laboratory course is designed to provide students with the basic skills for conducting organic reactions. The following techniques are learned: melting point determination, boiling  point determination, simple, fractional and steam distillation, gravity and vacuum filtration, drying solids and liquids, extraction, evaporation, reflux, recrystallization, thin-layer and column chromatography, and polarimetry. Students are introduced to ChemDraw software and molecular modeling.', 5),
(369, 'Chemical Reactions and Chemical Reactors', 'CHE 320', 3, 'This course introduces the principles of chemical reactions and chemical reactors. Reaction kinetics introduced. Several types of reactors designed: non-continuous (batch) and continuous reactors (plug flow reactor, continuous stirred tank reactor, and packed bed reactor). Both isothermal and non-isothermal reactors designed by building the Chemical reaction Engineering algorithm.', 5),
(370, 'Organic Chemistry II', 'CHE 323', 3, 'Topics include UV-visible and IR spectroscopy, mass spectrometry, aldehydes and ketones, carboxylic acids and derivatives, chemistry of aromatic compounds, enolate chemistry, polyenes, free radicals, amines, introduction to carbohydrates and peptides, and multistep synthesis.', 5),
(371, 'Organic Chemistry II Lab', 'CHE 324', 1, 'Laboratory experiments, including chemical compound synthesis, and instrumental analysis.', 5),
(372, 'Physical Chemistry', 'CHE 340', 3, 'Modern physical chemistry topics including molecular quantum mechanics, spectroscopy, and thermodynamics. Emphasis on quantitative understanding of chemical systems.', 5),
(373, 'Physical Chemistry Lab', 'CHE 341', 1, 'Laboratory experiments supplementing CHE340, with experiments related to spectroscopy, kinetics, polymers, colloids, electrochemistry, diffusion, and thermochemistry', 5),
(374, 'Separation Processes I', 'CHE 402', 3, 'This course includes thermodynamics, mechanisms, and design of separation units used for distillation, absorption, extraction, and solid-fluid systems.', 5),
(375, 'Separation Processes II', 'CHE 403', 3, 'This course covers design of separation units used for crystallization, adsorption, membrane separation, ion exchange, and chromatography, with a with a focus on their applications in sustainable processes. Emphasis is placed on energy-efficient and environmentally friendly designs by enabling water purification and desalination, through advancements in biofuel production and gas separation, and by promoting waste minimization and resource recovery .', 5),
(376, 'Fundamentals of Catalysis', 'CHE 411', 3, 'This course covers the fundamentals of catalysis: history of catalysis, catalytic materials, synthesis and characterization, catalytic reactor design and catalyst deactivation and regeneration. In addition, several important industrial catalytic processes will be covered including Fisher-Tropsch synthesis, hydrogenation, dehydrogenation, and oxidation of organic compounds.', 5),
(377, 'Advanced Reactor Design', 'CHE 421', 3, 'Advanced aspects of reactor design. Design and scale-up under realistic conditions of various types of chemical reactors. Safety in chemical reactors.', 5),
(378, 'Chemical Engineering Profession', 'CHE 434', 2, NULL, 5),
(379, 'Introduction to Process Control', 'CHE 450', 3, 'Continuous-time and discrete-time signal transformations and system classifications; Linear time invariant system analysis; Fourier series and transform; Laplace transform; block diagram algebra and signal flow graph; stability analysis techniques; root locus; state space analysis; modern and classical control designs.', 5),
(380, 'Chemical Engineering Lab', 'CHE 451', 1, 'Experiments of separation, chemical reactions, and process control. Emphasis on safety.', 5),
(381, 'HSE for Chemical Engineering', 'CHE 460', 3, 'This course covers safety, health and environment (HSE) related to chemical engineering field. Hazards and prevention of potential accidents as well as emergency preparedness. Audit preparation and evaluation. Process design considering HSE. HAZOP and HAZAN software used for case studies.', 5),
(382, 'Professional Experience', 'CHE 498', 6, 'Professional experience through training in the execution of real-life engineering projects. Pre-requisites: CHE434 ,CHE403, CHE460, CHE421 and either one of the following: CHE411 or CHE450.', 5),
(383, 'Applied Mathematics for Chemical Engineers', 'CHE 500', 3, 'Review of ordinary differential equations, nonhomogeneous equations; series solutions of linear ordinary differential equation. Laplace transform methods; Fourier-Bessel series and separation of variables for partial differential equations. Gamma, Bessel, Laguerre functions, and Legendre polynomials. Pre-requisite: MTH304 Differential Equations.', 5),
(384, 'Advanced Chemical Engineering Thermodynamics', 'CHE 501', 3, 'This course builds on undergraduate thermodynamics material. It covers physical and thermodynamic properties, and   phase equilibria, equations of state, and the liquid activity coefficient equations. Vapor-liquid, liquid-liquid,   vapor-liquid-liquid and solid-liquid equilibria are rigorously covered. A variety of methods for estimating   physical and thermodynamic properties are introduced.  The course includes an   introduction to statistical thermodynamics. Pre-requisite: MEE301 Thermodynamics', 5),
(385, 'Bioprocess Engineering', 'CHE 502', 3, 'Application of process engineering principles to the design and operation of fermentation reactors which are widely used in the pharmaceutical, food, brewing and waste treatment industries. Aspects of mass transfer, heat transfer, mixing and rheology with biochemical and biological constraints Pre-requisite: fourth-year standing', 5),
(386, 'Carbon Capture, Storage, and Utilization', 'CHE 541', 3, 'Carbon dioxide sources and emission levels. Net-zero emissions targets and energy transition. Introduction to capture and separation of CO2 produced by power generation or industrial activity using chemical processes. Conversion of CO2 by catalytic processes (e.g. methanation, dry reforming, etc.) into synthetic fuels and chemicals. CO2 storage in depleted oil and gas reservoirs, and other geologic formations.', 5),
(387, 'Chemical Reactor Design', 'CHE 542', 3, 'Introduction to the principles of reactor design. Non-continuous (batch) and continuous reactors (plug-flow, continuous stirred tank reactors and packed-bed reactors) are introduced in addition to semi-batch and membrane reactors. Design of reactors is practiced by using the chemical reaction engineering algorithm with its five building blocks. Classical reaction kinetics including rates, mechanisms and temperature effects are studied. Pre-requisite: PTE450 Introduction to Process Engineering', 5),
(388, 'Mass Transfer Operations', 'CHE 544', 3, 'Introduction to the basic principles of mass transfer needed to formulate and solve engineering problems involving different operations like absorption and stripping, distillation, liquid-liquid extraction, humidification, membrane and solid-sorbent agent separations. Pre-requisite: CHM205 Chemical Principles and PTE450 Introduction to Process Engineering', 5),
(389, 'Corrosion Engineering', 'CHE 546', 3, 'Introduction to the principles of corrosion engineering starting from the basic principles of electrochemistry and chemical thermodynamics until prevention and control of corrosion. Case studies from chemical and oil and gas industries are covered. Pre-requisite: Fifth-year standing', 5),
(390, 'Chemical Process Design', 'CHE 548', 3, 'This course combines material from several chemical engineering courses in order to design chemical processes. Students will learn some basics to implement real engineering projects: a flow sheet will be translated, using software, into a real process. Pre-requisites PTE450 Introduction to Process Engineering, CHE542 Reactor design, CHE544 Mass Transfer Operations, MEE403 Heat Transfer', 5),
(391, 'Industrial Catalytic Processes', 'CHE 549', 3, 'Fundamentals of catalytic science; catalyst synthesis, characterization, testing and usage in reactors and catalyst deactivation. Discussion of important industrial catalytic processes: Hydrogen Production and synthesis gas reactions, hydrogenation and dehydrogenation of organic compounds, oxidation of organic and inorganic compounds. Pre-requisite: PTE450 Introduction to Process Engineering', 5),
(392, 'Chemical Process Design', 'CHE 552', 3, 'Concepts learned in all chemical engineering core courses applied in this course to design chemical processes and plants.', 5),
(393, 'Chemical Process Design Lab', 'CHE 553', 1, 'Design and simulate chemical processes using computer aided process design and simulation tools like Aspen Plus. Determination of optimal operating conditions using optimization techniques. Perform cost estimation, energy efficiency evaluation and environmental impact assessment. Conduct risk assessment of chemical processes using Hazop (Hazard and Operability Study)', 5),
(394, 'Process Control Strategies', 'CHE 554', 3, 'State space methods. Sampled-data systems. Discrete systems. Transform methods. Multivariable control. Computer control. Closed-loop analysis. Design of controllers. Control of complex chemical systems. Pre-requisite: fourth-year standing', 5),
(395, 'Microprocessors in Process Control', 'CHE 555', 3, 'Introduction and overview of microprocessor-based technology in chemical engineering; analog and digital signal conditioning, data transmission and serial interfacing, analog-to-digital conversion and sampling; digital-to-analog conversion; digital I/O, switches/relays, and power supplies; microprocessor-based sensors, transducers and actuators; programmable logic controllers and batch process control; software packages for data-acquisition and control Pre-requisite: CHE450 Introduction to Process Control', 5),
(396, 'Advanced Process Control', 'CHE 556', 3, 'Mathematical modeling and identification of chemical processes. State-space process representation and analysis: stability, observability, controllability and reach-ability. Analysis and design of advanced control systems: internal model control, dynamic matrix control and model predictive control. Synthesis of multivariable control systems: interaction analysis, singular value decomposition, decoupler design. Continuous and sampled-data systems, on-line process identification. State and parameter estimation techniques: Luenberger observer and Kalman filter. Pre-requisite: CHE450 Introduction to Process Control', 5),
(397, 'Bioseparation Engineering', 'CHE 557', 3, 'Bioseparation engineering using specialized unit operations. Processing operations including product recovery, separations, purification, and ancillary operations. The principles of chromatography, Ion exchange, and affinity-based separation. Pre-requisite: fifth-year standing', 5),
(398, 'Petroleum Engineering Fundamentals', 'CHE 560', 3, NULL, 5),
(399, 'Drilling Engineering', 'CHE 561', 3, 'Introduction to drilling systems; equipment functions, performance, and design considerations of rotating system, hoisting system, and circulation system; drilling fluids calculations and selections; directional drilling; hydraulic programs; drilling optimization; casing string design; cementing techniques; well planning and control; drilling hydraulics; formulation evaluation and well completion; well deliverability; artificial lift; and drilling problems.', 5),
(400, 'Production Engineering', 'CHE 562', 3, 'Analysis, specification, and characteristics of production systems, design of well flow systems, types and characteristics of well completions, perforating, well bore damage and simulation, combined inflow and well performance analysis, artificial lift systems, and related production problems, oil well pumping, gas lift, surface facilities and flow measurement, well stimulation design methods, work over and recompletion analysis, design of surface separation and treating facilities.', 5),
(401, 'Well Testing', 'CHE 563', 3, 'Well test design and interpretation; analysis methods for pressure drawdown, buildup, and interference tests; principle of superposition and its application in well test analysis; average reservoir pressure estimation; effect of well bore conditions on pressure behavior; an introduction to drill stem testing and gas well testing.', 5),
(402, 'Reservoir Engineering', 'CHE 564', 3, 'Classification of subsurface reservoirs by type and recovery mechanism; analysis and prediction of reservoir performance by use of volumetric and material balance and state flow equations, influx theory, application of principles of reservoir analysis and modeling concepts to the determination of reservoir behavior and education; reserve estimates; introduction to displacement processes.', 5),
(403, 'Gas Engineering', 'CHE 565', 3, 'Analysis of four-point gas deliverability tests and gas well pressure transient tests, methods for determining wet gas and condensate reserves in volumetric and water drive reservoirs, gas inflow performance equations and methods of forecasting future production rates, essential surface facilities and methods for handling sour gas and hydrates.', 5),
(404, 'Reservoir Simulation', 'CHE 566', 3, 'Reservoir simulation for petroleum reservoir characteristics and behavior, pore volume, fluid distribution and movement, and recover; result simulation studies of optimized field development and management plans which maximize the value and/or reserves of producing properties; governing equations for development of several analytical models for reservoir evaluation and analysis; finite difference approximations to the diffusivity equation and the application of those approximations for reservoir simulations; application to common reservoir engineering problems.', 5),
(405, 'Sustainable Energy', 'CHE 570', 3, 'Pre-requisite: fourth-year standing', 5),
(406, 'Fundamentals of Advanced Energy Conversion', 'CHE 571', 3, 'Fundamentals of thermodynamics, chemistry, and transport as applied to energy systems. Analysis of energy conversion and storage in thermal, mechanical, chemical, and electrochemical processes in power and transportation systems, with emphasis on efficiency, performance, and environmental impact. Applications to fuel reforming and alternative fuels, hydrogen, fuel cells and batteries, combustion, catalysis, combined and hybrid power cycles using fossil, nuclear and renewable resources. CO 2 separation and capture. Biomass energy. Pre-requisite: CHE570 Sustainable Energy', 5),
(407, 'Biofuels Engineering Technology', 'CHE 572', 3, 'The fundamental concepts of biofuels and the current state-of -the-art technology for their production along with economics, environmental impact, and policy issues.  Conversion of feedstock to biofuels by both biochemical and thermochemical methods. Pre-requisite: CHE570 Sustainable Energy', 5),
(408, 'Electrochemical Energy Systems', 'CHE 573', 3, 'Principles and mathematical modeling of electrochemical energy conversion and storage. Equivalent circuits, thermodynamics, reaction kinetics, transport phenomena, electrostatics, porous media, and phase transformations. Applications to batteries, fuel cells, supercapacitors, and electrokinetics. Pre-requisite: CHE570 Sustainable Energy', 5),
(409, 'Capstone Design I', 'CHE 591', 3, 'Based on skills and concepts learned in all core chemical engineering courses to design a process that aims to solve an industrial problem. Projects can be conducted in collaboration with an industrial or academic partner.', 5),
(410, 'Capstone Design II', 'CHE 592', 3, 'Continuation of CHE499 to design and optimize an overall process or product based on societal, safety, environmental, and economic constraints.', 5),
(411, 'Computer Applications in INE', 'INE 212', 2, 'This is an introductory course on computer applications in Industrial engineering.  Course covers LINGO as a general purpose modelling language for writing and solving mathematical programs for INE applications; MATLAB including array definitions and manipulations, user-defined functions, plotting and built-in functions for data analysis and MATLAB Optimization and Statistics toolbox; and Excel for data analysis, statistical tests, design of experiments, and statistical quality control and process improvements.', 6),
(412, 'Deterministic OR models', 'INE 307', 3, 'Introduction to deterministic OR modeling. Optimization modeling: decision variables, objective functions, and constraints. Models include linear programs, integer programs, transportation and assignment problems, simple network problems. Methods include simplex method, transportation simplex, shortest path, minimum cost flow, and maximum flow problems. Pre-requisites: GNE333 Engineering Analysis I and COE 212 Engineering Programming or COE211 Computer Programming', 6),
(413, 'Stochastic OR Models', 'INE 308', 3, 'Introduction to discrete Markov chains and continuous Markov Processes, including transient and limiting behavior.  The Poisson/ Exponential process. Conditional probabilities and conditional expectations. Applications to reliability, maintenance, inventory, production, simple queues and other engineering problems.  Introduction to decision theory, risk, utility and decision trees. Pre-requisites: GNE331 Probability and Statistics.', 6),
(414, 'Engineering Economy I', 'INE 320', 3, 'This course covers equivalence and interest formulas, real-world transactions, present worth analysis, annual equivalent worth, rate of return analysis, depreciation, inflation, and cost/benefit ratio. Pre-requisite: Third-year standing.', 6),
(415, 'Engineering Economy I', 'INE 320H', 3, 'This course covers equivalence and interest formulas, real-world transactions, present worth analysis, annual equivalent worth, rate of return analysis, depreciation, inflation, and cost/benefit ratio. Pre-requisite: Third-year standing.', 6),
(416, 'Advanced Statistics', 'INE 340', 3, 'This course covers single factor experiments, randomized blocks, Latin squares, introduction to factorial designs, 2k factorial blocking and confounding, and forecasting. Pre-requisite: GNE331 Probability and Statistics.', 6),
(417, 'Production Systems I', 'INE 346', 3, 'Course is an introduction to subjects that span the industrial engineering curriculum and that are covered in greater detail in more advanced courses. Subjects covered are Forecasting, EOQ, safety stock, Process design, Aggregate Planning, facilities planning and logistics, quality control, human factors, ergonomics and work design, principles of Industrial Management and Project management. Pre-requisites: GNE331 Probability and Statistics, INE307 Deterministic OR models.', 6),
(418, 'Manufacturing Processes', 'INE 362', 3, 'This course offers a balanced quantitative and qualitative coverage of manufacturing processes: Casting, Material Removal, Deformation, Welding and Assembly. Course presents an overview of engineering materials, primary-manufacturing processes and includes projects tailored towards using manufacturing processes for obtaining functional products. Pre-requisite: MEE321 Material Properties and Processes.', 6),
(419, 'Manufacturing Lab', 'INE 363', 1, 'Lab provides students with hands on experience in the use of traditional mechanical workshop equipment and software for manufacturing drawings generation. Students are also introduced to CNC Programming.', 6),
(420, 'Optimization', 'INE 402', 3, 'This course covers queuing theory and models, linear programming, integer programming, transportation/allocation, assignment, inventory, annealing, networks, dynamic programming, forecasting, and simulation techniques.', 6),
(421, 'Network Flow', 'INE 407', 3, 'This course covers networks, shortest/longest path, decision trees, and network flow. Pre-requisite: INE307 Deterministic OR models or Consent of instructor.', 6),
(422, 'Ergonomics', 'INE 416', 3, 'Course covers the biomechanics of the musculoskeletal system; anthropometry; manual work design; lifting; motion study; workstation, tools, and tasks design; displays & controls design; machine user interfaces; environmental stress assessment (noise, heat, illumination); toxicology; cognitive work design; operations analysis; worker and machine relationships; productivity measures; time standards; allowances; work sampling; predetermined time systems; learning curves; wage payment; safety and risk factor identification; worker motivation; job evaluation; job compensation. Pre-requisites: Third year standing.', 6),
(423, 'Ergonomics Lab', 'INE 417', 1, 'Lab provides students with hands on experience in the use of the state of the art ergonomics equipment and software for virtual human modeling.', 6),
(424, 'Project Management', 'INE 428', 3, NULL, 6),
(425, 'Facilities Planning & Logistics', 'INE 438', 3, 'Course covers topics in flow measurements and analysis, flow planning, activity planning and relationships, layout planning, single facility location models minimax and minisum facility location, multiple facility location, process capacity analysis, materials handling capacity analysis, facilities planning in the context of supply chain design and supply chain excellence. Pre-requisites: INE446 Production Systems II.', 6),
(426, 'Quality Control', 'INE 442', 3, 'This course covers the modeling process quality, inferences about process quality, statistical process control, types of control charts, acceptance sampling, and process capability analysis. Pre-requisites: INE346 Production Systems I.', 6),
(427, 'Production Systems II', 'INE 446', 3, 'Pre-requisites: INE346 Production Systems I.', 6),
(428, 'Simulation', 'INE 450', 3, 'This course covers random number generation, random variety generation, components of discrete event simulation, learning simulation software, and the simulation of simple systems: queuing, inventory, manufacturing, QC, transportation, layout.', 6),
(429, 'Simulation Lab', 'INE 451', 1, 'Lab course complements the course INE450 simulation. This lab provides students with hands-on experience in the use of state of the art simulation tools and programs such as ARENA.', 6),
(430, 'Seminar on Contemporary Issues in INE', 'INE 491', 2, 'This is a seminar course covering contemporary issues in Industrial Engineering. Students are asked to research contemporary subjects in the field and present findings to the class. Pre-requisites: Fourth-year standing.', 6),
(431, 'Professional Experience', 'INE 498', 6, 'This course covers professional experience, through training in the execution of real-life engineering projects. Pre-requisites: Fifth-year standing and the consent of the instructor.', 6),
(432, 'Dynamic Programming', 'INE 505', 3, 'This is a course on the theory and practice of dynamic programming. Topics covered in Deterministic DP: Shortest path algorithms including label setting and correcting, A*, and solution horizon approaches, with applications in resource allocation, knapsack problem, capacity expansion, equipment replacement, and traffic routing; Infinite decision trees and dynamic programming networks with cycles. Topics covered in Stochastic DP are stochastic shortest path problem and Markov decision processes. Applications include asset divesture, capital budgeting, portfolio selection, inventory control, systems reliability, and maximization of expected utility with constant risk posture.', 6),
(433, 'Decision Analysis', 'INE 506', 3, 'This course covers decision analysis, game theory, Bayesian decision theory, and the utility theory. Pre-requisite: GNE331 Probability and Statistics.', 6),
(434, 'Engineering Economy II', 'INE 521', 3, 'This course deals with the uncertainty, breakeven analysis, sensitivity analysis, probabilistic risk analysis, and accounting principles. Pre-requisites: INE320 Engineering Economy I and fourth-year standing', 6),
(435, 'Financial Engineering', 'INE 523', 3, 'Introduction to financial models: mean-variance analysis, portfolio selection, separation theorems, capital asset pricing, arbitrage pricing, derivative security pricing, bond management. Modeling, analysis, and computation of derivative securities. Applications of stochastic calculus and stochastic differential equations. Numerical techniques: finite-difference, binomial method, and Monte Carlo simulation. Pre-requisites: INE308 Stochastic OR Models and fourth-year standing.', 6),
(436, 'Project Scheduling', 'INE 527', 3, 'This course covers the basic critical path planning and scheduling, with arrow and precedence networks, introduction to resource leveling, and least cost scheduling, including time-cost trade-off analysis, and schedule control. Pre-requisites: consent of instructor or fourth-year standing. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 6),
(437, 'Project Contracting', 'INE 529', 3, 'This course covers construction contracting for contractors, owners, and engineers. (1) Industry structure, (2) Types of contracts and delivery systems of construction, (3) Planning, estimating, quantity takeoff and pricing, labor and equipment estimate, (4) Proposal preparation, and students use of contract documents to prepare detailed estimates. Pre-requisites: Consent of instructor or fourth-year standing.', 6),
(438, 'Quality Management Systems', 'INE 541', 3, 'Course covers Total Quality Management theories and application, Design for Six Sigma (DFSS) and six sigma approaches, DMAIC, Auditing, ISO standards and ISO certification. Pre-requisites: INE442 Quality Control and fourth-year standing. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 6),
(439, 'Supply Chain Management', 'INE 542', 3, 'Special topics of current interest; Treatment of new developments in various areas of industrial engineering as warranted; Network Design in a Supply Chain; Demand Forecasting and Aggregate Planning; Transportation Networks; Sourcing. Pre-requisites: INE346 Production Systems I and fourth-year standing.', 6),
(440, 'Inventory Analysis', 'INE 544', 3, 'This course covers continuous/periodic/ deterministic/stochastic inventory models, materials requirements planning (MRP), just-in time production systems, assembly systems, and flexible manufacturing distribution systems. Pre-requisites: INE446 Production Systems II or consent of instructor.', 6),
(441, 'Machine Scheduling', 'INE 548', 3, 'This course covers basic single machine problem (BSMP), flow shop scheduling with setup cost (TSP), and vehicle routing. Pre-requisites: INE446 Production Systems II or consent of instructor.', 6),
(442, 'CAD/CAM', 'INE 563', 3, 'This course introduces students to the use of product lifecycle management (PLM) software packages for sketching, drafting, modeling, assembly and prototyping. Course includes projects tailored towards using software to the design and manufacturing of a physical product. Pre-requisite: INE362 Manufacturing Processes Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 6),
(443, 'Project I', 'INE 591', 3, 'This course covers selected engineering project, using acquired technical knowledge, formal report, and presentation. Pre-requisites: Fifth year standing and INE362 Manufacturing Processes, INE450 Simulation, INE446 Production Systems II.', 6),
(444, 'Project II', 'INE 592', 3, 'This course covers advanced engineering project, using acquired technical knowledge, formal report, and presentation. Pre-requisites: Fifth-year standing and INE591 Project I.', 6),
(445, 'Capstone Engineering Design', 'INE 593', 1, 'The course will reinforce and integrates topics covered in other courses in the curriculum and used in engineering design.  Topics covered include need identification and problem definition, managing the design process, team behavior and group dynamics, design research and information gathering, concept generation and evaluation, risk, reliability, and safety, legal and ethical issues in design, communicating the design.', 6),
(446, 'Undergraduate Research Project', 'INE 594', 3, 'This course covers advanced engineering undergraduate research project, using acquired technical knowledge, formal report, and Presentation. Pre-requisites: Fourth-year standing and the consent of the instructor; GPA ≥ 3.0', 6),
(447, 'Undergraduate Research Project', 'INE 594H', 3, 'This course covers advanced engineering undergraduate research project, using acquired technical knowledge, formal report, and Presentation. Pre-requisites: Fourth-year standing and the consent of the instructor; GPA ≥ 3.0', 6),
(448, 'Topics in Industrial Engineering', 'INE 599', 3, 'This course covers the treatment of new development, in various areas of industrial engineering. Pre-requisites: Fourth-year standing. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 6),
(449, 'Lean Manufacturing', 'INE 599A', 3, 'This is an introduction course for all engineering disciplines.  The course focuses on the concepts, principles, tools and techniques of Lean Manufacturing.  Examples from the manufacturing environment and administrative functions will be utilized to explain key concepts.', 6),
(450, 'Intro to System Dynamics', 'INE 599D', 3, 'This course introduces you to system dynamics modeling for the analysis of policy and strategy in an industrial context.  System dynamics allows us to abstract complex situations down to a level where we can visualize the long-term side effects of decisions, and systematically explore new strategies and policies that increase performance and reduce undesirable side effects.  We use role playing games, simulation models and case studies to develop sound principles of policy design for successful management of complex strategies.', 6),
(451, 'Six Sigma', 'INE 599G', 3, 'This is an introduction course for engineering disciplines.  The course focuses on the concepts, principles, tools and techniques of Six Sigma.  Examples from the manufacturing environment and administrative functions will be utilized to explain key concepts.', 6),
(452, 'Industrial Engineering Applications in Services Industries', 'INE 599I', 3, 'This is an introduction course for all engineering disciplines.  The course focuses on the application of Industrial Engineering tools and principles to improve the quality and productivity of service industries such as restaurants, banks, hotels, health care, etc. This course includes lecture, case studies as well as project. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 6),
(453, 'Risk Assessment and Management', 'INE 599K', 3, 'Risk assessment and management is the identification, analysis, and prioritization of risks; as well as the coordinated treatment of risk to prevent, minimize, monitor, and control the probability and/or impact of undesirable events and consequences. Areas covered include the principles and applications of risk assessment and management in the context of engineering management and systems engineering. This course is about the systematic approach to the management of risk as applied to engineering, operations, and management decisions Students will be prepared to function in a business environment, developing an awareness of the challenges, the tools, and the process of designing and implementing risk assessment and management strategies.', 6),
(454, 'Renewable Energy', 'INE 599M', 3, 'Course Description: A course that covers the principles of emerging renewable technologies, including solar, wind, biomass, geothermal, hydropower and other energy sources. A premise of the course is that a renewable energy technology must both be technically feasible and economically viable. At the conclusion of the course, students will have a solid technical and economic understanding of these energy technologies.', 6),
(455, 'Data Analytics using R Language', 'INE 599P', 3, 'This course covers data analysis, Metrology, multivariate analysis and applications using R language.', 6),
(456, 'Risk Management in Healthcare', 'INE 599Q', 3, 'In an evolving environment with a growing complexity of healthcare organizations, comes new sets of risks and a new dimension of risk management. This course will go through the main concepts of conventional risk management and their implementation in the organizational structure of healthcare institutions. You will get acquainted with healthcare structures, challenges and concerns at the introductory level and go over the implementation of risk management techniques in this specific environment.', 6),
(457, 'Queuing Theory & Application', 'INE 599R', 3, 'This course is an introduction to congestion and related stochastic models. Topics include birth and death models, measures of performance, Little’s Law, conservation law, PASTA, work in system, service disciplines and priorities, regenerative processes, stability and stationary distributions, approximations and bounds. Examples from telecommunications, production, inventory, and computer science, are covered.', 6),
(458, 'Topics: Optimal Resource Allocation Methods in industrial Systems', 'INE 599S', 3, 'This class is an introduction to resource allocation methods using systematic approaches based on mathematical models and cost-benefit analysis. These methods allow planners determine the optimal allocation that offers the most value and impact. Topics include traditional traffic models, in addition to novel intelligent dynamic models. These models can be used for efficient capacity planning and resource allocation in assembly systems consisting of dedicated and reconfigurable lines, in call centers, and in transportation. These methods can also be used by industrial support teams to make better staffing decisions while maintaining constraints.', 6),
(459, 'Tp: Industrial Automation Systems', 'INE 599T', 3, 'This course examines the various dimensions and determinants of health and wellbeing. An emphasis is placed on public health as well as the social and mental health aspects of wellbeing. An interdisciplinary approach is used to address present and future challenges to physical and mental wellbeing of the public. This course will rely on case studies as well as other active learning strategies to enhance students’ problem-solving skills and wellbeing based on applied, day-to-day examples.', 6),
(460, 'Micro & Surface Engineering', 'INE 599U', 3, 'This course centers on the micro world of surface engineering science, emphasizing how modifying material surfaces at micro and nano scales can significantly enhance performance and durability. Techniques such as ceramic coating, micromachining, ultrasonics, and laser pulse treatment are employed to improve surface functionality. These approaches play a crucial role in the innovation of manufactured products at small scales. Applications span across high-tech sensor development, electronics, micro-engines, and hydrophobic surfaces, with relevance to various industries, including biomedical, electronics, aerospace, and ceramic coatings.', 6),
(461, 'Environmental Impact Assessment', 'INE 599V', 3, 'Study and evaluation of the impacts of large scale projects on the quality of the physical, biological, and socio-economic environment taking into account environmental laws and regulations and EIA guidelines, identification of impacts, quantification methods, mitigation measures, and monitoring plans. Case study involving the preparation of an EIA report including sustainability impact assessment and effects of climate change.', 6),
(462, 'Construction Cost Engineering', 'INE 599W', 3, 'Construction financial accounting for construction organizations, projects, and operations, generally accepted accounting principles, preparation of financial statements, project progress monitoring and cost controlling, break even analysis, profit, earned value, construction accounts and end-of-period closing; cost indices, parametric estimates, and analysis of financial ratios.', 6),
(463, 'Green Engineering', 'INE 599X', 3, 'This course explores the pivotal role of innovative green engineering practices in enhancing product value, minimizing pollution, and reducing costs. It covers key topics including the Green Economy, Green Business, Green Marketing, Green Finance, Green Design, and Green Cities. Additionally, the course examines Economic Efficiency versus Profitability, methods for Quantifying Internal and External Costs, Assessing Environmental Degradation Costs, and the integration of ESG (Environmental, Social, and Governance) principles and CSR (Corporate Social Responsibility) strategies. Pre-requisites: Fourth-year standing', 6),
(464, 'Aerospace Processes, Materials and Applications', 'INE 599Y', 3, 'Modern aerospace and automotive sectors require advanced materials that meet demands for strength, low weight, durability, and reliability. This course explores recent advances in materials and processing methods, as well as their applications in aerospace and high-performance automotive engineering. Topics include polymer and metallic composites, highlighting their high-strength and lightweight, use in aircraft structures, spacecraft, and next-generation vehicles. Powder metallurgy is addressed with emphasis on the processing and application as in turbine engines and racing systems. Fracture mechanics and failure analysis are introduced to assess fatigue life and durability in demanding environments. The course also reviews PCB materials and fabrication techniques for aerospace / automotive applications. Hands-on projects and industry case studies support practical understanding of these technologies.', 6),
(465, 'Advanced Statistics', 'INE 700', 3, 'This course covers single factor experiments, randomized blocks, Latin squares, introduction to factorial designs, 2k factorial blocking and confounding, and forecasting.', 6),
(466, 'Linear programming', 'INE 701', 3, 'This course covers the formulation of linear programming problems, simplex method, and duality and sensitivity analysis. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 6),
(467, 'Integer Programming', 'INE 702', 3, 'This course covers integer programming, and general search techniques. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 6),
(468, 'Dynamic Programming', 'INE 703', 3, 'This is a course on the theory and practice of dynamic programming. Topics covered in Deterministic DP: Shortest path algorithms including label setting and correcting, A*, and solution horizon approaches, with applications in resource allocation, knapsack problem, capacity expansion, equipment replacement, and traffic routing; infinite decision trees and dynamic programming networks with cycles. Topics covered in Stochastic DP are stochastic shortest path problem and Markov decision processes. Applications include asset divesture, capital budgeting, portfolio selection, inventory control, systems reliability, and maximization of expected utility with constant risk posture. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 6),
(469, 'Stochastic Processes', 'INE 704', 3, 'This course covers Markov decision processes, and chains stochastic processes. Pre-requisite: Consent of the instructor. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 6),
(470, 'Non-Linear Programming', 'INE 705', 3, 'This course covers nonlinear/continuous optimization methods. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 6),
(471, 'Decision Analysis', 'INE 706', 3, 'This course covers decision analysis, game theory, Bayesian decision theory, and utility theory.', 6),
(472, 'Network Flow', 'INE 707', 3, 'This course covers networks, shortest/longest path, decision trees, and network flow. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 6),
(473, 'Queuing Theory & Application', 'INE 708', 3, 'This course is an introduction to congestion and related stochastic models. Topics include birth and death models, measures of performance, Little’s Law, conservation law, PASTA, work in system, service disciplines and priorities, regenerative processes, stability and stationary distributions, approximations and bounds. Examples from telecommunications, production, inventory, and computer science, are covered. Pre-requisite: INE704 Stochastic Processes or Consent of the instructor. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 6),
(474, 'Advanced Stochastic Processes', 'INE 709', 3, 'This course is an introduction to martingales in continuous time. Brownian motion: construction, basic properties, sample paths. Stochastic integration, Its rule, and applications, are discussed. The course is an introduction to stochastic differential equations and diffusion processes. Applications to financial economics: option pricing, and consumption/investment problems, are also covered. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 6),
(475, 'Advanced Simulation', 'INE 711', 3, 'This course covers an analysis of simulation data: input and output, validation and verification of system design, comparing alternative system configuration, simulation of complex systems, and case studies.', 6),
(476, 'Cost Engineering and Control', 'INE 721', 3, 'This course covers cost engineering for construction organizations, projects, and operations, it also covers construction financing, break-even, profit, and cash flow analyses, capital budgeting, equipment cost, and procurement decisions. Construction, financial accounting, cost accounting, cost control systems, and databases, as well as cost indices, parametric estimates, unit price proposals, measuring work, and settling claims are also covered. Pre-requisite: INE729 Project Contracting or consent of instructor. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 6),
(477, 'Infrastructure Management', 'INE 722', 3, 'This course covers the general methods of engineering systems management, and the different types of infrastructure. The course analyzes possible financing, and engineering, solutions and alternatives, and the overall management during the life cycle of the project. Pre-requisite: Consent of the instructor . Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 6),
(478, 'Quality Management Systems', 'INE 724', 3, 'This course is an introduction to quality management systems, ISO 9000, 14000, Total Quality Management, and the applications of QMS to the engineering, and management, of large projects, systems, and organizations. Pre-requisite: INE742 Quality Control I or Consent of the instructor. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 6),
(479, 'Project Scheduling', 'INE 727', 3, 'This course covers the basic critical path planning, and scheduling with arrow and precedence networks, introduction to resource leveling, and least cost scheduling, including time-cost tradeoff analysis and schedule control. Pre-requisite: Consent of the instructor. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 6),
(480, 'Project Contracting', 'INE 729', 3, 'This course covers the construction contracting for contractors, owners and engineers. The course also covers industry structure, the types of contracts and delivery systems of construction, planning, estimating, quantity takeoff and pricing, labor and equipment estimate, and the proposal preparation. Students use contract documents to prepare detailed estimates. Pre-requisite: Consent of the instructor.', 6),
(481, 'Lean Manufacturing', 'INE 741', 3, 'This is an introduction course for all engineering disciplines.  The course focuses on the concepts, principles, tools and techniques of Lean Manufacturing.  Examples from the manufacturing environment and administrative functions will be utilized to explain key concepts. Pre-requisite: Consent of the instructor Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 6),
(482, 'Quality Control I', 'INE 742', 3, 'This course covers the modeling process quality, inferences about process quality, statistical process control, types of control charts, acceptance sampling, and process capability analysis. Pre-requisite: Consent of the instructor.', 6),
(483, 'Reliability Evaluation of Engineering Systems', 'INE 743', 3, 'This course covers the concepts and basic background for evaluating the reliability of engineering systems. It covers network modeling and evaluation of simple and complex systems, cut-set method, tie-set method, multi-failure modes. Probability distributions in reliability evaluation and system reliability evaluation using probability distributions are discussed. Also, discrete and continuous Markov chains (reliability evaluation in repairable systems), frequency and duration techniques (concepts, applications to multistate problems, frequency balance approach) and the Monte Carlo simulation, are covered. Pre-requisite: Consent of the instructor . Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 6),
(484, 'Inventory Analysis', 'INE 744', 3, 'This course covers the continuous/periodic/ deterministic/stochastic inventory models, Materials Requirements Planning (MRP), just-in-time production systems, assembly systems, and flexible manufacturing distribution systems. Pre-requisite: Consent of the instructor.', 6),
(485, 'Facilities Planning and Layout', 'INE 745', 3, 'This course covers the process product and schedule design, determining activity relationships and space requirements, mathematical layout models and computerized layout algorithms, location and assignment models, storage spaces and warehouse design, design of non-manufacturing facilities, airport design and the evaluation of alternative design. Pre-requisite: Consent of the instructor. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 6),
(486, 'Materials Handling', 'INE 746', 3, 'This course covers the materials handling equipment; selection and design of material handling systems, simulation, and interface with facilities layout. Pre-requisite: Consent of the instructor. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 6),
(487, 'Machine Scheduling', 'INE 748', 3, 'This course covers the Basic Single Machine Problem (BSMP); flow shop scheduling with setup cost (TSP); vehicle routing. Pre-requisite: INE701 Linear Programming or consent of instructor.', 6),
(488, 'Transportation and Supply Chain Systems', 'INE 749', 3, 'This course covers the topics of supply chain characterization, site location, mode selection, distribution planning, vehicle routing, demand management, replenishment management, geographic information systems, and real-time control issues. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 6),
(489, 'Computer Aided Design/Computer Aided Manufacturing', 'INE 761', 3, 'This course covers the use of computer-aided design software packages, including systems for computer-aided drafting, solid modeling, finite element analysis, and computer-aided manufacturing, and design projects including the fabrication of physical prototypes generated with numerically controlled machines. Pre-requisite: Consent of the instructor . Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 6),
(490, 'Analysis of Automated Manufacturing Systems', 'INE 762', 3, 'This course covers the development of analytical stochastic models as the basis for understanding the performance, and the design/planning aspects of automated manufacturing systems. The course focuses on flow lines, job shops, and flexible manufacturing systems. Pre-requisite: Consent of the instructor . Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 6),
(491, 'Advanced Information Technology for Industrial & Manufacturing Engineering', 'INE 763', 3, 'This course covers advanced information technology concepts, tools, and techniques, for designing, and implementing, manufacturing systems. Pre-requisite: Consent of the instructor . Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 6),
(492, 'Times Series Control & Process Adjustment', 'INE 764', 3, 'This course covers the statistical analysis and design of process adjustment methods for quality improvement purposes. Topics include ARIMA time series models, autocorrelation and SPC, integration of SPC schemes and feedback control, identification and estimation of transfer function models, design and analysis of optimal stochastic controllers, PID and EWMA controllers, self-tuning and multivariate control. Pre-requisite: Consent of the instructor . Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 6),
(493, 'Intro to Systems Dynamics', 'INE 765', 3, 'This course introduces you to system dynamics modeling for the analysis of policy and strategy in an industrial context.  System dynamics allows us to abstract complex situations down to a level where we can visualize the long-term side effects of decisions, and systematically explore new strategies and policies that increase performance and reduce undesirable side effects.  We use role playing games, simulation models and case studies to develop sound principles of policy design for successful management of complex strategies. Pre-requisite: Consent of the instructor.', 6),
(494, 'Financial Engineering', 'INE 771', 3, 'This course is an introduction to financial models: mean-variance analysis, portfolio selection, separation theorems, capital asset pricing, arbitrage pricing, derivative security pricing, bond management, modeling, analysis, and computation of derivative securities. Applications of stochastic calculus and stochastic differential equations are covered, as well as numerical techniques: finite-difference, binomial method, and Monte Carlo simulation. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 6),
(495, 'Advanced Financial Engineering', 'INE 772', 3, 'This course is a review of basic mathematics, including renewal theory and stochastic calculus, Martingale approach to Black-Scholes formula, optimal stopping and American options, pricing of continuous and discrete exotic options, term structure models and pricing of bond options, jump diffusion models, and applications, including pricing of real and electricity options, and hedging of real options. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 6),
(496, 'Risk Assessment and Management', 'INE 773', 3, 'Risk assessment and management is the identification, analysis, and prioritization of risks; as well as the coordinated treatment of risk to prevent, minimize, monitor, and control the probability and/or impact of undesirable events and consequences. Areas covered include the principles and applications of risk assessment and management in the context of engineering management and systems engineering. This course is about the systematic approach to the management of risk as applied to engineering, operations, and management decisions Students will be prepared to function in a business environment, developing an awareness of the challenges, the tools, and the process of designing and implementing risk assessment and management strategies. Pre-requisite: Consent of the instructor.', 6),
(497, 'Engineering Economy II', 'INE 781', 3, 'This course covers the principles of investing, including investment strategies, investment in stocks and bonds. Project risk and uncertainty with focus on break-even analysis, decision trees, and sequential investment decisions, are discussed. Capital budgeting, including the choice of minimum attractive rate of return under capital rationing, evaluation of multiple investment alternatives and capital budgeting with limited budgets are covered, as well as the Monte Carlo Simulation.', 6),
(498, 'Project Course', 'INE 800', 3, 'This course is an applied design course. Design reviews and a final oral presentation with a written report are required. Pre-requisite: Consent of the instructor.', 6),
(499, 'Special Topic Courses', 'INE 801', 3, 'Topics of current interest selected by instructor. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 6),
(500, 'Special Topics in Optimization', 'INE 810', 3, 'This course covers topics of current interest in optimization, selected by instructor. Pre-requisite: Consent of the instructor. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 6),
(501, 'Topics: Optimal Resource Allocation Methods in industrial Systems', 'INE 810A', 3, 'This class is an introduction to resource allocation methods using systematic approaches based on mathematical models and cost-benefit analysis. These methods allow planners determine the optimal allocation that offers the most value and impact. Topics include traditional traffic models, in addition to novel intelligent dynamic models. These models can be used for efficient capacity planning and resource allocation in assembly systems consisting of dedicated and reconfigurable lines, in call centers, and in transportation. These methods can also be used by industrial support teams to make better staffing decisions while maintaining constraints.', 6),
(502, 'Special Topics in Infrastructure & Construction Management', 'INE 820', 3, 'This course covers topics of current interest in infrastructure, and construction management, selected by instructor. Pre-requisite: Consent of the instructor. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 6),
(503, 'Special Topics in Production Systems & Manufacturing', 'INE 840', 3, 'This course covers topics of current interest in production systems and manufacturing, selected by instructor. Pre-requisite: Consent of the instructor. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 6),
(504, 'Special Topics in Computational Modeling and Data Analytics', 'INE 860', 3, 'This course covers topics of current interest in computational modelling and data analytics, selected by the instructor. Pre-requisite: Consent of the instructor. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 6),
(505, 'Special Topics in Finance & Economics', 'INE 870', 3, 'This course covers topics of current interest in finance, and economics, selected by the instructor. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 6),
(506, 'Thesis', 'INE 899', 6, 'This research-based thesis course involves independent work performed by students, and leading to original contribution to knowledge. Topic selection is to be agreed upon in consultation with a Faculty Advisor. The student is limited to one thesis course per degree. Pre-requisite: Consent of the instructor, GNE798 Research Methods.', 6),
(507, 'Electromechanics', 'MCE 301', 3, 'This course discusses the analysis and design of electromechanical devices, with an emphasis on power and energy applications. Devices based upon mechanical forces generated by both electromagnetic fields and materials with electromechanical material properties will be considered.', 7),
(508, 'Mechatronics System Design I', 'MCE 410', 3, NULL, 7),
(509, 'Mechatronics System Design II', 'MCE 411', 3, NULL, 7),
(510, 'Professional Experience', 'MCE 498', 6, 'This course covers professional experience through training in the execution of real-life engineering projects.', 7),
(511, 'Biomechatronics', 'MCE 540', 3, 'Biomechatronics is the application of mechatronic engineering to human biology . This course will cover state-of-the-art in the field of Biomechatronics including assistive technologies, prosthetic devices, rehabilitation robots, and exoskeletons. Pre-requisites: (ELE401 Electronics I or MEE 391 Instrumentation & Measurements) and (ELE442 Control Systems or MEE445 Control Systems).', 7),
(512, 'Robotics and Intelligent Systems', 'MCE 550', 3, 'This course introduces the basic concepts of Robotics. The course discusses coordinate transformation, forward/inverse kinematics, linear/angular velocities, dynamics, equations of motion, and control strategies of serial industrial manipulators. The second part of the course introduces the Robot Operating System (ROS), an open-source framework for robotics applications. The covered topics include ROS architecture, packages, robot modeling, control, simulation, and visualization.', 7),
(513, 'Underactuated Robotics', 'MCE 551', 3, 'This course explores the nonlinear dynamics and control of underactuated mechanical systems, with a strong focus on computational approaches. Key topics include the complex behavior and nonlinear dynamics of robotic arms, optimal and robust control strategies, trajectory optimization, and motion planning. Real-world examples—from biology to applications like legged robots, soft manipulators, underwater vehicles, and aerial systems—will be used to illustrate the concepts. Pre-requisites: ELE442 or MEE445', 7),
(514, 'Computer Vision and Image Processing', 'MCE 552', 3, NULL, 7),
(515, 'Mobile Robotics', 'MCE 553', 3, NULL, 7),
(516, 'Capstone Design Project I', 'MCE 591', 3, 'This course covers selected engineering project using acquired technical knowledge, formal report, and presentation. Pre-requisites: Fifth-year standing and the consent of the instructor .', 7),
(517, 'Capstone Design Project II', 'MCE 592', 3, NULL, 7),
(518, 'Engineering Mechanics', 'GNE 212', 3, 'This course covers the review of vector algebra, forces systems resultants, equilibrium of particles and rigid bodies, internal forces, kinematics and kinetics of particles, systems of particles and rigid bodies.', 8),
(519, 'Professional Communication', 'GNE 301', 2, 'This course covers the English language proficiency, business letter writing, memo writing, report presentation and writing, and the use of presentation software.', 8),
(520, 'Engineering Ethics', 'GNE 303', 2, 'Introduce the fundamental canon of ethics in engineering practices and the associated professional liabilities. Reinforce the importance of safety as it relates to engineering design and implementation. The course involves teamwork researching a situation related to professional and ethical responsibilities.', 8),
(521, 'Probability and Statistics', 'GNE 331', 3, 'This course covers set theory, probability axioms, random variables (RV), continuous and discrete probability density functions, distributions, operations on RV’s, sampling distributions, confidence intervals (single variable), hypothesis testing (single variable), linear regression (single variable), and non-linear regression.', 8),
(522, 'Engineering Analysis I', 'GNE 333', 3, 'This course covers vector spaces, matrix algebra, solution of linear systems with numerical applications, eigenvalues and eigenvectors and applications, nonlinear equations and systems with numerical solutions and numerical integration. Pre-requisite: MTH201 Calculus III.', 8),
(523, 'Engineering Analysis II', 'GNE 334', 3, 'This course covers vector-integral calculus, Gauss-Stokes theorem, introduction to partial differential equations, Fourier series and Fourier integral, and numerical solution of ordinary and partial differential equations.', 8),
(524, 'Introduction to Sustainable Engineering', 'GNE 335', 3, 'Sustainable design and related topics such as environmental impact assessment methods, climate science, green building, life cycle analysis, and energy considerations. Principles of sustainability and their application to real world design and problem analysis within various fields of engineering.', 8),
(525, 'Introduction to Sustainable Engineering', 'GNE 335H', 3, 'Sustainable design and related topics such as environmental impact assessment methods, climate science, green building, life cycle analysis, and energy considerations. Principles of sustainability and their application to real world design and problem analysis within various fields of engineering.', 8),
(526, 'Trustworthy and Secure AI', 'GNE 336', 3, 'This course provides an introduction to validating, tuning, and assuring machine learning and neural network algorithms, among other categories of AI algorithms. The course targets AI assurance, bias mitigation, AI explainability, trustworthiness, data poisoning, and imbalance issues. Additionally, it will cover topics relevant to security and privacy within AI systems, including: detecting and mitigating cyber threats, cyber hygiene, protecting big data, and cyber policies. AI and cyber application examples are presented and studied, such as applications in the policy, medical, biological, water, and agricultural domains, amongst others.', 8),
(527, 'Trustworthy and Secure AI', 'GNE 336H', 3, 'This course provides an introduction to validating, tuning, and assuring machine learning and neural network algorithms, among other categories of AI algorithms. The course targets AI assurance, bias mitigation, AI explainability, trustworthiness, data poisoning, and imbalance issues. Additionally, it will cover topics relevant to security and privacy within AI systems, including: detecting and mitigating cyber threats, cyber hygiene, protecting big data, and cyber policies. AI and cyber application examples are presented and studied, such as applications in the policy, medical, biological, water, and agricultural domains, amongst others.', 8),
(528, 'Introduction to Virtual and Augmented Reality', 'GNE 337', 3, 'This course introduces students to the fundamentals, uses and benefits of virtual and augmented reality (VR/AR) technologies today, then teaches them the programming skills necessary to successfully create their own VR/AR apps such as UNITY.', 8),
(529, 'Introduction to Virtual and Augmented Reality', 'GNE 337H', 3, 'This course introduces students to the fundamentals, uses and benefits of virtual and augmented reality (VR/AR) technologies today, then teaches them the programming skills necessary to successfully create their own VR/AR apps such as UNITY.', 8),
(530, 'Engineering Entrepreneurship', 'GNE 340', 3, 'Concepts and practices of technology entrepreneurial thinking and entrepreneurship. Business planning and fundamental knowledge on establishing start-up companies. Innovative projects implementation in large companies for process improvement and optimum efficiency.', 8),
(531, 'Engineering Entrepreneurship', 'GNE 340H', 3, 'Concepts and practices of technology entrepreneurial thinking and entrepreneurship. Business planning and fundamental knowledge on establishing start-up companies. Innovative projects implementation in large companies for process improvement and optimum efficiency.', 8),
(532, 'Civic Engagement for Engineers', 'GNE 345', 3, 'This course aims to bridge the gap between engineering education and civic responsibility, highlighting the role of engineers in addressing societal challenges within the framework of the Sustainable Development Goals (SDGs). Through lectures, case studies, service learning, and project-based activities, students will learn how to apply their technical skills for the public good, engage with community stakeholders, and advocate for sustainable and equitable solutions to local and global issues.', 8),
(533, 'Civic Engagement for Engineers', 'GNE 345H', 3, 'This course aims to bridge the gap between engineering education and civic responsibility, highlighting the role of engineers in addressing societal challenges within the framework of the Sustainable Development Goals (SDGs). Through lectures, case studies, service learning, and project-based activities, students will learn how to apply their technical skills for the public good, engage with community stakeholders, and advocate for sustainable and equitable solutions to local and global issues.', 8),
(534, 'Introduction to Peace Engineering', 'GNE 425', 3, 'This course equips students with the tools and knowledge to address global challenges related to conflict, human security, climate change and sustainable development under the framework of the UN SDGs. Apply system-level science, technology, culture, and engineering principles to directly promote and support conditions for peace, to build resilient communities and contribute to conflict resolution through innovative solutions. Application of advanced engineering methods to reduce violent conflicts and foster social justice and economic well-being. Methods to analyze and forecast complex adaptive systems; develop trusted, secure, and interoperable data systems; create and integrate sensing technologies develop quantitative peace metric focusing on quality-of-life indicators; and enhance resilience engineering.', 8),
(535, 'Introduction to Peace Engineering', 'GNE 425H', 3, 'This course equips students with the tools and knowledge to address global challenges related to conflict, human security, climate change and sustainable development under the framework of the UN SDGs. Apply system-level science, technology, culture, and engineering principles to directly promote and support conditions for peace, to build resilient communities and contribute to conflict resolution through innovative solutions. Application of advanced engineering methods to reduce violent conflicts and foster social justice and economic well-being. Methods to analyze and forecast complex adaptive systems; develop trusted, secure, and interoperable data systems; create and integrate sensing technologies develop quantitative peace metric focusing on quality-of-life indicators; and enhance resilience engineering.', 8),
(536, 'Management Consulting for Engineers', 'GNE 430', 3, 'Business and strategy consulting: industry overview, soft skills and fit interviews in consulting, market sizing, storyline and recommendations development, market entry strategies, problem structuring and the pyramid principle, business financials and profitability analysis, mergers and acquisitions, corporate finance and valuation. Industry guest speakers across several topics.', 8),
(537, 'Management Consulting for Engineers', 'GNE 430H', 3, NULL, 8),
(538, 'Quality Systems and Excellence', 'GNE 435', 3, NULL, 8),
(539, 'Research Methods for Engineers', 'GNE 598', 3, NULL, 8),
(540, 'Research Methods', 'GNE 798', 3, 'Methods to improve and develop research skills which Includes: principles of scientific research, ethics, writing skills, methods for compiling scientific literature, identification of research questions and specific hypotheses, presentation of research results, writing research papers, proposal preparation, preparation of grant proposals, thesis and dissertation.', 8),
(541, 'Research Methods', 'GNE 798H', 3, 'Methods to improve and develop research skills which Includes: principles of scientific research, ethics, writing skills, methods for compiling scientific literature, identification of research questions and specific hypotheses, presentation of research results, writing research papers, proposal preparation, preparation of grant proposals, thesis and dissertation. Pre-requisite: Graduate standing', 8),
(542, 'Operations Management', 'ENM 601', 3, NULL, 9),
(543, 'Supply Chain Management', 'ENM 611', 3, NULL, 9),
(544, 'Discrete Event Simulation', 'ENM 612', 3, NULL, 9),
(545, 'Risk Assessment and Management', 'ENM 613', 3, NULL, 9),
(546, 'Decision Analysis', 'ENM 614', 3, NULL, 9),
(547, 'Calculus I', 'MTH 101', 3, 'The course is an intuitive approach to the techniques of calculus and analytic geometry. Topics include functions, graphs, trigonometric functions, rates of change, limits and continuity, the derivative function, the derivative as a rate of change, differentiation rules, derivatives of trigonometric functions, the chain rule, implicit differentiation, extreme values of a function, the Mean Value and Intermediate Value Theorems, curve sketching, optimization, linearization and differentials, L’Hopital’s rule, and an introduction to anti-derivatives.', 10),
(548, 'Calculus II', 'MTH 102', 3, 'This course covers integration. Topics include indefinite integrals, integral rules, integration by substitution, estimating with finite sums, Riemann sums and definite integrals, the Fundamental Theorem of Calculus, substitution in definite integrals, applications of integrals (areas between curves and volumes by slicing, volumes by cylindrical shells, and lengths of plane curves), transcendental functions (logarithms, exponential functions, inverse trigonometric functions), and some basic techniques of integration (integration by parts, and trigonometric integrals). In addition, the course covers differential equations and modeling (first order separable differential equations, linear first order differential equations), vectors in the plane and in space, as well as dot and cross products, lines and planes in space, and conics (ellipse, hyperbola, parabola).', 10),
(549, 'Calculus III', 'MTH 201', 3, 'This course covers hyperbolic functions, integration techniques and improper integrals. The course covers also infinite sequences and series: limits of sequences of numbers, bounded sequences, integral test for series, comparison tests, ratio and root tests, alternating series test, absolute and conditional convergence, power series, Taylor and MacLaurin series, and applications of power series. Polar functions, polar coordinates, and graphing of polar curves are also covered. In addition, topics from multivariable calculus are introduced: functions of several variables, partial derivatives, double integrals, applications to double integrals, and double integrals in polar form.', 10),
(550, 'Calculus IV', 'MTH 206', 3, 'This course covers the Fourier series, cylinders and quadric surfaces, vector-valued functions, arc length and the unit tangent vector, curvature and the unit normal vector, torsion and the binormal vector, partial derivatives and applications, the chain rule, directional derivatives, gradient vectors, tangent planes, linearization and differentials, extreme values and saddle points, Lagrange multipliers, triple integrals, triple integrals in cylindrical and spherical coordinates, integration in vector fields, line integrals, circulation and flux, potential functions and conservative fields, the Fundamental Theorem of Line Integrals, Green’s theorem, surface integrals, parametric surfaces, Stokes and divergence theorems.', 10),
(551, 'Discrete Structures I', 'MTH 207', 3, 'This course covers the foundations of discrete mathematics as they apply to computer science. The course is an introduction to propositional logic, logical connectives, truth tables, normal forms, validity, predicate logic, universal and existential quantification, and the limitations of predicate logic. Also, the following topics are covered: the number system, the Euclidean algorithm, proof techniques, mathematical induction, counting arguments, permutations and combinations, binomial coefficients, sets, functions, relations, matrices, and Boolean Algebra.', 10),
(552, 'Linear Algebra', 'MTH 301', 3, 'This is an introductory course in linear algebra where students are exposed for the first time to a balance of computation, theory, and applications. Topics include the systems of linear equations, vector spaces, linear dependence, bases, linear transformations, matrices, determinants, eigenvalues, and eigenvectors.', 10),
(553, 'Geometry', 'MTH 302', 3, 'This course presents an investigation of the axiomatic foundations of modern geometry. More specifically, Euclidean geometry is discussed in detail. Less emphasis is also placed on spherical, and/or hyperbolic geometries.', 10),
(554, 'Numerical Methods', 'MTH 303', 3, 'This course compares and contrasts various numerical analysis techniques, in addition to error definition, stability, the machine precision concepts, inexactness of computational approximations, the design, code, test, and debug programs that implement numerical methods, floating-point arithmetic, convergence, iterative solutions for finding roots (Newton’s Method), curve fitting, function approximation, numerical differentiation and integration, explicit and implicit methods, differential equations (Euler’s Method), and finite differences.', 10),
(555, 'Differential Equations', 'MTH 304', 3, 'This course covers the topics of first order ordinary differential equations and applications, linear higher order differential equations and applications, systems of linear differential equations, series solutions of differential equations and solutions, and Laplace transforms.', 10),
(556, 'Probability and Statistics', 'MTH 305', 3, 'This course covers essentially the distribution theory, estimation and tests of statistical hypotheses. More specifically, the topics of this course include: Random variables, discrete probability, conditional probability, independence, expectation, standard discrete and continuous distributions, regression and correlation, point and interval estimation. Also included are illustrations from various fields.', 10),
(557, 'Non-Linear Dynamics Chaos', 'MTH 306', 3, 'This course covers the topics of iteration, fixed and periodic points, graphical analysis of iteration, stable and unstable orbits, attracting and repelling periodic points, iterations of a quadratic family, Julia sets, Mandelbrot sets, fractals, and chaos.', 10),
(558, 'Discrete Structures II', 'MTH 307', 3, 'This course covers computational complexity and order analysis, recurrence relations and their solutions, graphs and trees, elementary computability, classes P and NP problems, NP-completeness (Cook’s theorem), NP-complete problems, reduction techniques, automata theory including deterministic and nondeterministic finite automata, equivalence of DFAs and NFAs, regular expressions, the pumping lemma for regular expressions, context-free grammars, Turing machines, nondeterministic Turing machines, sets and languages, uncomputable functions, the halting problem, implications of uncomputability, Chomsky hierarchy, and the Church-Turing thesis.', 10),
(559, 'Number Theory', 'MTH 308', 3, 'Topics covered are: The history of number representation systems, divisibility, greatest common divisor and prime factorization, linear Diophantine equations, congruences, and condition congruences.', 10),
(560, 'Graph Theory', 'MTH 309', 3, 'This course covers the fundamental concepts and methods of graph theory, and their applications in various areas of computing. Topics include graphs as models, representation of graphs, trees, distances, matching, connectivity, and flows in networks, graph colorings, Hamiltonian cycles, traveling salesman problem, and planarity.', 10),
(561, 'Abstract Algebra', 'MTH 311', 3, 'This course studies the algebra of sets, the definition and basic properties of groups, rings, and fields, and the divisibility theorems for integers and polynomials.', 10),
(562, 'Applied Linear Algebra', 'MTH 312', 3, 'An application-oriented and introductory course in linear algebra and its applications, with an emphasis on building computational skills in this area. Topics include systems of linear equations, matrices, Gaussian elimination, subspaces, bases, orthogonal vectors and projections. Matrix inverses, kernel and range, rank-nullity theorem. Determinants, eigenvalues and eigenvectors, Cramer’s rule, diagonalization and least squares. Also included are applications to curve fitting and Markov processes.', 10),
(563, 'Advanced Linear Algebra', 'MTH 400', 3, 'A thorough treatment of vector spaces and linear transformations over an arbitrary field; the Hamilton-Cayley Theorem, similarity, the Jordan Normal form, the dual of a linear transformation, direct sums, canonical forms, orthogonal and unitary transformations, normal matrices, and selected applications of linear algebra.', 10),
(564, 'Real Analysis I', 'MTH 401', 3, 'Topics covered include metric spaces, basic topics in topology, numerical sequences and series, continuity and uniform continuity of functions, differentiation, the mean-value theorem, Taylor’s theorem, and the Riemann-Stieljes integral.', 10),
(565, 'Theory of Interest', 'MTH 402', 3, 'This course is an intensive study of interest including the measurement of interest, the accumulation and discount of money, the present value of a future amount, the forces of interest and discount, equations of value, annuities (simple and complex), perpetuities, amortization and sinking funds, yield rates, bonds, and other securities, installment loans, depreciation, depletion and capitalized cost.', 10),
(566, 'Introduction to Complex Analysis', 'MTH 403', 3, 'Topics covered include the algebra of complex numbers, analytic functions, complex integration, Cauchy’s integral formula, singularities, residues, poles, Taylor and Laurent series.', 10),
(567, 'Actuarial Mathematics', 'MTH 407', 3, 'This course covers survival functions, complete and curtate future lifetime random variables, life tables, select and ultimate survival functions, valuation of insurance benefits, mathematics of life annuities, future loss random variables, premium calculations, policy values calculation, multiple state models and mathematics of pension plans and retirement benefits. Prerequistes: MTH305 and either MTH402 or FIN301', 10),
(568, 'Introduction to Topology', 'MTH 409', 3, 'Topics covered include general topological spaces, connectedness, and compactness, continuity, and product spaces.', 10),
(569, 'Real Analysis II', 'MTH 410', 3, 'This course will continue to cover the fundamentals of real analysis, concentrating on the Riemann integral, convergence of sequences and series of functions, functions of several variables, integration of differential forms, curl, divergence and Stoke’s theorem.', 10),
(570, 'Advanced Topics in Abstract Algebra', 'MTH 411', 3, 'This course is a continuation of Abstract Algebra and topics covered include ring theory, Galois Theory, unique factorization, Principal Ideal Domain, Unique Factorization Domain, and some Diophantine Equations.', 10),
(571, 'Topics in Mathematics', 'MTH 498', 3, 'This course covers selected topics in mathematics. It may be repeated for credit.', 10),
(572, 'Introduction to Physical Science', 'PHY 101', 4, 'This freshman-level course is an introduction to essential concepts of astronomy, physics, chemistry, and geology for non-science majors. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 11),
(573, 'Mechanics', 'PHY 111', 4, 'This course  deals with the mechanics and properties of matter, vectors and scalars, linear and circular  motion, dynamics of particles, work and power, energy and the conservation theorems, simple harmonic motion, gravitational forces and the properties of solids and fluids, and heat and thermodynamics.', 11),
(574, 'Electricity & Magnetism', 'PHY 201', 3, 'Coulomb’s law, Gauss’s Theorem, electrical field and potentials, Ampere’s law and magnetic fields, electric current and Ohm’s law, electromagnetic induction, alternating current, and electromagnetic wave.', 11),
(575, 'Electricity & Magnetism Lab', 'PHY 201B', 1, 'This course includes laboratory experiments associated with PHY201. Corequisite: PHY201 Electricity & Magnetism', 11),
(576, 'Classical Mechanics', 'PHY 202', 3, 'Newtonian mechanics of particles and rigid bodies (kinematics, forces, energy, momentum, angular momentum), harmonic oscillators, resonance, introduction to Lagrangian and Hamiltonian mechanics.', 11),
(577, 'Classical Mechanics Lab', 'PHY 203', 1, 'This course includes laboratory experiments associated with PHY202. Corequisite: PHY202 Classical Mechanics', 11),
(578, 'Classical Physics for Life Sciences', 'PHY 301', 3, 'This course is divided into three main parts: Newtonian Mechanics of a particle, Thermodynamics, and the study of fluids and solids. It begins with the study of Kinematics (geometrical analysis of the motion of a particle), continues with Newton’s Laws of Motion (kinetics), and then proceeds to the study of energy and momentum (work/energy theorem). The second part deals with temperature and heat, leading to the definition of entropy and to the laws of thermodynamics. The last part defines fluids and their density and pressure, leading to the Bernoulli equation, then defines solids and their stress and strain relationships with regards to Young’s modulus.', 11),
(579, 'Classical  Physics for Life Sciences Lab', 'PHY 302', 1, 'This course includes experiments covering linear momentum, such as: rotational motion, Newton’s Law of Motion, equilibrium and elasticity, work and energy, temperature, heat and thermal properties of matter, laws of thermodynamics, collision, pendulum, Boyle’s Law, fluid mechanics, coefficient of viscosity, and waves and optics.', 11),
(580, 'Mathematical Methods for Physicists', 'PHY 304', 3, 'This course covers the topics of first order ordinary differential equations and applications, linear higher order differential equations and applications, systems of linear differential equations, series solutions of differential equations and solutions, and Laplace transforms.', 11),
(581, 'Modern Physics for Life Sciences', 'PHY 305', 3, 'This course  covers  Coulomb’s Law of Electrostatics, the study of moving charges (electric current, DC or AC), electromagnetism, wave phenomena, light and optics, introduction to relativity, atomic energy levels, nuclear mass/energy relationship, and energy decay phenomena (radiation and nuclear physics). This course is designed in a way to show the application of some of the above fields in biological systems, and medicine, when possible.', 11),
(582, 'Modern Physics for Life Sciences Lab', 'PHY 306', 1, 'This course  includes experiments covering Coulomb’s Law, electric field for parallel plate, electric field for concentric cylinders, parallel plate capacitors, resistance, resistors in series and parallel, Wheatstone Bridge, basic oscilloscope operation, measurement of magnetic induction fields, solenoids and Faraday’s Law, charge to mass ratio of the electron, Ohm’s Law, and Plank’s Constant and Atomic Spectroscopy.', 11),
(583, 'Thermodynamics', 'PHY 307', 3, 'This course covers the basic principles of thermodynamics: Thermodynamic variables and equations of state. Basics concepts like heat, temperature, inner energy and enthalpy. Classical kinetic theory of gases, temperature, velocity and Maxwell’s velocity distribution. The ideal gas law and other simple equations of state for gases and other physical systems. The laws of thermodynamics. Macroscopic definition of and Boltzmann’s equation for entropy. Thermodynamics potentials. Maxwell’s and other thermodynamic relations. Phase transitions. Heat processes with technical applications such as heat engines and heat pumps. Heat conduction in different geometries. Radiation including the usage of Stefan-Boltzmann and Wien laws.', 11),
(584, 'Quantum Mechanics', 'PHY 308', 3, 'This course is an introduction to nonrelativistic quantum mechanics. It covers the Schrödinger equation in one and three dimensions, including spherical symmetric systems such as the three-dimensional oscillator and the hydrogen atom. Additionally, it explores the theory of angular momentum, the Zeeman effect, the Stark effect, spin-orbit coupling, time-dependent perturbation theory, and variational methods. The course will also provide an overview of the mathematical formalism necessary for understanding the principles of quantum mechanics.', 11),
(585, 'Advanced Physics Lab I', 'PHY 309', 1, 'This laboratory course covers advanced experiments in thermodynamics and optics.', 11),
(586, 'Organic Materials I', 'PHY 311', 3, 'This course is an introduction to the basic concepts of organic chemistry with an emphasis on the relation between structure and properties. It also includes synthesis, properties and reactions of aliphatic and aromatic hydrocarbons, alkyl halides and alcohols with an emphasis on mechanistic and stereo-chemical aspects of organic reactions.', 11),
(587, 'Organic Materials II', 'PHY 312', 3, 'This course covers in depth organic structure determination by spectroscopic methods, properties, reactions, and synthesis including alcohols, ethers, aldehydes, ketones, carboxylic acids and derivatives, amines, phenols, carbohydrates, and proteins. Emphasis will be placed on reaction mechanism and stereochemistry, as well as the design of multi-step synthesis.', 11),
(588, 'Introduction to Modern Physics', 'PHY 321', 3, 'An introduction to modern physics including relativity, black-body radiation, photoelectric effect, wave nature of particles, atomic and molecular spectra, models of the nucleus, nuclear reactions and elementary particles.', 11),
(589, 'Advanced Physics Lab II', 'PHY 322', 1, 'This laboratory course covers advanced experiments in modern and quantum physics.', 11),
(590, 'Intro. to Astrophysics', 'PHY 323', 3, 'Introduction to the universe, its origin and its evolution, The big bang theory, ancient and modern astronomy, stars, planets, galaxies, black holes, dark energy and dark matter, observational astronomy, and space missions.', 11),
(591, 'Nuclear Physics', 'PHY 324', 3, 'Nuclear forces, scattering and cross-section, radioactive decay law, nuclear models, nuclear decays, nuclear reactions, fission and fusion, nuclear reactors, radiation detectors.', 11),
(592, 'Particle Physics', 'PHY 325', 3, 'Historical overview, discovery of elementary particles, the Standard Model, Feynman diagrams, symmetries and parity, particle accelerators.', 11),
(593, 'Computational Physics', 'PHY 326', 3, 'This introductory course covers diverse computational techniques employed in various branches of physics research. It includes methods for analyzing functions, addressing linear and non-linear equations, eigenvalue problems, Fourier analysis, and differential equations. Applications in fluid dynamics, statistical physics, quantum mechanics, and other fields of physics.', 11),
(594, 'Solid State Physics', 'PHY 402', 3, 'This course covers crystal structure, lattice vibrations, the free electron model, energy bands in solids. Additionally, it provides an introduction to materials used in emerging technologies, including conducting, semiconducting, superconducting, inorganic and organic materials, nanomaterials. The course also covers the design, preparation, processing, and an array of characterization methods.', 11),
(595, 'Fluid Mechanics', 'PHY 404', 3, 'This course covers fluid statics, analysis of fluid motion using the continuity, momentum, and energy, relationship, and the introduction to viscous flow.', 11),
(596, 'Statistical Mechanics', 'PHY 405', 3, 'This course introduces the fundamental principles of statistical mechanics and their applications to a wide range of physical systems. It covers ensembles, partition functions, phase transitions, and critical phenomena, as well as the formulation of quantum statistics, ideal Bose and Fermi systems.', 11),
(597, 'Optics and Waves', 'PHY 413', 3, 'This course covers geometrical and wave optics: wave motion, electromagnetic theory, photons, light, superposition, polarization, interference, diffraction, lasers.', 11),
(598, 'Introduction to Nanotechnology', 'PHY 424', 3, 'This course covers nanofabrication technologies (“bottom up” to “top down” technologies), the interdisciplinary nature of nanotechnology and nanoscience (including areas of chemistry, material science, physics, and molecular biology), examples of nanoscience phenomena (the crossover from bulk to quantum mechanical properties), and applications (from integrated circuits, quantum computing, MEMS, and bioengineering).', 11),
(599, 'Medical Imaging and Instrumentation', 'PHY 450', 3, 'This course is an introduction to key physical principles applied to medical imaging and instrumentation.  Topics covered will include imaging principles (intensity, resolution, contrast), x-ray physics, computed tomography, radioactivity, radioisotope production, positron emission tomography, radiation exposure principles, ultrasound physics, and magnetic resonance imaging.', 11),
(600, 'Topics in Physics', 'PHY 480', 3, 'Contemporary topics in physics selected based on the faculty expertise and students interests and needs.', 11),
(601, 'Capstone Project', 'PHY 499P', 3, 'This course is designed to build foundational skills in research ethics and methodologies tailored to physics. Students will explore how to perform an in-depth literature review on a selected physics topic, gain insights into contemporary research trends, and effectively integrate their findings into a structured review paper.', 11),
(602, 'Undergraduate Research', 'PHY 499R', 3, 'This course is designed to teach research methods. It includes work on a short research topic, and the presentation of the findings in a research paper.', 11),
(603, 'Preparatory Chemistry', 'CHM 005', 0, NULL, 12),
(604, 'General Chemistry', 'CHM 101', 4, 'This freshman-level course is an introductory course that includes theoretical and applied basic concepts of atomic structure, chemical bonding, chemical reactions, stoichiometry, gases, aqueous solution, chemical kinetics, and chemical equilibrium.', 12),
(605, 'Essentials of Chemistry', 'CHM 200', 3, 'This is a one semester course for health science students that introduces basic concepts of general, organic and biochemistry, and basic nuclear chemistry. The course includes basic: stoichiometric chemical calculations, bonding concepts, solution chemistry, acid-base and redox reactions, basic nuclear reactions, properties of organic compounds, structure and reactivity of hydrocarbons, alcohols, ethers, carbonyls, carboxylic acids, amines, carbohydrates, amino acids, lipids, enzymes and biochemical energy.', 12),
(606, 'Chemical Principles', 'CHM 201', 3, 'This course covers the principles and theories of atomic structure, chemical bonding, stoichiometry, mass spectrometry, properties of gases, basic thermodynamics, kinetic molecular theory, solids and liquids, solutions, and ionic and chemical equilibrium.', 12),
(607, 'Qualitative Analysis', 'CHM 203', 1, 'This course is an introduction to experimental chemistry including stoichiometric application, properties of gases, colligative properties of solution and detailed qualitative chemical analyses of various matrices.', 12),
(608, 'Quantitative Analysis', 'CHM 204', 2, 'This course is an introduction to experimental chemistry that involves gravimetric, volumetric, and spectrophotometric methods, and techniques used in quantitative chemical analysis.', 12),
(609, 'Fundamentals of Chemistry', 'CHM 205', 3, 'This course incorporates the principles of stoichiometry, properties of gases, chemical equilibrium, aqueous equilibrium (acids and bases, buffers, titrations), thermodynamics (energy, enthalpy, thermochemistry, spontaneity, entropy, free energy), atomic structure, chemical bonding, rates of reactions, liquids and solutions.', 12),
(610, 'Essentials of Chemistry for Computer Science', 'CHM 209', 3, 'The course includes basic: stoichiometric chemical calculations, bonding concepts, solution chemistry, acid-base and redox reactions, properties of organic compounds, structure and reactivity of hydrocarbons, alcohols, ethers, carbonyls, carboxylic acids, amines, carbohydrates, amino acids, lipids enzymes and biochemical energy. The course includes a short laboratory component that complements the theoretical course material.', 12),
(611, 'Qualitative and Quantitative Analysis Lab', 'CHM 300', 2, 'This laboratory course offers a comprehensive introduction to experimental chemistry, encompassing both qualitative and quantitative analysis. Through hands-on experiments, students will explore stoichiometry, gas laws, and colligative properties while mastering gravimetric, volumetric, and spectrophotometric techniques. The course emphasizes essential laboratory skills, including precision, data interpretation, and scientific communication.', 12),
(612, 'Analytical Chemistry', 'CHM 301', 3, 'This course introduces the fundamental principles and practices of analytical chemistry. A focus is on the development of a quantitative understanding of homogeneous and heterogeneous equilibria phenomena. Equilibria include acid-base of simple and complex systems, complex ions, solubility products, and the effect of electrolytes. In addition, the course covers fundamentals and applications of titration, electrochemistry, and chemical kinetics.', 12),
(613, 'Instrumental Analysis', 'CHM 302', 3, 'This course is an introduction to a variety of analytical methods of analysis covering theoretical concepts of instrumentation as well as research and hands-on applications. Topics include emission and absorption spectroscopy, nuclear magnetic resonance spectroscopy, electrochemistry, various mass spectrometry and chromatography techniques.', 12),
(614, 'Basic Organic Chemistry', 'CHM 310', 3, 'This course is for pre-health professionals. Material covered includes electronic structure and bonding, acid-base reactions in organic chemistry, nomenclature, physical properties, reactions and reactivity of alkanes, alkenes, alkynes, alkyl halides, alcohols, amines, ethers, epoxides, and aromatic compounds. The central role of carbonyl compounds, their reactions, and the chemistry of biomolecules are also covered.', 12),
(615, 'Organic Chemistry I', 'CHM 311', 3, 'This course is an introduction to the basic concepts of organic chemistry with an emphasis on the relation between structure and properties. It also includes nomenclature, properties and reactions of aliphatic hydrocarbons, alkyl halides and alcohols with an emphasis on mechanistic and stereochemical aspects of organic reactions and their application in organic synthesis. The concept of aromaticity is introduced. Perquisite: CHM201 Chemical Principles or CHM205 Fundamentals of Chemistry', 12),
(616, 'Organic Chemistry II', 'CHM 312', 3, 'This course  covers in depth organic structure determination by spectroscopic methods, nomenclature, properties, reactions, and synthesis of aromatic hydrocarbons, organometallics, alcohols, thiols, ethers, sulfides, carbonyl compounds (aldehydes, ketones, carboxylic acids and derivatives), and amines. Emphasis is placed on reaction mechanisms, stereochemistry, and the design of multi-step synthesis.', 12),
(617, 'Organic Chemistry I Lab', 'CHM 313', 1, 'This laboratory course is designed to provide students with the basic skills for conducting organic reactions. The following techniques are learned: melting point determination, boiling  point determination, simple, fractional and steam distillation, gravity and vacuum filtration, drying solids and liquids, extraction, evaporation, reflux, recrystallization, thin-layer and column chromatography, and polarimetry. Students are introduced to ChemDraw software and molecular modeling.', 12),
(618, 'Organic Chemistry II Lab', 'CHM 314', 1, 'This course is an advanced organic chemistry lab course that utilizes the techniques learned in CHM313, in order to synthesize and study the properties and reactivities of functional groups. Experiments conducted include nitration of aromatic compounds, Suzuki coupling, aldol condensation, Diels-Alder reaction and Friedel Crafts acylation. The synthesis of dyes and natural products are also investigated in addition to conducting quantum chemical calculations using Gaussian software.', 12),
(619, 'Physical Chemistry I', 'CHM 330', 3, 'This course covers the basic principles of chemical thermodynamics and chemical dynamics including heat, work and energy, the three laws of thermodynamics and their application to chemical systems and thermodynamic solutions, physical transformations and phase diagrams of pure substances, simple mixtures, kinetic theory of gases, rate law, mechanism, Bodenstein approximation, fast reactions, photochemistry, and reaction rate theories. Note: MTH304 Differential Equations is strongly recommended.', 12),
(620, 'Physical Chemistry II', 'CHM 332', 3, 'This is a course that covers quantum theory, postulates, particle in a box, Schrödinger equation of hydrogen, harmonic oscillator and vibrational spectroscopy, rigid rotor and rotational spectroscopy, H+2 and H2, atomic and molecular orbitals, approximation methods, many electron atoms, atomic and molecular spectra, and applications in spectroscopy. Note: MTH304 Differential Equations is strongly recommended.', 12),
(621, 'Physical Chemistry Laboratory', 'CHM 334', 1, 'This is a laboratory course that covers principles and experimental techniques in thermochemistry, kinetics, quantum mechanics, atomic and molecular spectroscopy and electrochemistry.', 12),
(622, 'Environmental Chemistry', 'CHM 340', 3, 'This course is an application of chemical principles, chemical equilibrium, and reaction kinetics to the study of environmental science and engineering. It includes natural processes and pollution problems related to air, water, and soil such as air pollution, the ozone hole, indoor air quality, climate change, water quality and pollution, water purification, solid wastes, and toxic metals. Solutions to reduce air pollution such as designing cyclones, and catalytic converters will be discussed.', 12),
(623, 'Drug Discovery and Medicinal Chemistry I', 'CHM 350', 3, 'This course provides undergraduates with an insight into the complex process and importance of early drug design and discovery. The course content covers general aspects, methods, and principles within drug design and discovery.', 12),
(624, 'Drug Discovery Laboratory', 'CHM 351', 1, 'This laboratory course deals with the introduction of different phases in drug development and testing including computational drug design, synthesis and identification of organic and inorganic active substances, analytical methods creation and validation.', 12),
(625, 'Method Validation and Quality Assurance', 'CHM 352', 3, 'This course covers the principles of analytical method development and validation; quality assurance and control; ISO requirements; sampling, preparations and storage of samples and standard solutions; physiochemical characterization; statistical analysis; good laboratory practice (GLP) requirement; and validation, verification, and documentation of analytical testing methods and procedure. In this course, students will learn about method development and assessment for analysis of chemicals, organic compounds, drugs, pharmaceuticals, and biopharmaceuticals.', 12),
(626, 'Chemistry of Materials', 'CHM 402', 3, 'This course is an introduction to the materials of emerging technologies including metals, alloys, and inter-metallics, ceramics, polymers, composites, nanomaterials and biomaterials, semiconductors, superconductors and dielectrics, as well as the design, preparation, processing, and array of characterization methods for material performance.', 12),
(627, 'Polymer Science', 'CHM 403', 3, 'This course is an introduction to polymer science involving classification of polymers, preparative methods of polymerization, characterization, mechanical properties, fabrication techniques, thermodynamics and kinetics of polymers, commercial importance and applications. Pre-requisite: CHM312 Organic Chemistry II Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 12),
(628, 'Forensic Chemistry', 'CHM 404', 3, 'This course is a general overview of the fundamental principles, methods, and instrumentation involved in the forensic analysis of physical evidence such as hair, fiber, bodily fluids, glass, paint, soil, fingerprints, and documents.', 12),
(629, 'Forensic Chemistry Lab', 'CHM 404B', 2, 'This lab is a direct application of the forensic principles that are covered in the course. Physical and biological evidence will be subjected to various extraction methods, spot and color tests, followed by instrumental analysis for the purposes of qualitative and quantitative analysis. Pre- or Corequisite: CHM404 Forensic Chemistry Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 12),
(630, 'Statistical Mechanics', 'CHM 405', 3, 'This course involves probability laws and distribution, statistical mechanics, postulates, fundamental equations, statistical mechanics calculations, Bose-Einstein statistics, transition state theory, as well as isotope effect from a statistical perspective. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 12),
(631, 'Industrial Chemistry of Organic and Inorganic Compounds', 'CHM 406', 3, 'This course explores the fundamental principles and applications of industrial chemistry, with a focus on both organic and inorganic compounds. Students will gain an understanding of the synthesis, properties, and reactions of various chemical substances used in industry. This course is essential for students pursuing careers in industrial chemistry, materials science, and related fields, as it provides a solid foundation in chemistry that drives modern industry.', 12),
(632, 'Synthesis and Identification of Organic Compounds', 'CHM 412', 2, 'This course is an experimental chemistry course that explores synthetic transformations, separation and identification of organic compounds by wet chemical techniques, spectroscopic tools, elemental analysis, and NMR. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 12),
(633, 'Inorganic Chemistry I', 'CHM 421', 3, 'This course outlines the fundamental concepts in Inorganic Chemistry with emphasis on coordination compounds. Topics include the atomic theory, chemical bonding and molecular orbital theory, group theory and symmetry, acids and bases in Inorganic Chemistry.', 12),
(634, 'Inorganic Chemistry II', 'CHM 422', 3, 'This course is an application to modern Inorganic Chemistry. Topics include physical methods in Inorganic Chemistry, metallic elements in the periodic table, structure of ionic solids or crystals, reactions of coordination compounds, organometallics reactions, catalysis and spectroscopy.', 12),
(635, 'Synthesis and Identification of Inorganic Compounds', 'CHM 423', 2, 'This course is an experimental chemistry course that explores a wide variety of synthetic methodologies and characterization techniques of inorganic compounds such as main group, transition metals and organometallics. Several characterization techniques are used to analyze the synthesized products such as conventional spectroscopy, magnetic susceptibility and thermal analysis. The special laboratory skills of air-free manipulation of chemicals will also be introduced.', 12),
(636, 'Synthesis and Characterization of Nanomaterials', 'CHM 424', 2, 'This course is an experimental course that explores a wide variety of synthetic and characterization techniques for nanomaterials using advanced instrumental techniques such as thermogravimetric analysis, atomic absorption spectroscopy, scanning electron microscopy, X-ray diffraction, and nuclear magnetic resonance spectroscopy. Pre- or Corequisites: CHM402 Chemistry of Materials, CHM330 Physical Chemistry I', 12),
(637, 'Computational Chemistry', 'CHM 425', 2, 'This course is a hands-on computer laboratory course that covers the practical aspects of computational chemistry as applied in chemical structure and chemical dynamics calculations. Methods cover molecular mechanics, semi-empirical, ab-initio , molecular dynamics, and statistical mechanics. Calculations range from optimizations (ground, excited, and transition state) and conformational searching to structure-property relationships.', 12),
(638, 'Inorganic Chemistry Lab', 'CHM 427', 1, 'This course is an experimental chemistry course that explores a wide variety of synthetic methodologies and characterization techniques of inorganic compounds such as main group, transition metals and organometallics. Several characterization techniques are used to analyze the synthesized products such as conventional spectroscopy, magnetic susceptibility and thermal analysis. The special laboratory skills of air-free manipulation of chemicals will also be introduced.', 12),
(639, 'Air Pollution Control', 'CHM 430', 3, 'Analysis of air pollution sources and methods for controlling emissions, with a focus on transportation-related air pollution. The fundamental chemical and physical processes governing pollutant behavior, and a quantitative overview of the characterization and control of air pollution problems. Analysis of key elements of the air pollution system.', 12),
(640, 'Environmental Chemistry Lab', 'CHM 432', 1, 'This laboratory course will explore sampling and measurement techniques, which are important for determining environmental pollutants. Students will collect air, water, soil, and consumer samples to determine the levels of targeted pollutants.', 12),
(641, 'Drug Discovery and Medicinal Chemistry II', 'CHM 450', 3, 'This course provides undergraduates with an insight into the complex process and importance of early drug design and discovery. The course content exemplifies important and recent medicinal chemistry developments for a number of specific targets and diseases.', 12),
(642, 'Chemical Pharmacology', 'CHM 451', 3, 'This course highlights the relation between chemical composition and physiological action by taking into consideration the ADME process. Such an understanding facilitates the reverse engineering of therapeutic agents as part of Drug Design. The course content also covers pharmacodynamics and pharmacokinetics.', 12),
(643, 'Topics in Chemistry', 'CHM 488', 3, NULL, 12),
(644, 'Special Topics in Industrial Chemistry', 'CHM 488C', 3, 'This course explores advanced and contemporary issues in industrial chemistry.', 12),
(645, 'Special Topics in Environmental Chemistry', 'CHM 488D', 3, NULL, 12),
(646, 'Special Topics in Medicinal Chemistry', 'CHM 488E', 3, 'This course explores advanced and contemporary issues in medicinal chemistry.', 12),
(647, 'Capstone Project', 'CHM 499P', 3, 'This course is designed to teach research methods. It includes work on acquiring soft skills, scientific writing, researching on a scientific topic and the presentation of a research paper.', 12),
(648, 'Undergraduate Research', 'CHM 499R', 3, 'This course is designed for students to undergo undergraduate research. It includes work on a short, novel research topic, and the presentation of the findings in a research paper.', 12),
(649, 'Introduction to Biological Science', 'BIO 101', 4, 'This course covers general biology for freshman Liberal Arts students. It is a simplified presentation of basic biological concepts, with emphasis on human biology.', 13),
(650, 'Basic Biology', 'BIO 200', 3, 'This course introduces basic principles of human biology. It focuses on cell and tissue structure and function, classification, evolution, modern genetics and molecular biology. It also provides brief coverage of organs and systems.', 13),
(651, 'General Biology I', 'BIO 201', 3, 'This course is an introductory, yet comprehensive, study of the chemical, cellular, and the tissue organization of life, evolution, the transfer of energy through living systems, the expression of genetic information, essential microbiology principles, as well as a discussion of the major characteristics of viruses, bacteria, fungi, protists, and plants.', 13),
(652, 'General Biology I Lab', 'BIO 201B', 1, 'This course introduces the major characteristics of living organism. The overall objective is to allow students to obtain a hands-on experience focusing on the chemical, cellular, and the tissue organization of life, evolution, the transfer of energy through living systems, the expression of genetic information, essential microbiology principles, as well as of the major characteristics of viruses, bacteria, fungi, protists, and plants.', 13),
(653, 'General Biology II', 'BIO 202', 3, 'This course is an introduction to the classification of the Animal Kingdom, and an in depth discussion of animals, with particular emphasis on the study, and a comparison, of structures and functions, and of tissues and the organ system, all within the context of diversity of life as shaped by evolution.', 13),
(654, 'General Biology II Lab', 'BIO 202B', 1, 'This course introduces the major characteristics of animals. The overall objective is to allow students to obtain a hands-on experience focusing on the classification of the Animal Kingdom with particular emphasis on the study, and a comparison, of structures and functions, and of tissues and the organ systems, all within the context of diversity of life as shaped by evolution.', 13),
(655, 'Introduction to Ecology', 'BIO 203', 3, 'This course introduces the organization of individual organisms into populations, communities, and ecosystems. It focuses on the interactions between living organisms and their physical environment. Concepts such as diversity, competition, natural selection, adaptation, climate changes, migration, extinction and deforestation are covered. Additionally the course tackles concepts of environmental microbiology in relation to pollution, remediation and recycling of liquid and solid wastes. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 13),
(656, 'Basic Biology for Computer Science', 'BIO 209', 3, 'This course introduces basic principles of biology. It focuses on cell and tissue structure and function, classification, evolution, ecology, and modern genetics. It also provides a brief coverage of organs and systems in relation to disease and nutrition. The course includes a short laboratory component that complements the theoretical course material.', 13),
(657, 'Microbiology, a Human Perspective', 'BIO 222', 3, 'This course is designed to provide nursing and nutrition students with a foundation in basic microbiology with emphasis on infectious diseases and interaction of microorganisms with humans. The student will gain an understanding of the various characteristics of microorganisms in general and the specific characteristics of pathogenic bacteria, viruses and fungi. It will enable the students to learn how to avoid the spread of infectious microorganisms in the hospital environment. Topics include the different aspects of epidemiology, control of pathogens, disease transmission, nosocomial infections, host resistance, immunity, and sample collection.', 13),
(658, 'Human Anatomy and Physiology', 'BIO 260', 3, 'This course covers the structure and function of the human body and the mechanisms involved for maintaining homeostasis within it. Body systems, including the muscular, skeletal, cardiovascular, respiratory, digestive, nervous, excretory, integumentary, endocrine and reproductive systems will be surveyed with an emphasis on the relation between structure and function.', 13),
(659, 'Human Anatomy and Physiology Lab', 'BIO 261', 1, 'This course includes experimental activities designed to enhance students’ ability to both visualize anatomical structures, and to understand most physiological topics. All laboratory sessions focus on humans.', 13),
(660, 'Microbiology', 'BIO 311', 3, 'This is a course intended for the Biology Major, and covers principles of microbiology, and the impact these organisms have on humans and the environment. Topics include the history of microbiology, a survey of the different types of microorganisms, prokaryotic cell structure and function, microbial nutrition and growth, control of microorganisms and microbial metabolism, physiology, genetics, interaction of microorganisms with other forms of life, role of microorganisms in disease, immunity, and other selected applied areas.', 13),
(661, 'Microbiology Lab', 'BIO 312', 1, 'This course explores the ubiquitous nature of microbes. The overall objective is to allow students to obtain a hands-on experience in many of the microbiological techniques routinely employed, with emphasis on the methodological, and clinical, relevance of the procedures. Students connect theoretical lectures to the practical applications in medicine, environment, and other related fields.', 13),
(662, 'Genetics', 'BIO 321', 3, 'This course is a study of the factors governing heredity, and variation, in plants and animals, on the classical and modern levels, with an emphasis on molecular and microbial genetics, and an introduction to recombinant DNA technology.', 13),
(663, 'Genetics Lab', 'BIO 322', 1, 'This course is a hands-on laboratory course that familiarizes students with principles of classical Mendelian genetics and modern molecular genetics with an emphasis on recombinant DNA technology through an in depth analysis of the genetics and workings of basic model organisms such as Saccharomyces cerevisiae , Sordaria fimicola, Zea mays and Escherichia coli .', 13),
(664, 'Ecology', 'BIO 331', 4, 'This course covers the study of the relationships between living organisms and their environment. Major concepts related to the structure, function, organization, and regulation, at various levels (population community, ecosystems, and biomes), are covered theoretically and via laboratory work and field trips.', 13),
(665, 'Plant Physiology', 'BIO 341', 3, 'This course covers the study of fundamental processes underlying survival, growth development, and normal functions of plants, with special emphasis on photosynthesis, respiration, mineral nutrition, water absorption and transpiration, translocation of solutes, hormonal control, and development.', 13),
(666, 'Anatomy and Physiology', 'BIO 343', 3, 'This course entails an anatomical, and physiological approach to the study of the cardiovascular, nervous, endocrine, muscular, respiratory, excretory, digestive, and reproductive systems, with emphasis on homeostasis.', 13),
(667, 'Anatomy and Physiology Lab', 'BIO 344', 1, 'This course includes experimental activities designed to enhance students’ ability to both visualize anatomical structures, and to understand most physiological topics. All laboratory sessions focus on human and other higher vertebrates. Pre-requisites: BIO201 General Biology I and BIO202 General Biology II', 13),
(668, 'Cell & Molecular Biology', 'BIO 345', 3, 'This course is an integration of the approaches of cytology, biochemistry, genetics, and physiology, to provide a comprehensive understanding of the operation of cells as units of structure and function in living organisms.', 13),
(669, 'Cell & Molecular Biology Lab', 'BIO 345B', 1, 'This course focuses on cellular and molecular techniques. The overall objective is to allow students to obtain a hands-on experience integrating cytology, biochemistry, genetics, and physiology techniques, to provide a comprehensive understanding of the operation of cells as units of structure and function in living organisms.', 13),
(670, 'Developmental Biology', 'BIO 401', 3, 'This course covers basic human and animal developmental processes. It deals with gametogenesis, fertilization, cleavage, gastrulation, neural and germ layer formation. It explores the details of early human embryo development and human birth defects. The course also deals with the most recent Assisted Reproductive Technologies (ART) as well as emphasizes and updates current Stem Cell research knowledge and its application in treatment of diseases and gene therapy.', 13),
(671, 'Developmental Biology', 'BIO 401H', 3, 'This course covers basic human and animal developmental processes. It deals with gametogenesis, fertilization, cleavage, gastrulation, neural and germ layer formation. It explores the details of early human embryo development and human birth defects. The course also deals with the most recent Assisted Reproductive Technologies (ART) as well as emphasizes and updates current Stem Cell research knowledge and its application in treatment of diseases and gene therapy.', 13),
(672, 'Biotechnology', 'BIO 410', 3, 'This course examines all the biological principles underlying current biotechnology in the fields of human genetics, and genetic engineering. Methods of basic scientific research, the impact of technology on society, and the ethical problems in human genetics, will be explored. Topics include gene structure, function, expression, and manipulation in both the prokaryotes and eukaryotes principles of recombinant DNA technology, microbial biotechnology, animal and plant biotechnology, medical biotechnology, DNA profiling, forensics, and the regulation of biotechnology and patenting.', 13),
(673, 'Virology and Immunology', 'BIO 420', 3, 'This course provides an introduction to the immune response, the cells and tissues of the lymphoid system, lymphocyte activation and specificity, humoral and cell-mediated immunity, the concept of immunity to diseases, and immunodeficiency, and AIDS autoimmune diseases and transplantation. It examines the interactions between pathogens and host defense mechanisms (innate and specific immunity), as well as the problems in pathogenesis. The student will be also exposed to the principles of virology, with topics covering the fundamental properties of viruses, including their structure, replication, molecular biology, pathogenesis, epidemiology, and the medical importance of major virus groups and their interaction with host cells.', 13),
(674, 'Population Genetics', 'BIO 430', 3, 'This course covers the most commonly used statistical methods for the study of allele frequency distribution as well as association and linkage analysis. It also introduces the four main evolutionary processes: mutation, natural selection, gene flow and genetic drift.', 13),
(675, 'Functional Genomics', 'BIO 435', 3, 'One part of the course is related to the functional properties of genes while the second part is related to how we can annotate genes and extract their functional properties from online resources. This course also includes the analysis of gene expression data (microarray, single cell, etc.).', 13),
(676, 'Special Topics in Biology', 'BIO 488', 3, 'This course covers specialized contemporary topics of current interest to senior undergraduates in the Biology program.', 13),
(677, 'Special Topics in Biology', 'BIO 488H', 3, 'This course covers specialized contemporary topics of current interest to senior undergraduates in the Biology program.', 13),
(678, 'Seminar in Biology', 'BIO 489', 1, 'This is a combined lecture/seminar course designed for seniors. Students enrolled in this course will give an oral presentation to the faculty and students of the Department about contemporary research topics.', 13),
(679, 'Senior Study', 'BIO 499P', 3, 'This course is designed to teach research ethics and methods, including how to conduct: a survey of literature on a problem in biology, and its presentation in a paper.', 13),
(680, 'Senior Study', 'BIO 499PH', 3, 'This course is designed to teach research ethics and methods, including how to conduct : a survey of literature on a problem in biology, and its presentation in a paper.', 13),
(681, 'Senior Study', 'BIO 499R', 3, 'This course is designed to teach research ethics and methods, including how to conduct: a survey of literature on a problem in biology, a laboratory investigation of some phase of it, and its presentation in a paper.', 13),
(682, 'Senior Study', 'BIO 499RH', 3, 'This course is designed to teach research ethics and methods, including how to conduct: a survey of literature on a problem in biology, a laboratory investigation of some phase of it, and its presentation in a paper.', 13),
(683, 'Graduate Seminar', 'BIO 600', 0, 'This course introduces students to the art of preparing and presenting research work. Student and faculty will present either their own research, or research articles of interest. Course will also include presentations from invited researchers and faculty members. Students should register in this course during all their semesters.', 13),
(684, 'Research Tools', 'BIO 605', 3, 'This course combines both theoretical knowledge and hands on laboratory training in cell biology, genomics, and proteomics. Students will perform experiments that will allow them to gain necessary research skills, and improve analytical thinking required in a master’s thesis project. In addition, this course provides students with an overview of basic laboratory etiquette, laboratory safety, research ethics, and necessary concepts in biostatistics.', 13),
(685, 'Molecular Biology and Genomics', 'BIO 611', 3, 'The course emphasizes principles and information, which form the contemporary basis for molecular biology and genomics. The course will cover DNA/RNA structure and function, DNA recombination and replication, regulation of gene expression and operon function, eukaryotic molecular genetics, recombinant DNA technology, and epigenetics. This course will also provide a broad overview of the theoretical skills concerning new large-scale and technology-driven approaches within genomics, such as High-throughput Sequencing and sequence analysis.', 13),
(686, 'Cell Biology', 'BIO 613', 3, 'The course will discuss the latest discoveries in the fields of Cell biology. It is also an integration of the fields of signaling biochemistry and genetics to provide a comprehensive understanding of the operation of cells as units of structure and function in living organisms. This is done through a historical overview of the research advances leading to the knowledge we have today about protein structure and function and interaction in the cell as well as the impact of its physiology and pathology on disease.', 13),
(687, 'Model Organism Genetics', 'BIO 621', 3, 'Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 13),
(688, 'Human Genetics and epidemiology', 'BIO 622', 3, NULL, 13),
(689, 'Quantitative imaging of cells', 'BIO 623', 3, 'Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 13),
(690, 'Proteomics', 'BIO 625', 3, 'This course provides an in depth introduction to using proteome sequences to unravel problems of interest to biomedical researchers. Sessions include a combination of technical lectures, scientific testimonials, and hands-on solving problems, where students will be able to put the theoretical concepts into practice. Topics covered include MALDI mass spectrometry, NMR and X ray crystallography.', 13),
(691, 'Tumor Markers and Targeted Cancer Therapeutics', 'BIO 631', 3, NULL, 13),
(692, 'Advances in Epigenetics and Therapeutics', 'BIO 632', 3, NULL, 13),
(693, 'Signaling in Cancer Malignancies and Metastasis', 'BIO 633', 3, 'Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 13),
(694, 'Diagnostic Microbiology and Immunology', 'BIO 645', 3, 'Biochemical, serological and automated methods used in the laboratory diagnosis of infectious diseases. The laboratory part of the course allows for better understanding through application. Titles include: monoclonal antibody production, detection of fluorescent antibodies, Enzyme-linked immunosorbent assay, radioimmunoassay, gas-liquid chromatography, high performance liquid chromatography, mass spectrometry, time-resolved immunofluorescence, nucleic acid probes in clinical diagnostic, and diagnostic virology and parasitology. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 13),
(695, 'Microbial Pathogenesis', 'BIO 646', 3, NULL, 13),
(696, 'Fungal Genetics and Pathogenicity', 'BIO 648', 3, NULL, 13),
(697, 'Bioinformatics Tools and Applications', 'BIO 660', 3, 'Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 13),
(698, 'Special Topics in Biology', 'BIO 681', 3, 'This course covers the selected, recent, and contemporary, advances in the various applied fields of the biological sciences, and affiliated disciplines.', 13),
(699, 'Thesis', 'BIO 699', 6, 'This course entails producing an original and extensive research project under the supervision of an advisor, and defended before a committee. It may include field research, be qualitative or quantitative, descriptive or experimental, and in the form of a case study, document analysis, or action research.', 13),
(700, 'Computer Applications', 'CSC 201', 1, 'The course ensures that all students will acquire basic, internationally recognized computer proficiency skills. Teaching and learning will be hands-on, in a computer-equipped classroom. The topics include the concepts of information technology, using the computer and its operating system and managing files, word processing, spreadsheets, and presentation software.', 14),
(701, 'Introduction to Object-Oriented Programming', 'CSC 243', 3, 'This course introduces the fundamental concepts, and techniques, of programming and problem solving. Topics include the introduction to computer systems, fundamental programming constructs, program readability, simple I/O, conditional constructs, iterative control structures, structured decomposition, method call and parameter passing, 1-D and 2-D arrays, basic searching and sorting algorithms, introduction to the object-oriented paradigm, simple testing and debugging.', 14),
(702, 'Introduction to Object-Oriented Programming Lab', 'CSC 243B', 1, 'Hands-on project and assignment-based course where students will gain strong practical and technical skills in programming.  Course emphasizes the use of shell, tools, utilities, and programming environments. Corequisite: CSC243 Introduction to Object-Oriented Programming.', 14),
(703, 'Objects and Data Abstraction', 'CSC 245', 3, 'This course presents further techniques of object-oriented programming and problem solving, with emphasis on abstraction and data structures. Topics include object oriented concepts, such as, composition, inheritance, polymorphism, information hiding, and interfaces; basic program design and correctness, such as, abstract data types, preconditions and post conditions, assertions and loop invariants, testing, basic exception handling, and the application of algorithm design techniques. The course also covers basic algorithmic analysis, time and space tradeoffs in algorithms, big-O notation; fundamental data structures and applications, such as, collections, single- and double-linked structures, stacks, queues, and trees; performance issues for data structures; recursion, more sorting algorithms.', 14),
(704, 'Objects and Data Abstraction  Lab', 'CSC 245B', 1, 'Hands-on project and assignment-based course where students will gain strong practical and technical skills in programming.  Course emphasizes the use of shell, tools, utilities, programming environments, user interfaces, software versioning, and GUI applications. Corequisite: CSC245 Objects and Data Abstraction', 14),
(705, 'Algorithms and Data Structures', 'CSC 310', 3, 'This course presents the fundamental computing algorithms and data structures, with emphasis on design and analysis. Topics include the asymptotic analysis of upper and average complexity bounds, recurrence relations, disjoint sets, hashing and hash tables, heaps, priority queues, and graphs (representation, traversals and applications, shortest-path algorithms, network flows, topological sort). The course also covers sorting algorithms and performance analysis, which include mergesort, quicksort and heapsort. The course details the fundamental algorithmic strategies (divide-and-conquer approach, greedy, dynamic programming, and backtracking), and includes a brief introduction to NP-completeness theory.', 14),
(706, 'Algorithms and Data Structures Lab', 'CSC 310B', 1, 'Hands-on project and assignment-based course where students will gain strong practical and technical skills in the implementation of efficient algorithms. The course includes software design, continuous integration and continuous delivery, version control and source code management, deployment to repository managers, control issues and routines, developer testing, defensive programming, debugging, self-documenting code, refactoring, and design patterns. Corequisite: CSC 310 Algorithms and Data Structures', 14),
(707, 'Competitive Programming', 'CSC 317', 3, 'This course introduces techniques and skills needed to solve algorithmic problems in a competitive problem-solving environment.  Topics include techniques for attacking and solving challenging computational problems, functional programming, essential mathematics-related problems, data structures, greedy and dynamic programming, combinatorial games, graph algorithms, network flow problems, computational geometry, and string algorithms.', 14),
(708, 'Computer Organization', 'CSC 320', 3, 'Overview of the history of the digital computer, representation of numeric data, introduction to digital logic, logic expressions and Boolean functions, and logic functions minimization as well as processor and system performance, and Amdahl’s law. The course provides an introduction to reconfigurable logic and special-purpose processors, instruction set architecture, and microarchitecture. Processor structures, instruction sequencing, flow-of control, subroutine call and return mechanism, structure of machine-level programs, low level architectural support for high-level languages are also covered as well as memory hierarchy, latency and throughput, cache memories: operating principles, replacement policies, multilevel cache, and cache coherency. Finally, the course covers register-transfer language to describe internal operations in a computer, instruction pipelining and instruction-level parallelism (ILP), an overview of superscalar architectures, and multicore and multithreaded pro', 14),
(709, 'Computer Organization Lab', 'CSC 322', 1, 'Students gain experience with computer organization techniques by designing and implementing actual circuits using a high-level language, Verilog HDL and FPGAs. The course culminates in the design and simulation of a complete pipelined CPU. Corequisite: CSC 320 Computer Organization .', 14),
(710, 'Operating Systems', 'CSC 326', 3, 'This course introduces the fundamentals of operating systems design and implementation. Topics include C language and shell programming, operating system components, dynamic memory allocation, text processing, memory management, virtual memory, files, pipes, processes, process scheduling, process synchronization (mutual exclusion, deadlocks), and threads.  The course includes hands-on labs using Linux that introduce students to pthreads, operating systems administration and basic shell manipulation, mounting systems, maintaining services, tracking and debugging processes and services, and process resources usage.', 14),
(711, 'Database Management Systems', 'CSC 375', 3, 'This course is an introduction to the fundamental concepts and relational and NoSQL database systems. Topics include database architecture, row and columnar databases, data independence, data modeling, physical and relational database design, functional dependency, normal forms, query languages, query optimization, database security, and transactions at the SQL level.  The course also covers NoSQL databases and their core concepts (key-value, column family, document, and graph) in addition to an exploration of how MongoDB implements these core concepts.', 14),
(712, 'Theory of Computation', 'CSC 380', 3, 'This course covers elementary computability, the classes P and NP, NP-completeness (Cook’s theorem), problem-reduction techniques, automata theory including deterministic and nondeterministic finite automata, equivalence of DFAs and NFAs, regular expressions, the pumping lemma for regular expressions, context-free grammars, Turing machines, nondeterministic Turing machines, sets and languages, the halting problem, Chomsky hierarchy, and the Church-Turing thesis.', 14),
(713, 'Computer Networks', 'CSC 430', 3, 'This course introduces the structure, implementation, and theoretical underpinnings of computer networks. Topics include network structure, performance metrics, circuit switching and packet switching, the Internet protocol stack, physical layer networking concepts, data link layer technologies and protocols, internetworking and routing, transport layer protocols, application layer protocols, client-server programming, and emerging technologies.', 14),
(714, 'Mobile Applications', 'CSC 431', 3, 'This course covers writing cross-platform mobile web apps using a variety of frameworks that can be converted into native apps for Android, iOS, and Windows Phone 7 devices.  Topics include designing user interfaces for mobile devices, accessing mobile device API’s (such as accelerometer, GPS, compass, or camera), and power management issues.', 14),
(715, 'Introduction to Cloud Computing', 'CSC 433', 3, 'This course provides an introduction into the technologies behind cloud computing by exposing students to the leading cloud computing paradigms and programming interfaces (e.g., EC2, Lambda), services.  The course discusses various types of design patterns including basic, distributed, and cloud design patterns.  The course includes a hands-on component that underlying technological concepts such as virtualization (Dockers and Kubernetes), scalability, fault tolerance, and security.', 14),
(716, 'Computer Security', 'CSC 435', 3, 'This course is an introduction to computer security including formal models of security, security goals and fundamentals (confidentiality, integrity, availability, etc.), introduction to risk assessment and management, security standards in government and industry, cryptography, authentication, security operations, software attacks including malicious code and buffer overflows, social engineering, and injection attacks.', 14),
(717, 'Networks Security', 'CSC 437', 3, 'This course is an introduction to networks security including denial-of-service, capabilities, network intrusion detection/prevention, worms, forensics, scanning, traffic analysis, legal issues, web attacks, anonymity, wireless and networked devices, honeypots, scams, underground economy, attacker infrastructure, and ethics. Hands-on experience is part of the class.', 14),
(718, 'Blockchain Systems', 'CSC 438', 3, 'The course covers the technical aspects of cryptocurrencies, blockchain technologies, and distributed consensus. Students will learn how these systems work and how to engineer secure software that interacts with a blockchain system like Bitcoin and Ethereum.', 14),
(719, 'Introduction to Computer Forensics', 'CSC 439', 3, 'This course provides a general introduction to the concepts, theories, principles, and practice of digital forensics. Topics include types of digital forensics, forensic acquisition and validation, forensic methodologies, file systems and file examination, expert testimony, legal issues, and challenges for the field.', 14),
(720, 'Web Programming', 'CSC 443', 3, 'This course introduces advanced concepts in web programming and focuses on the development of dynamic web pages that incorporate both client-side and server-side programming. Topics include web programming using JavaScript, NodeJS, React, design patterns, relational and non-relational databases, security, web services, cloud deployment, and scalability and performance Issues. Hands-on experience is part of the course.', 14),
(721, 'Systems Programming', 'CSC 446', 3, 'This course provides students with a basic understanding of the issues involved in writing system programs such as compilers, linkers, loaders and debuggers. Topics include POSIX System-Call API, system processes, system I/O and inter-process communication, system permissions, files, directories, signals, threads, sockets, terminal, etc. Students are introduced to the C programming language. The course includes the design of a small computer system with focus on process, memory virtualization, and concurrency.', 14),
(722, 'Parallel Programming for Multicore and Cluster Systems', 'CSC 447', 3, 'This course provides an introduction to parallel programming with a focus on multicore architectures and many programming techniques. Topics include relevant architectural trends, techniques, and aspects of multicores and GPU programming including writing parallel programs and extracting data parallelism using vectors and SIMD, thread-level parallelism, task-based parallelism, efficient synchronization, program profiling and performance tuning.', 14),
(723, 'Artificial Intelligence', 'CSC 460', 3, 'This course is a survey of knowledge-based artificial intelligence. Topics include the history, definition, philosophical foundations, search techniques, game playing, propositional logic, predicate logic, knowledge representation, planning, and agents.', 14),
(724, 'Introduction to Machine Learning', 'CSC 461', 3, 'This course provides an overview of theoretical and application aspects of machine learning. Topics include supervised and unsupervised learning including generative/discriminative learning, parametric/non-parametric learning, neural networks, support vector machines, clustering, dimensionality reduction, and kernel methods. The course also covers learning theory, reinforcement learning, adaptive control. An applied approach will be used, where students get hands-on exposure to ML techniques through the use of state-of-the-art machine learning software frameworks.', 14),
(725, 'Fundamentals of Deep Learning', 'CSC 462', 3, 'Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 14),
(726, 'Introduction to Data Science', 'CSC 463', 3, 'This course is an introduction to data science and analytics including a basic understanding of how to manipulate, analyze and visualize large data in a distributed computing environment. The course covers the ETL pipeline including data wrangling and cleaning, data query and retrieval, data analysis and interpretation, data visualization, statistical inference and prediction, decision-making and proper results reporting.  Special emphasis will be placed on ethical questions and implications in the use of AI and data.', 14),
(727, 'Deep Learning for Natural Language Processing', 'CSC 464', 3, 'Understanding complex language has wide applications in web search, advertisement, customer service, automatic translation, chat bot engineering, etc. Many different machine learning techniques are at the heart of natural language processing (NLP) applications. Recently, Deep Learning (DL) approaches have obtained very high performance across many different NLP tasks. This course covers such approaches. Students will build their own neural network model and apply it to a large scale NLP problem. From the model side, the following topics will be covered:  word vector representations, window-based neural networks, recurrent neural networks, long-short-term-memory models, recursive neural networks, convolutional neural networks. From the NLP side, the course covers the following topics: syntax parsing, vector space modeling, dimensionality reduction, speech tagging, text classification, and sentiment analysis. Note: This course has not been thought since Fall 2023  and will not be taught ', 14),
(728, 'Software Engineering', 'CSC 490', 3, 'This course presents the techniques for developing reliable, and cost-effective, medium-to-large-scale with an emphasis on agile development methods appropriate for rapidly-moving projects. Basic software development infrastructure; requirements elicitation and tracking; prototyping; basic project management; basic UML; introduction to software architecture; design patterns; testing.', 14),
(729, 'Professional Experience', 'CSC 491', 1, 'Students participate in a project-based Professional Experience in the junior year. The department requires evidence of project-based work and relevant professional experience.', 14),
(730, 'Topics in Computer Science', 'CSC 498', 3, 'This course covers selected topics in computer science. This course may be repeated for credits.', 14),
(731, 'Introduction to Computer Innovation', 'CSC 597', 3, 'This course introduces elements of technology venture creation including opportunity identification and validation, ideation, customer discovery, market analysis, minimum viable product development, business models, intellectual property, and capital raises.', 14),
(732, 'Undergraduate Research in Computer Science', 'CSC 598', 3, 'This course has a limited enrollment and open only to qualified students starting in their fourth semester. Students work on individual projects as suggested each term. Students may also approach faculty to devise their own projects.', 14),
(733, 'Capstone Project', 'CSC 599', 3, 'This course is a stand-alone project course that allows students to integrate the many concepts, and skills, they have learned.  The course requires the design, implementation, and oral presentation of a complete significant team project.  The course is offered in a classroom environment with a capacity of 18 students.', 14),
(734, 'Graduate Seminar', 'CSC 600', 0, 'This is a mandatory zero credit course that all graduate students have to pass. Students are required to attend a certain number of seminars/theses defences and make at least one presentation other than their own thesis defence and proposal. All work has to be completed within two years of registering the course.', 14),
(735, 'Design and Analysis of Algorithms', 'CSC 611', 3, 'This course addresses both the fundamentals and the research boundaries of algorithm design and analysis. Covered topics include: complexity of algorithms, divide and conquer techniques, greedy methods, dynamic programming, recursive backtracking, amortized analysis, graph algorithms, polynomial-time problem reduction, NP-completeness, approximation algorithms and a selected advanced topic.', 14),
(736, 'Foundations of Computer Science', 'CSC 612', 3, 'This course covers finite automata and regular expressions, context-free grammars, pushdown automata, properties of regular and context-free languages, Turing machines, undecidability, computational complexity, Cook-Levin theorem and the polynomial time hierarchy.', 14),
(737, 'Computational Methods in Biology', 'CSC 613', 3, 'This course covers the use of computer science methods and algorithms to solve problems related to biology, biochemistry, and/or medicine. Topics include fundamental algorithmic methods in computational molecular biology, and bioinformatics, such as protein sequence analysis, pair wise and multiple alignment, fragment assembly, probabilistic models, phylogenetic analysis, folding and structure prediction, biological structures (protein structures, RNA structures, etc…), and information that could be derived from them. The course is research-based. Students are required to read papers and articles, compare different techniques used to solve problems, and suggest alternatives.', 14),
(738, 'Meta-Heuristics', 'CSC 614', 3, 'This course covers widely used meta-heuristic optimization techniques in computing, such as simulated annealing, Tabu search, genetic algorithms, ant algorithms and de-randomized evolution strategies. Serial as well as parallel algorithms will be studied. Students will develop application projects from a wide range of application areas. The advantages and disadvantages of meta-heuristic search methods are discussed.', 14),
(739, 'Machine Learning', 'CSC 615', 3, 'This course provides an overview of popular algorithms in machine learning. Topics include supervised learning, linear and polynomial regression, classification algorithms, gradient descent, unsupervised learning, instance-based learning, neural networks, and genetic algorithms and boosting. The course requires some knowledge of artificial intelligence, and good programming skills. The theoretical aspects of the algorithms will be studied, and assignments will be given to test their applicability.', 14),
(740, 'Cryptography and Data Security', 'CSC 616', 3, 'This course is an advanced survey of modern topics of theory, foundations, and applications of modern cryptography. One-way functions, pseudo-randomness, encryption, authentication, public-key cryptosystems, and notions of security, are covered. The course also covers zero-knowledge proofs, multiparty cryptographic protocols, and practical applications.', 14),
(741, 'Fundamentals of Data Science', 'CSC 617', 3, NULL, 14),
(742, 'Fundamentals of Computer Networks', 'CSC 618', 3, NULL, 14),
(743, 'Fundamentals of Database Systems', 'CSC 619', 3, NULL, 14),
(744, 'Transaction Processing Systems', 'CSC 621', 3, 'This course covers the theoretical foundations underlying commitment protocols that form the basis of transaction processing techniques. Transaction Processing systems have lots of moving parts, client-side forms, web servers, mid-tier application servers, and back-end databases. Although these components are distributed across multiple processes, these processes share state, and use specialized communication protocols and synchronization techniques. This course explains how these systems are constructed. Topics include the transaction abstraction, application servers, transactional communications, persistent queuing and workflow, software fault tolerance, concurrency control algorithms, database recovery algorithms, distributed transactions, two-phase commit, and data replication.', 14),
(745, 'Distributed Systems', 'CSC 622', 3, 'This course is an introduction to distributed systems, distributed system models, network architecture and protocols, inter-process communication, client-server models, group communication, TCP sockets, remote procedure calls, distributed objects and remote invocation, distributed file systems, file service architecture, name services, directory and discovery services, distributed synchronization and coordination, and distributed multimedia systems.', 14),
(746, 'Knowledge-Based Systems', 'CSC 623', 3, 'This course covers knowledge discovery and representation. Among the techniques used to represent knowledge, it focuses on trees, semantic networks, frames and production rules.  The course covers search techniques and inferences used in knowledge based systems. It also covers topics such as theorem proving and expert systems.', 14),
(747, 'Data Mining', 'CSC 624', 3, 'This course covers the fundamental techniques and applications for mining large data sets. Topics include techniques and algorithms for classification, clustering, association rules, scalable and distributed data mining algorithms, and applications.', 14),
(748, 'Discrete Event Simulation', 'CSC 625', 3, 'This course covers the model construction and simulation applied to problems taken from such diverse fields as economics, social science, communication networks and computer systems. It includes programming in simulation languages such as SIMSCRIPT, SIMULA or GPSS. Students will be able to analyze a problem, and determine whether simulation techniques could be used to solve it. Students are also required to develop a viable model of the system program, and to execute a computer simulation of the model, and finally analyze the results of the simulation.', 14),
(749, 'Blockchain Systems', 'CSC 630', 3, NULL, 14),
(750, 'High Performance Computer Architecture', 'CSC 631', 3, 'This course covers the concepts and examples of advanced computer systems, especially scalable parallel computers. Topics include memory-system design, advanced processor design techniques, pipelined, vector, shared memory, and distributed-memory computer systems, parallel algorithms, and software and architectural issues for efficient parallel processing.', 14),
(751, 'ULSI Testing', 'CSC 632', 3, 'This course covers the problems of testing of Ultra Large Scale Integrated Circuits (ULSI), the design of circuits for testability, the design of built-in self-testing circuits, and the use of the IEEE Boundary Scan Standards. Topics include an introduction to the testing process, fault modeling and detection, logic and fault simulation, testability measures, test generation for combinational circuits, test generation for sequential circuits, design for testability, built-in self-test, delay testing, current testing, ATPG-based logic synthesis, system test and core-based design, and testing a system-on-a-chip.', 14),
(752, 'Embedded Systems', 'CSC 633', 3, 'This course introduces methodologies for the systematic design of embedded systems including processors, DSP, memory, and software. Topics include hardware and software aspects of embedded processor architectures, along with operating system fundamentals, system specification, architecture modeling, component partitioning, estimation metrics, hardware and software co-design and diagnostics, system interfacing basics, communication strategies, sensors and actuators, and mobile and wireless technology. Projects use pre-designed hardware and software components. The course covers design case studies in wireless, multimedia, and/or networking domains.', 14),
(753, 'Network Programming', 'CSC 634', 3, 'This course covers methods and tools used for network programming and simulation. Covered topics include operating system support for network protocols, inter-process communication tools (such as pipes, sockets and remote procedure calls), design of client and server sides of network protocols, simulation tools for network design and analysis, in addition to experimental research topics in the area of computer networks.', 14),
(754, 'Internet of Things (IoT)', 'CSC 635', 3, NULL, 14),
(755, 'Networks Security', 'CSC 636', 3, 'This course covers theory and practice of network security. Topics include static packet filter, stateful firewall, proxy firewall, IDS, VPN Device, DMZs and screened subnets, networks defence components, internal network security, host hardening, configuration management, audit, human factors, and security policies. The course also covers cryptographic protocols, privacy, anonymity and various case studies.', 14),
(756, 'Pervasive Computing and Wireless Networking', 'CSC 637', 3, 'This course covers the fundamental principles of pervasive and mobile computing in addition to the design of state-of-the-art wireless technologies and wireless networking protocols. Topics include pervasive and mobile computing fundamentals and challenges; pervasive and mobile computing services and application areas; mobile device technologies; mobile device platforms; mobile device application development challenges; mobile device programming; wireless network architectures; WLAN, WiMAX, GSM, UMTS, and Bluetooth wireless technologies; Mobile IP; Wireless TCP; pervasive computing and wireless networking research trends.', 14),
(757, 'Computer Forensics', 'CSC 638', 3, NULL, 14),
(758, 'Parallel Algorithms and Programming', 'CSC 647', 3, 'This course covers techniques and methods for parallel algorithms and programming. Topics include: models of parallel machines and programs, efficiency and complexity of parallel algorithms, paradigms of parallel programming and corresponding extensions to sequential programming languages, advanced parallel algorithms and programming on clusters and multi-core systems. The course is research oriented. In addition to lectures and exams, students are required to work on selected advanced topics for an experimental course project.', 14),
(759, 'Advanced Computer Graphics', 'CSC 650', 3, 'The course covers major aspects of digital image generation: geometric modeling, computer animation, and rendering.  It also covers recent advanced topics such as subdivision surfaces, real-time global illumination, and physically based animation.', 14),
(760, 'Artificial Intelligence: Principles and Techniques', 'CSC 660', 3, 'The course covers computational approaches for modeling uncertainty and solving decision problems. Topics include search techniques, constraint satisfaction problems, game playing (including alpha-beta pruning), propositional logic, predicate logic, knowledge representation, planning, probabilistic reasoning, Bayesian networks and case-based reasoning. It also covers advanced topics in Artificial Intelligence such as natural language processing and robotics.', 14),
(761, 'Fundamentals of Deep Learning', 'CSC 662', 3, NULL, 14),
(762, 'Advanced Machine Learning', 'CSC 664', 3, NULL, 14),
(763, 'Artificial Intelligence Methods for Natural Language Processing', 'CSC 666', 3, NULL, 14),
(764, 'Data Visualization', 'CSC 668', 3, NULL, 14),
(765, 'Advanced Topics in Computer Science', 'CSC 688', 3, 'This course covers selected topics in Computer Science. The course may be repeated for credits more than once.', 14),
(766, 'Search-Based Software Engineering', 'CSC 690', 3, 'Search-Based Software Engineering formulates Software Engineering problems as search problems and applies meta-heuristics to tackle these problems. The course introduces the most popular meta-heuristic techniques used in the domain such as Hill Climbing, Simulated Annealing, Genetic Algorithms and Ant Colony Optimization. This is focuses on how these methods can be used to solve problems from different stages of the software engineering lifecycle. Examples of such problems are stress testing real-time systems, predicting software quality, test case generation and software project scheduling.', 14),
(767, 'Advanced Software Engineering', 'CSC 691', 3, 'The course covers techniques for the construction of reliable and cost-effective large-scale software. Topics include process models, unified process, Unified Modelling Language requirements analysis and specification, design methods and principles, agile software development.', 14),
(768, 'Software Quality Assurance and Testing', 'CSC 694', 3, 'The course covers the capability maturity model; process assessment, modeling, and improvement techniques; maintenance; quality; metrics; theoretical and practical aspects of testing software, including classical and object oriented testing methods at various testing levels.', 14),
(769, 'Human-Computer Interaction', 'CSC 696', 3, 'This course provides a comprehensive introduction to the principles and techniques of human-computer interaction and user interface design, with a focus on highly usable software, user and task modeling, user centered design, evaluation of user interfaces, detailed discussion of many user interface design issues such as the use of coding techniques (color, icons, sound, etc.), screen and web page design, feedback and error messages, internationalization of user interfaces, response time, accessibility to the disabled, user interfaces for different types of devices, voice user interfaces, etc. This course requires students to implement user interfaces.', 14),
(770, 'Managing Software Development', 'CSC 697', 3, 'Students will acquire knowledge and skills for developing a software project management plan; leading a project team; estimating time, cost, and effort; conducting risk analysis;  and configuration management. as well as the legal issues involved in liability, warranty, patentability and copyright.', 14),
(771, 'Project', 'CSC 698', 3, 'This course entails an independent development, and documentation of substantial software, or computer-based system, using recent or significant techniques and/or tools.', 14),
(772, 'Thesis', 'CSC 699', 6, 'This course entails an independent investigation of a topic of interest, in a basic or applied computer science area, with the objective of producing original results.', 14),
(773, 'Remedial English', 'ENG 009', 0, 'The course introduces academic reading and writing skills needed in various disciplines. It focuses on exposing students to general academic vocabulary, grammatical structures, and other rhetorical tools in context for a sufficient understanding of various academic texts. The course also introduces students to basic tasks required in academic learning, and integrates oral/aural skills. The cut-off scores for ACT Writing, EEE, IBT, IELTS, SAT Evidence-Based Reading & Writing, and SAT Writing can be found here .', 15),
(774, 'Academic English I', 'ENG 101', 3, 'Academic English I (ENG101) is a course that builds upon the skills taught in ENG009 and emphasizes academic writing and research skills. The course allows students to examine elements of academic texts and produce written syntheses in which they demonstrate proper use of formal academic language, referencing, and grammar.', 15),
(775, 'Academic English II', 'ENG 102', 3, 'This course is designed to develop advanced reading and writing skills in an academic context.  Emphasis is on the analytical reading of different text types required in the disciplines as well writing a review of relevant literature on an assigned theme.', 15),
(776, 'Advanced Academic English', 'ENG 202', 3, 'This course is designed to develop advanced reading and writing skills in an academic context.  Emphasis is on the analytical reading of different text types required in the disciplines as well writing a review of relevant literature on an assigned theme.', 15),
(777, 'Advanced Academic English', 'ENG 202H', 3, 'This course is designed to develop advanced reading and writing skills in an academic context.  Emphasis is on the analytical reading of different text types required in the disciplines as well writing a review of relevant literature on an assigned theme.', 15),
(778, 'English Literature I', 'ENG 211', 3, 'This course offers a critical study of literature from the ancient world through the Renaissance with emphasis on the European and Mediterranean traditions. Readings chosen emphasize themes that continue to resonate in the present.', 15),
(779, 'English Literature II', 'ENG 212', 3, 'This course offers a critical study of Western literature from the seventeenth century through the twentieth century as a continuation of ENG211. Readings chosen emphasize themes that continue to resonate in the present.', 15),
(780, 'English Literature II', 'ENG 212H', 3, 'This course offers a critical study of Western literature from the seventeenth century through the twentieth century as a continuation of ENG211. Readings chosen emphasize themes that continue to resonate in the present.', 15),
(781, 'Introduction to Language', 'ENG 213', 3, 'A survey of the theoretical bases of language study emphasizing theories of language origins and developments. Topics include semantics, syntax, pragmatics, writing systems, dialects, phonology, and the contrast between communication, true language, and artificial language.', 15),
(782, 'Introduction to Literature', 'ENG 216', 3, 'Through analysis of primary and secondary texts, this course provides a survey of the methodology and practice of literary study; of basic notions of literary theory; and a survey of the historical development of English literature.', 15),
(783, 'Introduction to Literature', 'ENG 216H', 3, 'Through analysis of primary and secondary texts, this course provides a survey of the methodology and practice of literary study; of basic notions of literary theory; and a survey of the historical development of English literature.', 15),
(784, 'Language and Change: Past, Present, and Future', 'ENG 281', 3, 'This course provides an overview of the history and development of the English language from its origins to the present. It examines the effects of historical, socio-political, and cultural phenomena on linguistic change. The course also discusses the notion of a ‘standard’ English, the richness and diversity of English dialects and varieties, and the role of English today as a global language.', 15),
(785, 'Language and the Media', 'ENG 282', 3, 'This course examines the structure and use of language in various print and digital media texts such as newspaper articles, blogs, e-mails, Instant Messages (IMs), and Facebook posts. The course emphasizes the importance of studying media discourse in its socio-political and historical context and investigates how the language used in the media affects our knowledge and interpretation of phenomena and events.', 15),
(786, 'Language and Gender', 'ENG 283', 3, 'This course explores the relationship between language and gender by focusing on both the nature as well as function of gender differences in communication. It examines the differences in linguistic behavior between men and women pertaining to issues as politeness and status. It also tackles the question of sexism in language by shedding light on issues like gender stereotyping, its socio-cultural effects, and attempts to counter it socio-culturally and linguistically.', 15),
(787, 'Food and Travel Writing', 'ENG 301', 3, 'The course introduces the history of food writing, different genres of food criticism, and trains students to write restaurant criticism, food criticism for different media. The course also studies different forms of travel writing from the past and present and offers practical training in several genres of travel writing, in structuring narratives, drawing on experience, developing specialized language the right angle, inventive ideas, descriptions, imagery, and humor. Students will explore new formats such as blogging, multimedia and photography.', 15),
(788, 'Literary Linguistics', 'ENG 303', 3, 'Offers a systematic linguistic approach to literary analysis, utilizing such linguistic tools as transitivity and voice, deixis, tense, modality, etc. It aims at consolidating students’ knowledge of both literature and linguistics by drawing on their interconnectedness.', 15),
(789, 'Semantics and Pragmatics', 'ENG 308', 3, 'Introduces theoretical and empirical approaches to linguistic semantics and pragmatics in relation to language encoded meanings as part of language syntactic structures and language choice in social interaction/ context.', 15),
(790, 'Renaissance Drama', 'ENG 323', 3, 'Examines the plays of Shakespeare and his contemporaries with attention to their social context and later reception. Close readings of texts and film versions are directed toward discerning elements of dramatic technique, characterization and theme.', 15),
(791, 'Medieval Literature', 'ENG 324', 3, 'Surveys the Medieval origins of English literature until the late 15 th century across the genres of lyric, epic, romance and drama.', 15),
(792, 'Renaissance Poetry', 'ENG 325', 3, 'Examines the genres of lyric and epic poetry from the 16th and 17th centuries.', 15),
(793, 'Restoration and Neoclassical Literature', 'ENG 326', 3, 'This course places the genres of poetry, drama and the prose essay within their historical contexts of the late 17 th and the early 18 th centuries.', 15),
(794, 'Early Novel', 'ENG 328', 3, 'This course focuses on the emergence and early development of the novel in English starting in the 17 th century in light of its historical and literary contexts.', 15),
(795, 'Poetry Writing', 'ENG 331', 3, 'This course provides guidance in the form and construction of diverse forms of poetry, including poetry used in non-literary domains (such as advertising). Workshops are designed to develop style and theme, to deepen awareness of meter and rhyme, and the use of natural rhythms of the English language.', 15),
(796, 'Life Writing', 'ENG 332', 3, 'In this course, students will read a range of literature in the genre of life-writing, which will include biography, autobiography, letters, and podcasts. Set texts will include not only those conventionally understood as autobiography, but also those, such as works by Truman Capote (U.S.) and Doris Lessing (U.K.), which creatively blur the line between biography and autobiography. The course will allow students to develop their life writing narratives by producing portfolios of both biographical and memoiristic stories. Intersections and distinctions between (auto) biographical writing modes will be explored through in-class exercises to curate voice, and to develop skills of style, point of view, and narrative structure.', 15),
(797, 'Fiction Writing', 'ENG 333', 3, 'This course introduces the basic skills and techniques of writing prose fiction. Students study examples of published fiction for method and style. Through writing projects, exercises, and workshops, students learn to research, analyze, critique, revise, and edit their classmates as well as their own writing. The course offers students guidance and practice in developing description, dialogue, style, characterization, structure, as well as in experimenting with different genres such as fantastic realism, thriller, autobiographical, historical, experimental, or science fiction. Course projects can either be the first chapter of a novel, or one or several complete shorter prose works.', 15),
(798, 'Illness Writing', 'ENG 334', 3, 'Students in this course will explore an interdisciplinary range of illness narratives, which will include fiction extracts, memoirs, auto-ethnographies, and films/podcasts. Weekly readings will be linked to a related medical concept, illness, or controversy. The course trains students to engage, critically, with representations of illness in key texts, as well as creatively, by generating their own narratives that frame their perceptions of illness/otherness, as applicable, in relation to their home culture.', 15),
(799, 'Playwriting', 'ENG 335', 3, 'This course guides and enables students to practice playwriting. Students participate in writing exercises that focus on sense memory and perception, engage inner processes that generate work, experiment with dramatic and compositional strategies, learn different forms, including adaptations and documentary plays, and develop structure, point of view, story, character, and dialogue. In writing workshops students generate and receive constructive criticism. Students read and discuss a short play or scene from different historical and cultural contexts, to study and explore the diversity of individual voices and styles.', 15),
(800, 'Romantic and Victorian Poetry', 'ENG 336', 3, 'This course examines lyric and narrative poetry throughout the 19th century, primarily British and American.', 15),
(801, '19th-Century British Novel', 'ENG 339', 3, 'This course explores the novel of 19 th century England according to how it addresses major thematic and aesthetic concerns of the period.', 15),
(802, 'Modernism and Beyond', 'ENG 342', 3, 'This course explores the concept of Modernism and Modernist art forms from the late 19 th century to the 1960s. Through selected poetry, prose, film and plastic arts, the course seeks to understand a rich artistic, social and intellectual period.', 15),
(803, 'Modernism and Beyond', 'ENG 342H', 3, 'This course explores the concept of Modernism and Modernist art forms from the late 19th century to the 1960s. Through selected poetry, prose, film and plastic arts, the course seeks to understand a rich artistic, social and intellectual period.', 15),
(804, 'The 20th-Century British Novel', 'ENG 345', 3, 'This course tracks the British novelistic production throughout the 20 th century. Questions explored may include the novels’ relation to colonialism and its legacies, or the novels’ social and historical contexts of production.', 15),
(805, 'Contemporary Culture', 'ENG 346', 3, 'Explores contemporary culture through literature, film and other media using a British or American cultural studies approach. Topics may include the ways in which culture intersects with politics, race, class, religion, gender or globalization.', 15),
(806, 'Contemporary Culture', 'ENG 346H', 3, 'Explores contemporary culture through literature, film and other media using a British or American cultural studies approach. Topics may include the ways in which culture intersects with politics, race, class, religion, gender or globalization.', 15),
(807, 'Postcolonial Anglophone Literatures', 'ENG 348', 3, 'This course explores the English-language literary production from areas outside Europe and North America. Empire, encounter, diaspora, immigration, and exile may be among the objects of study.', 15),
(808, 'Early American Literature', 'ENG 351', 3, 'Chronicles the formation of a national literature from its Puritan beginnings to the late nineteenth century.  In tracing the emergence of an American “voice,” coursework may span a variety of genres such as autobiography, poetry, the novel, essays and speeches.', 15),
(809, '20th-Century American Novel', 'ENG 352', 3, 'This course tracks American novelistic production throughout the 20 th century. Issues explored may include war, race, the Great Depression, the Cold War and neo-imperialism.', 15),
(810, 'Theories of Literature and Culture', 'ENG 354', 3, 'Examines theories of literary and cultural production and reception. The course may be arranged chronologically or according to schools and approaches.', 15),
(811, 'Creative Writing', 'ENG 366', 3, 'This course develops creative writing in a variety of techniques of fiction, poetry writing and creative non-fiction writing, based on the study of selected models. Free-writing exercises and discussion of writing assignments will be emphasized.', 15),
(812, 'Creative Writing', 'ENG 366H', 3, NULL, 15),
(813, 'Comparative and World Literatures', 'ENG 372', 3, 'The course concentrates on the particular insights and problems attendant to examining literature from a cross-cultural perspective. Questions of genre, period and cultural relativism may be examined through primary texts drawn from two or more language traditions.', 15),
(814, 'Comparative and World Literatures', 'ENG 372H', 3, 'The course concentrates on the particular insights and problems attendant to examining literature from a cross-cultural perspective. Questions of genre, period and cultural relativism may be examined through primary texts drawn from two or more language traditions.', 15),
(815, 'Gender in Literature', 'ENG 376', 3, 'Traces the construction of gender as depicted in literature and other cultural productions. Women’s issues, sexuality and identity formation may be among the objects of study.', 15),
(816, 'Language and the Law', 'ENG 380', 3, 'This course offers a comprehensive account of the role of language in legal settings. It provides a theoretical and empirical approach to language in legal contexts such as legal and criminal investigations and courtroom proceedings. The principles of forensic linguistics are introduced in light of evidential texts/recordings. The course focuses on the use of a variety of linguistic tools varying from speaker’s/writer’s linguistic profiling to translation and interpreting.', 15),
(817, 'Corpus Linguistics', 'ENG 381', 3, 'This course takes a computer-based methodological approach to the study of authentic patterns in language use and their contextualization and applicability to language teaching and learning. Linguistic variations in databank of written and/or spoken texts will be explored through the analysis of concordances, frequencies, collocations and lexical bundles. The major aspects of corpus design, tools and types are also covered in this course.', 15),
(818, 'Corpus Linguistics', 'ENG 381H', 3, 'This course takes a computer-based methodological approach to the study of authentic patterns in language use and their contextualization and applicability to language teaching and learning. Linguistic variations in databank of written and/or spoken texts will be explored through the analysis of concordances, frequencies, collocations and lexical bundles. The major aspects of corpus design, tools and types are also covered in this course.', 15),
(819, 'Topics in Literature and Culture', 'ENG 479', 3, 'This course explores a literary-theoretical topic in some depth.  Topics might include philosophy and literature, psychological and Marxist approaches to literature, narrative theory or postmodernism.', 15),
(820, 'Topics in Literature and Culture', 'ENG 479H', 3, 'This course explores a literary-theoretical topic in some depth.  Topics might include philosophy and literature, psychological and Marxist approaches to literature, narrative theory or postmodernism.', 15),
(821, 'Discourse and Power', 'ENG 480', 3, 'This course examines the relationship between language and ideology through investigating the role of discourse as an instrument of power and control. Emphasis is placed on modern socio-political discourse using Critical Discourse Analysis (CDA) as an analytic model. Both CDA’s theoretical underpinnings as well as its more useful practical aspects are covered with particular emphasis on Systemic Functional Grammar, conceptual metaphorical mapping, and generic framing as the most valuable analytical tools for uncovering hidden ideologies in texts.', 15),
(822, 'Topics in Drama and Theater', 'ENG 487', 3, 'This course explores ideas of form, convention, style and context in Drama & Theater. It focuses on different dramaturgical and theatrical approaches to specified topics or theater trends or schools (Modern Drama, Postmodernism, Documentary Drama, Gender and Theater, Popular Theater…) Course may be repeated under different topics each semester.  Students may take it more than once.', 15),
(823, 'Topics in English Language', 'ENG 488', 3, 'This course examines a specialized topic in English language studies in depth. It engages with theoretical and applied perspectives, fostering critical analysis of language in diverse contexts. Focus is on interdisciplinarity in covering more recent developments in the fields of language and linguistics.', 15),
(824, 'Capstone Project', 'ENG 499P', 3, 'An in-depth individual capstone project involving personal research—and if appropriate an internship in an off-campus setting—under close faculty supervision, culminating in a substantial paper demonstrating scholarly expertise as well as original insights in a significant subject relevant to the curriculum of the English Studies program.', 15),
(825, 'Capstone Research', 'ENG 499R', 3, 'An in-depth individual capstone project involving personal research—and if appropriate an internship in an off-campus setting—under close faculty supervision, culminating in a substantial paper demonstrating scholarly expertise as well as original insights in a significant subject relevant to the curriculum of the English Studies program.', 15),
(826, 'Essay Reading and Writing I', 'ARA 101', 3, 'This course concentrates on essay reading and writing. Through selected readings that represent different types of essays, students will receive training on literary analysis and essay writing skills. This course also includes a review of essential grammatical rules of the Arabic language.', 16),
(827, 'Arabic Grammar and Syntax', 'ARA 303', 3, 'This course looks into advanced elements of Arabic grammar, syntax and issues of I’rab. It trains students to analyze sentence structures.', 16),
(828, 'Arabic Linguistics', 'ARA 304', 3, 'This course addresses principles and trends of linguistics in light of modern linguistic theories and descriptive methodologies as they apply to Arabic.', 16),
(829, 'Arabic Philology and Lexicography', 'ARA 305', 3, 'This course deals with major issues of Arabic philology and offers an overview of Arabic lexicography. Students will be asked to consider theoretical issues in analyzing lexical and lexicographic material. This course tackles also issues related to phonology and elocution.', 16),
(830, 'Classical Arabic Rhetoric and Literary Criticism', 'ARA 310', 3, 'This course addresses basic features of Arabic rhetoric and literary criticism, and the dialectical relationship between them. Representative texts will be studied to illustrate theories presented throughout the course.', 16),
(831, 'Contemporary Literary Theory and Criticism', 'ARA 312', 3, 'This course introduces several modern and postmodern theories of literature and literary criticism such as structuralism, deconstruction and feminism. Rep­resentative literary texts will be an integral part of the course.', 16),
(832, 'Creative Writing', 'ARA 313', 3, 'This course exposes students to various literary styles and artistic forms of writing. Students are given the opportunity to implement the skills they learn in creative writing of their own.', 16),
(833, 'Pre-Islamic and Umayyad Poetry', 'ARA 320', 3, 'This course is a survey of ancient Arabic poetry from the pre-Islamic period to the end of the Umayyad era. The course focuses on major issues and problems reflected in the poetry of this period.', 16),
(834, 'Abbasid Poetry', 'ARA 323', 3, 'This course is a survey of the poetic trends, themes and stylistics of the Abbasid period. The course focuses on the major figures of poetry in that period, and relates Abbasid poetry to the cultural changes in that period.', 16),
(835, 'Abbasid Poetry', 'ARA 323H', 3, 'A survey of the poetic trends, themes and stylistics of the Abbasid period. The course focuses on the major figures of poetry in that period, and relates Abbasid poetry to the cultural changes in that period.', 16),
(836, 'Andalusian Literature', 'ARA 324', 3, 'This course studies Arabic poetry and prose in Andalusia focusing on the development of new genres and literary art-forms in that period.', 16),
(837, 'Classical Prose', 'ARA 325', 3, 'The course is a survey of the development of Arabic literary prose from the 2nd/8th to the 5th/11th centuries. The course introduces major authors and works that charac­terize the Arabic prose of the period.', 16),
(838, 'Classical Prose', 'ARA 325H', 3, 'The course is a survey of the development of Arabic literary prose from the 2nd/8th to the 5th/11th centuries. The course introduces major authors and works that charac­terize the Arabic prose of the period.', 16),
(839, 'Arab Civilization and Culture', 'ARA 326', 3, 'This course is a survey of Arab civilization and culture. It emphasizes aspects of cultural development in thought, sciences, social life and arts including paint­ing, music, singing, calligraphy, crafts, etc. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 16),
(840, 'Sufi Literature', 'ARA 327', 3, 'This course surveys the rise of ascetic and mystical tendencies in Islam includ­ing the historical development and central ideas of Sufism. It pays special atten­tion to the poetic expression of the mystical experience. Representative texts will be read for analysis and aesthetic appreciation. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 16),
(841, 'Arabic Folk Literature', 'ARA 328', 3, 'This course surveys the development of classical and premodern Arabic folk literature. Selections from texts such as The Arabian Nights, Sirat Antara and Sirat Bani Hilal are studied and analyzed in order to follow the development of this genre throughout history.', 16),
(842, 'Travel Literature', 'ARA 329', 3, 'This course surveys a selection of non-fictional texts categorized under ‘Travel Literature’. The course considers a number of travel narratives, paying attention to elements of history and context as well as narrative techniques, structure and themes in this particular genre. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 16),
(843, 'Lebanese Literary Heritage', 'ARA 330', 3, 'This course aims at introducing students to the Lebanese literary heritage. It allows students to appreciate the significance of the literary heritage of Lebanon which was presented in different genres. This is accomplished through a thorough critical study and analysis of Lebanese poetry, novels, literary criticism and history, and lyrics performed in the local dialect.', 16),
(844, 'Modern Arabic Novel and Short Story', 'ARA 341', 3, 'This course introduces the novel and the short story as literary forms. It explores various elements that make up the novel such as plot, characterization, style, genre and theme, as well as its historical, cultural, and thematic contexts.', 16),
(845, 'Arabic Drama', 'ARA 342', 3, 'This course addresses the emergence and development of drama as a genre in Arabic literature. Through careful readings of representative plays, students survey various themes and issues prominent in Arabic drama along with their social and political contexts.', 16),
(846, 'Modern Arabic Poetry', 'ARA 343', 3, 'This course focuses on modern Arabic poetry from the late 19th century up to the present time. Selected samples of poetry are studied and analyzed.', 16),
(847, 'Trends in Modern Literature', 'ARA 344', 3, 'This course deals with modern literary trends from classicism to surrealism. Students are trained in intensive analysis of selected texts in Arabic literature that are representative of the course content.', 16),
(848, 'Trends in Modern Literature', 'ARA 344H', 3, 'This course deals with modern literary trends from classicism to surrealism. Students are trained in intensive analysis of selected texts in Arabic literature that are representative of the course content.', 16),
(849, 'Topics in Arabic Language and Literature', 'ARA 488', 3, 'This course deals with a topic that is beyond the normal scope of the listed courses in the B.A. program. It includes new approaches to language, literature or civilization as well as a special theme.', 16),
(850, 'Senior Study', 'ARA 499', 3, 'A course designed for seniors to employ the techniques of modern literary criticism by conducting intensive research into a selected literary figure, trend or work.', 16),
(851, 'Basic Mathematical Statistics', 'STA 102', 3, 'This course includes counting (permutation and combination), basic probability, conditional probability (Bayes’ rule) and commonly used probability distributions such as the binomial distribution (discrete) and the normal distribution (continuous). The course also covers the nature of statistics, random variables, data organization (such as Pie chart, Bar Graph and Histograms) and descriptive measures (range, mean, median, mode and standard deviation). The student will be exposed to tools such as Excel and SPSS. Applications to social sciences are covered through case studies.', 17),
(852, 'Biostatistics', 'STA 205', 3, 'This course introduces the statistical design and analysis techniques needed to perform pharmaceutical research, and evaluate clinical data. It includes designing epidemiologic and clinical studies, evaluating diagnostic testing procedures, interpreting the use of statistical data in Medical Literature, and using frequently used statistical methods of data analysis. Emphasis is placed on the statistical concepts, and their application to the critical appraisal of clinical and experimental data.', 17),
(853, 'Introduction to Statistics in Social Sciences', 'STA 302', 3, 'This course is an introduction to statistical analysis for the social and behavioral sciences. It covers both descriptive and inferential statistics. Descriptive statistics covers ways of representing data graphically, measures of central tendency and dispersion, the normal distribution and other types of standard scores as well as an introduction to probability and sampling. The inferential statistical tests addressed in the course cover ratio, ordinal and categorical variables. The course deals with inferential tests involving one, two or more means, proportions, and correlations. It also considers the basic analysis of variance models (ANOVA), linear regression models and non-parametric tests such as chi-square. Students will develop sufficient conceptual understanding to select from a variety of statistical tests appropriately. In addition, students will learn to use a statistical software package to enter data and conduct a range of statistical analyses.', 17),
(854, 'Introduction to Philosophy', 'PHL 101', 3, 'This course introduces the major issues and outlooks in ancient, modern, and contemporary philosophy.', 18),
(855, 'Ancient Philosophy: From the Pre-Socratics to the Epicureans and the Stoics', 'PHL 201', 3, 'This course examines the roots of Western philosophy in Ancient Greece, and serves as a broad introduction to philosophy. While emphasis will be placed on the works of Plato and Aristotle, the renewed appreciation of the depth of pre-Socratic thought and the value of post-Aristotelian thought will also be given their due. In the process, themes such as the origins of the universe, the nature of reality, the basis of our knowledge, the good life and society, and the handling of misfortune will be discussed. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 18),
(856, 'Medieval Philosophy: From Plotinus to Ockham', 'PHL 202', 3, 'An examination of the works of major Medieval thinkers. Special attention will be paid to the origins of modern philosophy in Medieval thought, and how Medieval thinking stands in contrast to Ancient thinking. Also, the theological character of scholastic thought will be emphasized, for example: attempts to reconcile each of Christian and Islamic teachings with the authority of Aris­totle; attempts to reconcile the benevolence of God with the existence of evil; attempts to reconcile the omnipotence of God with presumed limits placed on his power by “natural laws”; and attempts to reconcile the omniscience of God with free will. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 18),
(857, 'Early Modern Philosophy: From Montaigne to Kant', 'PHL 203', 3, 'Emphasis will be given to (1) early modern theories of knowledge (epistemol­ogy) against the backdrop of the Scientific Revolution and (2) the roots of early modern philosophy in Renaissance humanism and the outstanding individuals such as Montaigne who had contributed to several areas of human endeavour. In parallel with (1) and (2), two contrasting approaches to acquiring knowledge will be studied, one based on experience (empiricism), the other on reason (rationalism). Finally, attention will be given to the significant role of skepticism. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 18),
(858, 'Modern Philosophy: From Hegel to Heidegger and/or Frege to Wittgenstein', 'PHL 204', 3, 'Two variants of the course will be offered to reflect recent realities. The first var­iant of the course traces a development from Hegel through Marx, Kierkegaard, Schopenhauer, and Nietzsche into 20th century Phenomenology and Existen­tialism. The second variant of the course will look at the work of Frege and Rus­sell, and some of their influential 20th century successors. Within the second variant, special attention will be given to Wittgenstein, who was a unique and unclassifiable thinker of great importance.', 18),
(859, 'Critical Thinking', 'PHL 210', 3, 'Students will be taught how to read out arguments in ordinary language —for instance in opinion pieces in newspapers and magazines or in short philo­sophical passages— and to identify the kind of argument, and to analyze and evaluate those arguments. Students will also be introduced to formal modes of reasoning in categorical and symbolic logic. Finally, students will be trained in thinking creatively about certain passages from the established great figures in the philosophical tradition.', 18),
(860, 'Symbolic Logic', 'PHL 211', 3, 'This course introduces the concepts and principles of symbolic logic, in particular the distinction between valid and invalid arguments, the determination of logical relations between sentences, the formal analysis of sentences so that the logical relations between them can be determined, the definition and construction of a formal language, the evaluation of truth, truth-functions, quantifiers and their use in the analysis of arguments, and predicate logic.', 18),
(861, 'Ethics', 'PHL 301', 3, 'Ethics is classically the study of what is right, just, appropriate, or desirable, all of which are among the various meanings given to “the good,” the central concern of ethics. Typically, this course will have historical, theoretical, and applied dimensions: the historical dimension will provide acquaintance with the various kinds of ethical and moral theory that have emerged over the last two and half millennia; the theoretical dimension will examine the content of these ideas closely; and the applied dimension will sharpen the student’s ability to think through distinctively ethical and moral problems.', 18),
(862, 'Theory of Knowledge', 'PHL 302', 3, 'Theory of knowledge, known as “epistemology,” is a fundamental and endur­ingly significant branch of philosophy. Despite many historical transformations (some of which will be examined), it has had stable aims, among which are the definition of knowledge, the distinction between knowledge and belief, the methodologies and procedure by which knowledge is acquired, and how to deal with skepticism. These issues will be raised and explored with reference to both ancient and modern texts.', 18),
(863, 'Metaphysics', 'PHL 303', 3, 'Metaphysics is the broad philosophical study of the basic form, structure, essence, and elements of reality or “being,” and in its classical form it tries to provide a unified account of how the cosmos hangs together and what makes the cosmos what it is. This course may variously emphasize metaphysical topics in religion, physics, and/or mind. Overall, the course will survey philosophers’ quest to grasp the basic nature of reality (perhaps with that of some physicists and biologists who have recently joined philosophers in their timeless quest).', 18),
(864, '19th Century Philosophy', 'PHL 304', 3, 'This course focuses on post-Kantian philosophy. The course traces the developments of thought through various thinkers such as Hegel, Fichte, Schelling, Nietzsche, Schopenhauer, Kierkegaard, and Marx. Thematically the course focuses on the ideas of idealism, materialism, transcendental and naturalistic philosophy, as well as various issues that arise out of these conceptions. These issues include the nature of reason, freedom, culture, and history.', 18),
(865, 'Phenomenology', 'PHL 306', 3, 'This course introduces the 20th century phenomenological movement while developing its connections to existentialism. The course begins with the early phenomenologists like Husserl, or early existentialists like Kierkegaard, and traces a line of development that proceeds through thinkers like Heidegger, Sartre, De Beauvoir, and Levinas. The focus on the course is on questions about the nature of consciousness, freedom, being, and their connections to moral, political, and religious thought.', 18),
(866, 'Philosophy of Language', 'PHL 307', 3, 'This course focuses on theories of meaning and reference particularly as they emerged in the early 20th century. The course begins with Gottlob Frege and proceeds through various philosophers who contributed to that tradition, including Russell, Donnellan, Grice, Davidson, and Kripke. The focus of the class will be largely on how proper names successfully refer, how sentences acquire their meaning systematically from their constituent parts, how there can be empty names, and how successful communication is possible. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 18),
(867, 'Philosophy of Religion', 'PHL 311', 3, 'This course will address fundamental philosophical questions arising from all major religions in the worlds, including the three Abrahamic faiths as well as the older Asian traditions such as Hinduism, Buddhism, Confucianism, and Dao­ism. The course will deal with common religious themes such as Transcendence (or the Sacred or Mystery), religious experience, religious language, symbolism, the relationship between faith and reason, the relationship between science, mythology, and religion, and religious pluralism.', 18),
(868, 'Philosophy of Art', 'PHL 321', 3, 'The course deals with (1) how we can discern whether something qualifies as art, in what sense our aesthetic judgments are subjective or objective, what qualifies as a good, bad, correct, or an incorrect interpretation of an artwork, and whether we can learn from art (epistemological issues); (2) the nature of art and artworks and the kinds of experience associated with them, how art relates to reality, the creative process, and aesthetic experience (metaphysical issues); and (3) the moral dimension of art (moral issues). Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 18),
(869, 'Philosophy in Literature and Film', 'PHL 322', 3, 'Modern novels and films have often been far more effective than the work of philosophers in engaging readers with some of the most important questions of life, such as the existence of God, the meaning of life, the role of art in shaping human beings, the nature of time, truth, and reality, our relationship to nature, and so on. This course will therefore turn to literature and/or film to immerse students in situations that bring urgent philosophical issues to the foreground with great power and conviction.', 18),
(870, 'Philosophy of History', 'PHL 323', 3, 'The principal aim of this course is a critical consideration of the claim that there has been genuine progress in global history, especially morally. Typically this course will study the work of G.W.F. Hegel and use it as a departure point, but other variations are possible. These variations will be based on the work of Hegel’s critics, such as Marx, Nietzsche, Adorno, and Foucault. A byproduct of such criticism has been the rediscovery of the value of pre-Hegelian philosophy of history, and so the worldly and deeply cultured approach taken by Vico, Herd­er, and von Humboldt will also be covered. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 18),
(871, 'Philosophy of Science', 'PHL 324', 3, 'Traditionally, this course has consisted in an examination of how philosophers have regarded science, especially the natural sciences: physics, chemistry, and biology. However, it has also become important to consider how scientists themselves regard their own work, especially since this often disagrees with what philosophers say about science. Readings will therefore be taken from well known philosophers of science such as Popper, Kuhn, Lakatos, Feyerabend, Holton, and A. W. Moore, and from the writings of scientists themselves, such as Darwin, Maxwell, Mach, Poincarré, Einstein, Heisenberg, Eiseley, Schrödinger, and Hawking.', 18),
(872, 'Philosophy of Mind', 'PHL 325', 3, 'Themes to be discussed are the nature of mind, the argument between materi­alists and non-materialists, artificial intelligence, and the resistance of mental states such as beliefs, intentions, values, norms, thoughts, perceptions, and judg­ments to physical interpretation. Positions canvassed will be chosen from the following: dualism, behaviourism, identity theory, and functionalism. Special consideration will be given to philosophers (like Hegel, Nietzsche, and Wittgen­stein) mindful of how traditional theory distorts our ability to appreciate the elusive “nature” of mind.', 18),
(873, 'Social and Political Philosophy', 'PHL 326', 3, 'Through a selection of works by leading thinkers from Plato onwards, issues addressed include the basic theoretical approaches (social contract theories, utilitarianism, political realism, politics guided by the idea of the Good and other ideas that are metaphysically grounded), the nature of power, good vs. bad governance, the role of reason in social and political life, ideology, the relation of ethics to politics (including a look at how ethical theories like utilitarianism and pragmatism can be utilized in political theory), and the recent liberalism vs. communitarianism debate. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 18),
(874, 'Philosophy and Mythology', 'PHL 327', 3, 'In conjunction with the recent success of popular works, this course attempts to revive interest in and appreciation of mythology. Emphasis will also be made on the realization that mythology has played an even greater role in shaping philosophical thought in ancient Greece, India, and China than previously recognized. Readings will include classic general works about mythology as well as works that illustrate how mythology has influenced some of the greatest thinkers of the ancient world. The aim is to portray a more “living” or “concrete” notion of what later became metaphysics and ethics. The implications for the philosophy of religion will also be discussed. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 18),
(875, 'Arab and Islamic Philosophy', 'PHL 328', 3, 'A look at key Arab and Islamic figures, past and present, such as al-Kindi, al-Farabi, Ibn Sina, al-Ghazzali, Ibn Rushd, and Mulla Sadra; and René Habachi, Charles Malik, Muhammad Abed al-Jabiri, Hassan Hanafi, Seyyed Hossein Nasr, Muhammad Arkoun, and Abdelkarim Surush. These works will be discussed in relation to how broad philosophical themes have been treated, including ques­tions of metaphysical, moral, epistemological, political, and religious interest. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 18),
(876, 'Individual Philosopher', 'PHL 350', 3, 'The course is an in-depth study of the work of a particular philosopher, and reflects the sustained rigor and depth of the approach of the philosopher to universal questions. It also examines the work of scholars who have studied the thought and works of individual philosophers. This helps students to appreciate the nature and virtue of the scholarly tradition. Primary as well as secondary sources are examined in order to provide a comprehensive overview of the life, works, thought and influence of the philosopher.', 18),
(877, 'Special Topics', 'PHL 401', 3, 'This course focuses on specific topics in the philosophical tradition; classical and modern. It may cover topics such as contemporary philosophy, interactive combinations among individual philosophers, specific philosophical themes, Arabic and Islamic philosophy, world philosophy, Phenomenology and Analyti­cal Philosophy.', 18),
(878, 'Senior Study', 'PHL 499', 3, 'Students must complete a supervised substantial paper (or an approved equiv­alent) on a topic formulated in consultation with a member of the philosophy faculty. This course provides the opportunity for seniors to share with one another their work in progress in a collegial seminar setting. Students present their work and receive feedback from their peers and their instructor.', 18),
(879, '20th Century History of Lebanon and the Region', 'HST 101', 3, 'This course examines the situation of Lebanon during and in the aftermath of World War I, the proclamation of Greater Lebanon after the war, and the French mandate until the independence of the Arab country in 1943. The course also encompasses the modern history of Lebanon in relation with the history of its neighboring Arab countries: Egypt, Syria, Palestine, Iraq, and Saudi Arabia.', 19),
(880, 'Historical Tools', 'HST 205', 3, 'This course introduces the discipline of history and provides students with the necessary historical and academic skills through acquainting them with differ­ent ways of reading, writing, and interpreting historical texts and documents. The core of this course is to enable students to conduct their own historical research. A broad overview of historical methodologies and historiography (‘the history of history’) also shows history’s unique place among the Humanities as well as the Social Sciences.', 19),
(881, 'The Ancient World, Pre-History to Pericles', 'HST 220', 3, 'This course traces history from the first known civilizations, focusing in particular on settlements arising around the major river systems such as the Nile, Tigris, Euphrates and the Indus river valley, to the archaic and classical Greek city states such as Athens and Sparta. The course may focus on Sumerian, Babylonian, Egyptian, Phoenician, Semitic and Greek culture, as well as other cultures of the Near and Middle East. Possible topics may include the introduc­tion of Hammurabi’s law-code, Egyptian-Phoenician trade relations, the devel­opment of writing, the Trojan War, the Spartan and Athenian constitutions and the Persian Wars. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 19),
(882, 'The Ancient World, Greece and Rome', 'HST 221', 3, 'This course introduces the history of ancient Greece and Rome. Starting with the development of poleis in Greece and Rome from the 8th century BCE onwards, and ending with the reign of the emperor Justinian in the 6th century AD, the course covers landmark events such as the Persian Wars (490-449 BCE), the Peloponnesian wars (431-404), the conquests of Alexander the Great (356-323 BC), the imperial expansion of Rome from the Punic Wars onwards, the rise of Christianity and the Edict of Milan (312 AD), the rise of Constantinople as imperial capital, and finally the various attacks on Rome by Huns, Goths and Germans in the 5th and 6th centuries. Students will engage with a variety of primary and secondary sources. Famous ancient authors such as Plato, Herodotus and Cicero may be discussed, but we will also look at archaeological remains, classical art and epigraphy. The course may focus on themes such as the birth of democracy, imperialism, causes for decline and progress and the ancient', 19),
(883, 'History of Lebanon—from Antelias Man to the Ottoman Conquest (1516)', 'HST 230', 3, 'This course surveys the history of Lebanon from prehistoric times through the Phoenician and Roman periods and on to the Middle Ages and the Crusades, ending with the Ottoman conquest at Marj Dabiq in 1516. The emphasis is on those features that define the peoples of Mount Lebanon and the Mediterrane­an coastal settlements throughout this span of time, and how the foundations for the later emergence of a distinct Lebanese polity and culture were laid. Among the themes explored by the course are the pre-Christian era, the coming of Christianity, the immigration into the Lebanese mountains of a variety of peoples including the early Maronites, the coming of Islam, the arrival of the Druze, rivalries and precarious balances, external factors and the economic viability or lack thereof of the mountain. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 19),
(884, 'History of Lebanon—from the Imarah to the 1975-1990 War', 'HST 231', 3, 'Tracing the history of Lebanon from the rise of the Imarah to the 1989 Ta’if agreement, this course focuses on the formation of the Lebanese polity and identity and its place in the wider Arab world. It may deal with pivotal figures such as Fakhr Ed-Deen and Emir Bachir, the role of the Maronites and their relations with France and the Vatican, the Ottoman period, the impact of the Tanzimat and the rise of the Mutasarrifiya. Key events and developments in the 20th century include the First World War, the French Mandate, Lebanese independence in 1943, the National Pact, the 1958 events, and the 1975-1990 War. How could the initial years of prosperity lead to the outbreak of war in 1975? The interaction between internal factions and communities and outside powers will be emphasized.', 19),
(885, 'History of Lebanon—from the Imarah to the 1975-1990 War', 'HST 231H', 3, NULL, 19),
(886, 'History of the Arab Peoples', 'HST 240', 3, 'The focus of this course is on the Arabs as a people and their achievements throughout history. From their Semitic origins in Arabia to their many succes­sive sub-variations throughout the Middle East the course traces the develop­ment of the Arabs and their civilization into modern times. The rise of Islam and the revelation of the Koran in the Arabic language to an Arab Prophet made the Arabs special in their own eyes and in those of all Muslims. Whether it is the life of the courts and cities under the Umayyads, the Abbasids, and in Arab Spain, or the everyday existence of common people in the countryside, the course provides students with a rich portrait of Arab culture and history. Critiques such as those of Ibn Khaldun and some of the later writers of the Nahda period starting in the second half of the 19th century could be germane to the presentation. How the Arabs interacted with Turks, Persians and Euro­peans and how these outsiders perceived the Arabs could also be central to', 19),
(887, 'History of the Arab Peoples', 'HST 240H', 3, NULL, 19),
(888, 'History of Islam in the Middle East', 'HST 241', 3, 'This course may either provide an overview of the history of the Islam from its conception in the 7th century to the present-day or focus on particular themes in the history of Islam. As well as introducing students to the history of one of the world’s major religious faiths, the course examines Islam’s development as a creed and a complete way of life. A particular focus will be the challenges arising from Islam’s relations with the non-Muslim world. The historical survey may include such pivotal events and developments as the life and message of the Prophet Mohammed, the first four wise Caliphs, the Sunni-Shiite split, the schools of Islamic jurisprudence, the shari’a and the five pillars. The Umayyad and Abbasid Empires and the expansion of Islam will be discussed. Important topics in the medieval history of Islam are the flowering of Islamic culture, the role of the Ayyubids, Fatimids and Seljuks, the Crusades, the Mongol invasion, the conversion of Iran to Shiism and the emergence', 19),
(889, 'History of Islam in the Middle East', 'HST 241H', 3, NULL, 19),
(890, 'Europe and the Middle East (1798-1956)', 'HST 242', 3, 'This course provides students with an overview of European-Middle Eastern relations during the 19 th and early 20th centuries. Introducing students to the stormy and complex interactions between European powers and the peoples and states of the Middle East, the course will not just deal with the political, military and diplomatic events but also with their social, economic and cultural impact on both Europe and the Middle East. The period reveals both Europe and the Middle East evolving rapidly, but not always in tandem.Examples might include the history of Egypt from Napoleon’s invasion in 1798 to the 1952 officer’s revolution led by Nasser; the history of the Ottoman Empire from the Tanzimat to its decline; British, French, German and Russian interests in the Middle East; the impact of the two World Wars, Mustafa Kemal Ataturk and the creation of modern Turkey and the rise of the Arab state system.', 19),
(891, 'Europe & the Middle East (1798-1956)', 'HST 242H', 3, 'This course provides students with an overview of European-Middle Eastern relations during the 19 th and early 20th centuries. Introducing students to the stormy and complex interactions between European powers and the peoples and states of the Middle East, the course will not just deal with the political, military and diplomatic events but also with their social, economic and cultural impact on both Europe and the Middle East. The period reveals both Europe and the Middle East evolving rapidly, but not always in tandem.Examples might include the history of Egypt from Napoleon’s invasion in 1798 to the 1952 officer’s revolution led by Nasser; the history of the Ottoman Empire from the Tanzimat to its decline; British, French, German and Russian interests in the Middle East; the impact of the two World Wars, Mustafa Kemal Ataturk and the creation of modern Turkey and the rise of the Arab state system.', 19),
(892, 'Economic History of the Middle East', 'HST 243', 3, 'This course provides a country by country account of economic development in the Middle East and North Africa from early modern to modern times. Emphasis may be put on the shift from early cottage industries to the rudimentary irri­gation schemes and cotton cultivation in Mohammad Ali’s Egypt. The collapse of Ottoman finances and the growing dependence on international financers may be another topic as well as the increased international competition in the textile and cotton industry. The importance of the region for the major trade routes between Europe and Asia will be emphasized throughout. Key events are the opening of Suez Canal in 1869, the High Dam project and the discovery of oil in Arabia. Charles Issawi’s classic work on the economic history of the region is used as a guide for basic readings along with other more recent authoritative treatments of specific economic issues.', 19),
(893, 'History of the Arab-Israeli Conflict', 'HST 244', 3, 'This course focuses on the emerging clash between the nascent Zionist project starting in the 19 th century and the gradual dispossession of the Arab inhabit­ants of Palestine culminating in the 1948 creation of the state of Israel. It aims to shed light on the historical progression of the conflict and the external players impacting its development. The course also assesses the Arab responses to Israel as well as the internal evolution of the Jewish state from frontier kibbutzim to nuclear power. Among events and developments leading up to 1948 the course may zoom in on the conception of Zionism, relationships between Zionists and the British and Ottoman Empires, early migration into Palestine and the impact of the two World Wars and the Holocaust. It will also address international responses to the existence of Israel arising from Arab and Palestinian nation­alism, the Arab-Israeli wars, the emergence of the Palestinian Fedayeen and the Palestine Liberation Organization, the impact o', 19),
(894, 'Europe in Late Antiquity (410–1066)', 'HST 301', 3, 'This course focuses on Europe in Late Antiquity and the Early Middle Ages. Through either a historical overview or a thematic approach it will clarify how the Roman Empire gave way to a feudalistic Europe. The impact of German­ic tribes and the development Christianity will be assessed to explain the distancing between East and West Europe culminating in the 1054 schism and the investiture struggle between popes and kings over who has superior power. Other possible topics may include the development of monasticism, the rise of Clovis and Charlemagne, the writings of key authors such as St. Augustine, Boethius and the Venerable Bede, Islamic conquests in Spain and Sicily, and the later conquests of the Normans. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 19),
(895, 'Medieval Europe (1066–1453)', 'HST 302', 3, 'This course concentrates on European history during the high and late Middle Ages. It may either provide a historical overview from the Norman conquest of Britain in 1066 to the fall of Constantinople in 1453, or offer a more thematic approach. Possible themes may include the Crusades, the founding of Europe’s great universities, the rise of scholasticism, Gothic architecture, the medieval guilds, the Italian city-states such as Florence and Venice and the Hundred Years War. Students will have the opportunity to engage with both secondary and pri­mary sources, among which can be the works of great thinkers and writers such as Abelard, Thomas Aquinas, Boccaccio and Dante among many others, but also archaeological and material sources that reflect on everyday life in medieval Europe. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 19),
(896, 'Early Modern Europe (1450–1750)', 'HST 303', 3, 'This course sheds light on the history of Europe in the Early Modern period through either a historical overview from the Renaissance to the beginnings of the Industrial Revolution, or a more thematic approach. Possible topics include the Protestant Reformation and the Catholic Counterreformation, the Age of Discovery, Renaissance humanism, encounters between Christians, Muslims and Jews, Tudor and Stuart England as well as social and economic develop­ments such as the rise of mercantilism. It may also focus on the beginnings of the scientific revolution through the contributions of scientists such as Coperni­cus, Galileo and Newton. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 19),
(897, 'Modern Europe (1750–1945)', 'HST 304', 3, 'This course treats the period starting with the beginnings of the Industrial Rev­olution in Britain and ending with the Second World War. It may either provide a historical overview, covering landmark events such as the French and Amer­ican Revolutions, the Napoleonic era, the 1848 revolutions, the 1854 Crimean War, the unification of Germany and Italy, the Great War and the 1917 Bolshevik Revolution and the Second World War. It could also approach the history of Europe from a more thematic approach focusing on themes such as the rise of nationalist and socialist ideologies, the idea of progress and evolutionism, the abolition of slavery and the end of colonialism, fin-de-siècle Vienna and Paris, developments in modern art and modern philosophy.', 19),
(898, 'Contemporary Europe (1945–1989)', 'HST 305', 3, 'This course covers the period from the end of World War II to the fall in 1989 of the Berlin Wall and the beginning of the end of communist rule in Eastern Europe and Russia. Its main focus is on the post-war ascendancy of both the United States and the Soviet Union and the developing rivalry between them known as the Cold War. Main flashpoints of the Cold war include Korea, Cuba, Vietnam, the Middle East, and Afghanistan. In addition to the history of the Cold War, the course may also address topics such as the Universal Declaration of the Human Rights, the civil rights movement, feminism, the 1968 student revolutions and the technological and information revolutions.', 19),
(899, 'History of Byzantium', 'HST 330', 3, 'This course deals with the history of Byzantium from the foundation of Con­stantinople by Constantine the Great in 330 until the fall of the city in 1453. It may either offer a historical overview along dynastic lines, or a more thematic approach. Possible themes include the relations of Byzantium with emerging powers in the East and the West, the religious controversies such as Iconoclasm and the 1054 schism, emperors and empresses, Byzantine cultural and architec­tural accomplishments in Constantinople and other cities, monasticism, and the Crusades. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 19),
(900, 'History of Russia', 'HST 331', 3, 'This course may either chronicle the history of Russia from the first Rus until Vladimir Putin, or focus on a particular theme. Possible topics include the conversion of Slavs to Christianity in 988 and subsequent relations between the Russians and the Orthodox Church, the establishment of Moscow and the institution of the Czar, international relations and isolation, serfdom and the emancipation of the Serfs, important Czars such as Ivan IV (the Terrible), Peter the Great, Catherine II the Great and the Romanovs, the 1917 Revolution, Lenin and Stalin, and the rise and collapse of the Soviet Union. Students will be invited to engage with the great Russian thinkers and authors such as Dostoevsky, Tolstoy, Solzhenitsyn and others. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 19),
(901, 'History of China', 'HST 332', 3, 'This course may survey the history of China from the Han dynasty (202 BC-221 AD) to the establishment of the present-day People’s Republic of China, covering such landmark events as the Ming dynasty, the Ch’ing dynasty, the Opium Wars, the Boxer uprising, the communist revolution and the cultural revolution. It may also focus on a particular theme, such as nationalism versus communism, Chiang Kai-Shek and Mao Zedong, the recent growth of the Chinese economy and China’s relations with Tibet, Taiwan, Japan, Britain, Russia and the United States. Finally, the course may focus on a particular period such as the 19 th cen­tury or the period between the two World Wars. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 19),
(902, 'History of South Asia', 'HST 333', 3, 'This course focuses on the Indian subcontinent, which includes India, Paki­stan, Bangladesh and Sri Lanka. It focuses on the interplay of the main world religions such as Hinduism, Buddhism, Islam, Christianity and the relations between Hindus, Sikhs, Muslims, Tamils and Sinhalese. Another main topic is the colonization and decolonization of South Asia from Vasco da Gama (1498) to the 1947 independence and partition. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 19),
(903, 'History of North America', 'HST 334', 3, 'This course may either provide a historical overview from pre-Columbian America to Obama or focus on a particular theme in American history. Possible topics may be the relations between European settlers and Native Americans, the rivalry between France, Spain and Britain over North America, the War for Independence and the formation of the US constitution, the westward expan­sion, discussion over slavery and the US Civil War. Important topics in the 20th century include the involvement in the two World Wars, the Depression, the Cold War and the Civil Rights Movement. The course may choose to focus on either the US or Canada. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 19),
(904, 'History of Central and South America', 'HST 335', 3, 'This course could provide a historical overview of South and Central America from the Incas, the Mayans and the Aztecs to Fidel Castro’s long reign in Cuba. It may also focus on the colonization of America and the 19th century struggles for independence, the impact of slavery on American societies, important figures such as Simon Bolivar, Cortes, Allende, Che Guevara and Fidel Castro, the exploitation of the Amazon rainforest and the cultivation of drugs, among many other themes. It may either cover the whole of Central and South America or zoom in on a particular country. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 19),
(905, 'History of Africa', 'HST 336', 3, 'This course can focus on any theme in African history from the earliest human settlements to the Apartheid regime in South Africa. It could either survey a particular period in history or choose a particular theme to emphasize, such as the “Scramble for Africa”, the impact of the slave trade, the role of newcomers from the Romans and the 5th century influx of Vandals to the Islamic conquests and the European colonists and African nationalism and fights for independ­ence after World War II. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 19),
(906, 'Topics in the History of Ideas', 'HST 340', 3, 'This course offers students a glimpse into the exiting world of intellectual history. It can either immerse the students into the intellectual tenor of a particular period through a discussion of this age’s interplay between history, philosophy, theology, literature and the arts. Or it can survey the history of a particular set of ideas, or an ideology. Students will engage primarily with primary sources, thus providing them with a firsthand feel for the history of ideas.', 19),
(907, 'Topics in the History of Science', 'HST 341', 3, 'This course will provide insight into the history of science through a focus on the development of a particular scientific field throughout history or science in general during a particular period. A key question is how science and society have impacted (and continue to impact) on each other. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 19),
(908, 'Topics in the History of Religion', 'HST 342', 3, 'This course can concentrate on a specific world religion and trace its develop­ment over time, or it can follow the comparative approach with respect to two or more religions, or, alternatively, it can choose a religious theme and follow its unfolding threads in one or more religious tradition. The major world religions usually provide the subject matter for this course: Judaism, Christianity, Islam, Mormonism, Buddhism, Hinduism, Confucianism, Shinto, Taoism, Sikhism, varieties of animism. In addition, the history of atheism may also be the focus of this course. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 19),
(909, 'Topics in Economic History', 'HST 343', 3, 'This course may concentrate on any theme in economic history, whether this is the development of economic theory itself, a discussion of economic decline and or progress in a particular region or period, the interplay of economy and ideology in the formation of ideologies such as socialism and capitalism, or the history of a particular economic sector (agriculture, industry, finance). The influence of an increasingly globalized world on production, labor, distribution of wealth, north-south dynamics, access to natural resources, and development is a central theme.', 19),
(910, 'Special Topics in History', 'HST 401', 3, 'Some possible topics could include: social history, oral history, history of slavery, history of architecture, history of changing tastes, history of ideologies, history of revolutions, comparative nationalisms, comparative empire building, causes of historical decline, and much more. Specific periods to be covered can also be designated.', 19),
(911, 'Senior Study', 'HST 499', 3, 'Every student majoring in history will be required to take this course in his/her senior year. It is a 3-credit course run seminar-style and entailing the interactive sharing of independent research by students working on the topics for their senior studies that have been agreed upon individually with the professor. Students write a supervised 40-page senior study on a topic formulated in con­sultation with a member of the history faculty.', 19),
(912, 'Introduction to Politics', 'POL 101', 3, 'A general introduction to the principal concepts of political science.  In presenting the major political ideas, political behaviors, and governing institutions, this freshman-level course investigates how political power is developed, preserved, and challenged.', 20),
(913, 'Introduction to Political Science', 'POL 201', 3, 'This course introduces students to the basic concepts of and approaches to the study of political science.  The course focuses on social science methodology, political ideologies, the state and state society relations, political parties, electoral systems, democracy, culture, institutions and international relations (IR).  A significant emphasis is placed on the ability to use these concepts toward the analysis of current political issues, disputes and trends.', 20),
(914, 'Government & Politics of Lebanon', 'POL 203', 3, 'A comprehensive survey of the political system in Lebanon from independence to the present. Detailed coverage of Lebanese politics and institutions.', 20),
(915, 'Introduction to Political Thought', 'POL 210', 3, 'This course surveys key political ideas.  Analysis and discussion of original texts and political ideas related to the general philosophy of each author’s historical and political background.', 20),
(916, 'Mediation Skills', 'POL 213', 3, 'This course provides students with an understanding of the role, and types of mediation.  It also provides students with an overview of how mediation is used as a means of resolving conflict.  The course discusses the relationship that exists between mediation and legal processes and gives students a solid grounding in the theoretical underpinnings of mediation.  The course also gives students the opportunity to learn some of the main skills involved in mediation through in-class exercises and simulations.', 20),
(917, 'Comparative Political Systems', 'POL 222', 3, 'This course provides an overview of political systems in the world and compares the ways governments operate and people behave in political life. It examines why different countries in the world implement different forms of government and electoral systems.  It compares the ways different governments interact with their respective citizens in both representation and policy making.', 20),
(918, 'Citizenship', 'POL 230', 1, 'This course will introduce the students to the multiple definitions of citizenship. It is designed to assist students to acquire the basic knowledge and attitude needed to become active and responsible citizens within the framework of a democratic political system through their direct involvement in relevant projects or case studies.', 20),
(919, 'Introduction to Human Rights', 'POL 231', 3, 'This course deals with international human rights’ policies and the moral and political issues to which they give rise. The course poses questions such as: What are human rights? Are some rights more fundamental than others, and what compelling interests, if any, justify their violation?', 20),
(920, 'Introduction to Human Rights', 'POL 231H', 3, 'This course deals with international human rights’ policies and the moral and political issues to which they give rise. The course poses questions such as: What are human rights? Are some rights more fundamental than others, and what compelling interests, if any, justify their violation?', 20),
(921, 'Basics of Conflict Resolution & Transformation', 'POL 235', 1, 'This course explores the sources, origins and dynamics of conflict resolution and transformation at different levels. It will review the major methods used to resolve and transform inter-personal, communal and international conflicts. Students will also be exposed to case studies on conflict resolution and transformation.', 20),
(922, 'Basics of Leadership', 'POL 237', 1, 'This course covers the basic concepts and definitions of leadership provided by the literature. It will cover the principles and skills that a leader should acquire and looks into the various forms of leadership in different social, political and economic contexts. It tackles a number of issues and challenges, like authority, charisma, democracy, team building, ethics and values that leaders face while performing their leadership roles through multiple forms of inquiry and learning experiences.', 20),
(923, 'Model United Nations: Diplomatic Skills & Simulation', 'POL 241', 3, 'The course explores the workings of the United Nations and expands the students’ global awareness on issues ranging from international disputes to cooperation towards development. The course initiates students to international diplomacy by letting them simulate various UN member states and investigate multilateral issues from a national perspective. The students would develop public speaking, debating, and negotiation skills; all while engaging in consensus building and learning prejudice reduction mechanisms.', 20),
(924, 'Fundamentals of Conflict Resolution', 'POL 252', 3, 'This introductory course explores the nature of conflict and a variety of tools that can be used to analyze conflict at its different levels. Drawing from broad theoretical bases, the course examines the complex causes of conflict within the framework of human rights and needs. The course introduces students to models for analyzing conflict and practical ways for responding to conflict, including skills of interpersonal communication, negotiation and mediation.', 20),
(925, 'Community Conflict and Conflict Resolution', 'POL 315', 3, 'This course focuses on the social dimension of conflict by looking at group dynamics and social interactions.  The course reviews concepts such as group formation, inter- and intra-group communication, group dynamics, cultural, religious and other influences as well as ways communal conflict manifest themselves and how conflicts tend to be resolved in communities.  Students would review group conflicts and analyze community conflicts that they are familiar with.  This course will be of significant relevance to Political Science, International Relations and Social Studies students.   The course will review the role of nongovernmental and governmental organizations in contributing to community conflict resolution. (Required core course)', 20),
(926, 'Introduction to International Conflict and Conflict Resolution', 'POL 316', 3, 'The course is designed to introduce students to the causes and dynamics of international conflict and ways they are addressed at the international level.  The course begins by reviewing the different theories that explain the emergence of international conflict.  It then studies the various factors that lead to international conflict and the dynamics that encourage conflict escalation.  Finally, the course reviews the various techniques used to intervene in such conflicts including early warning systems, first and second track diplomacy, sanctions and military intervention among others.', 20),
(927, 'Conflict Resolution Tools for the Business World', 'POL 317', 3, 'This course provides an overview of the skills and tools needed to understand different types of conflicts in a business setting. It also provides students with information on how to analyze such conflicts and review techniques used for effective intervention in such conflicts. Real life examples are used to illustrate such conflicts and the processes that have helped achieve conflict resolution or transformation. Furthermore, leadership role and cultural influences are reviewed in addition to conflict resolutions skills such as facilitation, negotiation and mediation techniques.', 20),
(928, 'Research Methodology I', 'POL 318', 3, 'This course provides students with the knowledge and skills to be able to design, conduct  and evaluate qualitative research projects in political science/international affairs.  Students will learn how to write a literature review, design a research project, including the development of research questions and hypotheses and the collection and analysis of qualitative data.', 20),
(929, 'Research Methodology II', 'POL 319', 3, 'This course provides students with the knowledge and skills needed to conduct quantitative research in political science/international affairs. Students will learn how to design a quantitative research project, including collection and analysis of quantitative data. They will further learn how to apply statistical methods to the analysis of datasets, including the analysis of variance, simple and multiple linear regression, and logistic regression. They will be also exposed to the skills in statistical computing, handling and manipulating of large datasets and using statistical software  such as SPSS.', 20),
(930, 'American Government and Politics', 'POL 321', 3, 'This course studies the structure and processes of the American political system. Topics include the nature of American democracy; the constitutional framework; political attitudes; socialization and participation, political parties and elections; and the federal decision-making process.', 20),
(931, 'American Government and Politics', 'POL 321H', 3, NULL, 20),
(932, 'Foreign Policy Analysis', 'POL 322', 3, 'A survey and analysis of the policies of the great powers in the post-cold war period. Changing patterns of ties between the great powers in light of the USSR’s disintegration and Russia’s revival; the continuing strength of the U.S.; the end of the cold war; Japan’s and Germany’s rise as economic giants; China’s economic growth; European integration and the U.N.’s revival. Domestic and international influences on great power decision-making, notably security and economic matters, are also included.', 20),
(933, 'Middle East Governments and Politics', 'POL 323', 3, 'This course surveys the major issues and problems that dominate the political scene in the Middle East, paying special attention to a number of themes including the process of post-colonial state formation; the rise of Arab nationalism and other forms of nationalism; variations in regime consolidation and state-society relations; the institutional structures of authoritarianism; the challenges of development; and the Islamist challenge, among others.', 20),
(934, 'Foreign Policy Analysis', 'POL 324', 3, 'This course introduces students to the theories and methods of Foreign Policy Analysis (FPA). It covers how foreign policy is made and who shapes it, and the outcomes and broader impact of policy choices. The course discusses how theories of international relations are relevant to FPA to understand opportunities and constraints arising from the international system. The course discusses the role of actors and processes, public opinion, individual decision-makers, group dynamics, lobby and interest groups, cognitive theories, and leadership styles by investigating the foreign policies of major, middle, and small powers during and after the Cold War. The empirical case studies focus on states in the Global North and the Global South, international organizations, and transitional actors.', 20),
(935, 'Diplomatic and Consular Services', 'POL 325', 3, 'This course covers the structure, functions, and procedures of diplomatic and consular services. It also covers the recruitment of diplomatic and consular personnel, diplomacy and diplomatic theory, and diplomatic privileges and immunities. This course will include interactive activities with diplomats and consulates through field trips to the Lebanese Foreign Ministry and to selected embassies in Lebanon.', 20),
(936, 'Politics of the European Union', 'POL 326', 3, NULL, 20),
(937, 'Fundamentals of Security Studies', 'POL 327', 3, 'The course introduces students to some of the theoretical approaches and central concepts of Security Studies. The course focuses on both traditional topics, known as ‘guns and bombs’, and non-traditional and ‘new’ threats and issues in Security Studies. The course focuses on different conceptualizations of Security, including political, military, economic, and social. The course enables students to contextualize and understand the current national and international security climate by examining core theories, concepts, and seminal historical events in the field of International Relations and Security Studies.', 20),
(938, 'Fundamentals to Public Policy', 'POL 328', 3, 'The course introduces students to the concept of public policy and to how policy makers address public needs, issues and concerns, including: economic development; taxation and spending; infrastructure; protecting the environment, Information Technology; and essential services such as education, health care, and pension plans among others.  The course draws on real life cases to explain the phases of the public policy process and to introduce the various actors, agencies and institutions involved.', 20),
(939, 'International Organization', 'POL 331', 3, 'This course covers the concepts and the evolution of international organization, the structure and the evolution of the United Nations, with emphasis on collective security, pacific settlements of disputes, peacekeeping operations and economic and social developments.', 20),
(940, 'Public International Law', 'POL 332', 3, 'This course examines the nature of international law sources, the differences between international law and municipal law and the international systems’ legal organization, states (their territory and jurisdiction) as subjects of international law, as well as international treaties and agreements, diplomatic and consular agents, laws of war, neutrality, belligerent occupation, and war crimes. Through case studies, this course examines the principle laws of nations.', 20),
(941, 'Negotiation and Bargaining', 'POL 334', 3, 'This course explores negotiation and bargaining from the individual to the international level, including both public and private sector examples.  It covers the context of negotiation, proceeds to the structure of negotiations and to the dynamics, strategy and tactics for persuading, coercing, and bargaining through to conclusion.  Group and national differences and approaches will be highlighted and demonstrated using intra-cultural negotiating exercises.', 20),
(942, 'Negotiation and Bargaining', 'POL 334H', 3, NULL, 20),
(943, 'Politics of Multiculturalism', 'POL 335', 3, 'Multiculturalism is a buzz word in current political debates and popular discussions of ethnicity and migrant communities.  This course explores why multicultural policy has become important, what kinds of minorities need to be accommodated and what kinds of policy contexts are important for multiculturalism in different countries.  The course examines sociological evidence for cultural diversity, its linkages with inter-generational socio-economic disadvantage and the political arguments for and against multiculturalism.', 20),
(944, 'Politics of the Global South', 'POL 336', 3, 'This course provides an introduction to the politics of the Global South. It addresses many of the key themes and dynamics that have shaped socioeconomic and political developments in Africa, Asia and Latin America. These include the legacies of colonialism, the achievement of independence, challenges of state building and regime consolidation, economic policy choices, the politics of class, ethnicity and gender, revolutions, the role of the military, and democratization.', 20),
(945, 'International Political Economy', 'POL 346', 3, 'This course provides students an overview of International Political Economy (IPE). It introduces students to the making of the international political economy as well as the main themes and debates in IPE. Topics covered include the nature of the international political economy, theories of IPE, the role of international institutions, the politics of international trade, complex interdependence, and foreign direct investment. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 20),
(946, 'Globalization and Political Change', 'POL 357', 3, 'This course unpacks the complex nexus between globalization, nation-states, borders, and citizenship in the 21st Century. The first section focuses on the conceptualization of globalization, its manifold causes in addition to its complex interactions with state sovereignty, social and communication networks, the politics of space, and citizenship. The second section of the course provides an in-depth analysis of key political, cultural and economic challenges that globalization has brought about. We focus on topics such as global governance and international organizations, economic inequality and free trade, the international governance of migration and borders, internet governance, ecological justice and climate change.', 20),
(947, 'Political Parties and Elections in America', 'POL 368', 3, 'This course focuses on two key elements of democratic politics using the case of the United States: political parties and elections. It explores elections, particularly presidential elections, as devices by which citizens may or may not control what their government does as well as analyzes political parties as selectors of candidates and organizers of political choices. The role of money, advertising, political activists, and the mass media are also discussed.', 20),
(948, 'Negotiation and Bargaining', 'POL 415', 3, 'This course explores negotiation and bargaining from the individual to the international level, including both public and private sector examples.  It covers the context of negotiation, proceeds to the structure of negotiations and to the dynamics, strategy and tactics for persuading, coercing, and bargaining through to conclusion.  Group and national differences and approaches will be highlighted and demonstrated using intra-cultural negotiating exercises.', 20),
(949, 'The Middle East in World Affairs', 'POL 422', 3, 'This course examines inter-state conflict in the modern Middle East. It examines contending theories of Middle East state behavior, and applies them to the main crises or events that have shaped regional dynamics. Special focus is given to the Arab-Israeli conflict, regional rivalries, the policies of the main international and regional actors, and domestic factors in shaping systemic dynamics, among other topics. The course also evaluates the causes of the different conflicts from contending theoretical perspectives.', 20),
(950, 'The Middle East in World Affairs', 'POL 422H', 3, NULL, 20),
(951, 'Diplomacy and Consular Services', 'POL 432', 3, 'This course covers the structure, functions, and procedures of diplomatic and consular services. It also covers the recruitment of diplomatic and consular personnel, diplomacy and diplomatic theory, and diplomatic privileges and immunities. This course will include interactive activities with diplomats and consulates through field trips to the Lebanese Foreign Ministry and to selected embassies in Lebanon.', 20),
(952, 'Topics in Global Governance', 'POL 434', 3, 'This course covers topics in Global Governance.', 20),
(953, 'Topics in Comparative Politics', 'POL 435', 3, 'This course covers topics in Comparative Politics.', 20),
(954, 'Topics in Middle Eastern Studies', 'POL 436', 3, 'This course covers topics in Middle Eastern Studies.', 20),
(955, 'Topics in Political Science-International Affairs', 'POL 437', 3, 'Courses designed to cover topical areas based on visiting instructors and/or current events.', 20),
(956, 'Topics in Political Science-International Affairs', 'POL 437H', 3, 'Courses designed to cover topical areas based on visiting instructors and/or current events.', 20),
(957, 'Topics in Political Science: Gender Equality in Negotiation, Mediation and Conflict Resolution', 'POL 437O', 3, '“Negotiation”, “Mediation” and “Conflict Resolution” are key skills that any professional must develop. But these skills are not limited to the workplace. Indeed, the ability to undertake effective cross-cultural, cross-gender discussions is an essential component of academic and social development. Numerous frameworks have been developed to train professionals to lead negotiations and navigate the complexities of conflict situations. Yet, few academic interventions have been developed to introduce undergraduate students to the principles and praxis of successful cross-cultural and cross-gender discussions.', 20),
(958, 'Internship', 'POL 447', 1, 'Provides the students with an opportunity to gain knowledge and skills from a planned work experience in their chosen major. It will provide learning experiences that are not available in the classroom setting. Students are expected to complete a minimum of 200 hours work in a local, regional, or international Governmental or non-Governmental organization working. Valuable work experience and credit is gained in translating theoretical and analytical skills in political science/international affairs into professional practice.', 20),
(959, 'Internship', 'POL 448', 3, 'Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 20),
(960, 'Internship', 'POL 488', 3, 'Introduction to the world of politics, government and related career fields in order to put into practice skills and theories learned in the classroom. Internships will take place at government agencies, IGOs, or NGOs approved by the department. Valuable work experience and credit is gained in translating theoretical and analytical skills in political science/international affairs into professional practice. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 20),
(961, 'Capstone Project', 'POL 499P', 3, 'The capstone course is designed to give students a culminating experience where they can focus on a project within the fields of international affairs and political science. In consultation with their instructor, students will base their capstone projects of a topic of interest, offering them an opportunity to strengthen their theoretical and applied knowledge of the subject matter by bridging theory and practice. Working in groups, students are also encouraged to pursue their choice of final deliverable that best suits their capstone, such as a poster, policy brief, or video. Students are encouraged to select a capstone topic and a final deliverable that best compliments their respective academic and professional objectives.', 20),
(962, 'Undergraduate Research', 'POL 499R', 3, 'The course aims at guiding senior standing students in an independent research project from the selection of an appropriate research design applicable to the analysis of a political question of interest through to the completion of an independent research paper.', 20),
(963, 'Psychology for All', 'PSY 101', 3, 'Psychology evolved out of both philosophy and biology. Discussions of these two subjects date as far back as the early Greek thinkers including Aristotle and Socrates. The word psychology is derived from the Greek word psyche, meaning ‘soul’ or ‘mind.’ Psychology is both an applied and academic field that studies the human mind and behavior. Research In psychology seeks to understand and explain thought, emotion and behavior. Applications of psychology include mental health treatment, performance enhancement, self-help, and many other areas affecting health and daily life.', 21),
(964, 'Introduction to Psychology', 'PSY 201', 3, 'Provides students with a general overview of the subject matter of psychology, which is defined as the scientific study of behavior and mental processes. The course aims to give students a better understanding of why people act, think, and feel the way they do. Among others, it covers topics on learning, personality, emotions, psychological disorders, social interactions, and the biological bases of behavior. Knowledge will be drawn from the major approaches of psychology, namely psychoanalytic, behavioral, humanistic, cognitive, social and biological.', 21),
(965, 'Child Psychology', 'PSY 202', 3, 'The course explores theories and research findings, on prenatal development, physical growth, emotional, social, and intellectual development, and cultural influences in children prior to adolescence.', 21),
(966, 'Development across the Life Span', 'PSY 234', 3, 'Human development through the lifespan is devoted to the study and understanding of constancy and change of human beings in the physical, cognitive, social and emotional domains interpreted through a variety of theoretical frameworks, contexts, and interdisciplinary research. The course will cover the periods of childhood, adolescence, adulthood, late adulthood and old age.', 21),
(967, 'Cultural Psychology', 'PSY 267', 3, 'The course will give students an introduction to the scientific, theoretical and applied basis of cultural psychology. Students will develop an understanding of universal and culturally shaped psychological processes and how they shape morality, religious thought, emotions, psychological health, conformity and other hot topics in the field.', 21),
(968, 'Health Psychology', 'PSY 302', 3, 'This course is designed to introduce the basic concepts of Health Psychology. Students will be introduced to different medical disorders and diseases and their impact on the psychological health and functioning of individuals with these disorders. Students will study physical limitations and adaptations. Psychological treatments of persons with disorders and physical limitations will be introduced. Topics covered will include depression and illness, traumatic injuries, neuromuscular diseases, cancer, and chronic pain. Also covered will be the use of psychological techniques to improve behaviors for wellness including smoking cessation, proper nutrition, and exercise. Such methods of treatment will include biofeedback, relaxation and behavioral goal setting.', 21),
(969, 'Introduction to Neuroscience', 'PSY 303', 3, 'This introductory neuroscience course will explore how our brains work and are formed, how our brains guide us through the changes in life, and why it is important to increase understanding of our brains. This course will allow you to discuss 1) why the brain is the body’s most important organ, 2) how brain cells communicate using both electrical and chemical signals, 3) how genetically determined brain circuits are the foundation of the nervous system, 4) how life experiences change the nervous system, 5) how intelligence arises as the brain reasons, plans, and solves problems, 6) how the brain endows us with natural curiosity to understand how the world works, and 7) how fundamental discoveries promote healthy living and the treatment of disease.', 21),
(970, 'Psychology of Youth', 'PSY 304', 3, 'This course focuses on the physical, cognitive and emotional changes experienced by young people and how these changes are affected by family, peers, dating, and the media. It also considers the challenges faced by adolescence, with a focus on drugs and deviance.', 21),
(971, 'Exceptional Child', 'PSY 311', 3, 'This course provides an introduction to the concept of exceptionality and an overview of the various forms of atypical growth and development. Course work includes psychology and identification of exceptional children. Focus is on children classified as having learning disabilities and their implications for classroom life in both special cases and inclusion setting.', 21),
(972, 'Theories of Personality', 'PSY 320', 3, 'This course provides a comprehensive coverage of the most influential theories of personality. It also examines the interplay of forces that shape the individual’s personality throughout the course of life.', 21),
(973, 'Mind and Behavior', 'PSY 322', 3, 'This course is an interdisciplinary introduction to the problems, theories and research on the human mind and other cognitive systems. The following topics will be covered: perception, memory, attention reasoning, problem solving, language comprehension, and production and cultural cognition', 21),
(974, 'Social Psychology', 'PSY 323', 3, 'Social Psychology focuses on how individual motives, cognitions, attitudes are affected by groups, organizations and institutes. These influences will be explored in domains such as interpersonal attraction, prejudice, conformity, attitudes, aggression and motivation.', 21),
(975, 'Theories of Learning', 'PSY 324', 3, 'This course provides an analysis of the factors in learning, through a survey of the major theories of learning. Special emphasis is placed on the learning principles and their implications in the teaching process.', 21),
(976, 'Psychological Assessment', 'PSY 326', 3, 'Psychological assessment is a building block of a clinical psychologist’s training. Validated and standardized tools are used in clinical research as well as in clinical assessment in the various aspects of the human existence; clinical diagnostics, characterological, personality, neurocognitive, intellectual, social and cultural. This course will expose students to methods by which psychologists conceptualize psychological measures using reliability, validity and generalizability, and teach them how to apply psychological assessment tools. Students will learn how to perform, score and interpret several psychological assessment tools varying between personality, pathology, intelligence and aptitude.', 21),
(977, 'Organizational Psychology', 'PSY 335', 3, 'Organizational psychology is the study of techniques and theories related to understanding, predicting, and managing human behavior within organizations in order to increase organizational effectiveness and individual well-being. Topics include selection, training, appraisal, job attitudes, work motivation, leadership, job design, organizational culture, and work environment.', 21),
(978, 'Research Methods', 'PSY 361', 3, 'Students will develop skills on literature search, critical review of empirical articles, hypothesis formulation, and APA writing, among others. Students will acquire skills in quantitative research and qualitative methods of data collection. The course will also cover main research designs in psychology (e.g., correlational and experimental), and issues on ethics, sampling, and reliability and validity of psychological studies. Students will design and implement a small-scale research study and will be introduced to different ways to analyze data using the SPSS statistical package and report results. The course combines both lectures and lab-based sessions.', 21),
(979, 'Abnormal Psychology', 'PSY 425', 3, 'In this course students examine the field of abnormal psychology, surveying the major psychological disorders and their classification. Emphasis is on recognizing symptoms and exposure to some treatment approaches.', 21),
(980, 'Counseling Psychology', 'PSY 466', 3, 'This course is designed to provide an introduction to the field of counseling psychology. Topics related to the contemporary counseling psychology approaches will be discussed. The core of the course will focus on theory and application. Case studies will supplement theoretical material.', 21),
(981, 'Internship', 'PSY 491', 1, 'The Academic Internship course provides students with a unique opportunity for learning about particular fields of Psychology through a combination of direct hands-on experience, formal study, collaborative learning with peers and the mentoring of junior students. The course is comprised of two main components: fieldwork at an internship site. For this component of the course some students may choose to get involved in collaborations with academic faculty or organizations in the U.S. via LAU’s New York office facilities. The second component is academic work in an internship seminar where the following topics are taken up: Ethical Issues in Professional Life, Social Justice, Legal Issues, Exploration of our skills, personality types and career aspirations, Interpersonal and Intercultural Communication. Each student is expected to spend 200 hours per semester. Pre-requisites : PSY361 Research Methods, STA302 Introduction to Statistics in Social Sciences, and senior standing.', 21),
(982, 'Topics in Psychology', 'PSY 498', 3, 'This course deals with an area of psychology, or a topic that is not usually dealt in other psychology courses. Topics will vary depending on contemporary issues in the field of psychology and students’ needs as agreed upon by the faculty of the program.', 21),
(983, 'Capstone project', 'PSY 499P', 3, 'This is the capstone course and it involves an independent empirical study on a topic chosen by the student.', 21),
(984, 'Capstone Project', 'PSY 499PH', 3, 'This is the capstone course and it involves an independent empirical study on a topic chosen by the student.', 21),
(985, 'Undergraduate Research', 'PSY 499R', 3, 'This is the undergraduate research course involving an independent empirical study on a topic chosen by the student. This course is an independent scholarly work aimed at publication.', 21),
(986, 'Sociology and Society', 'SOC 101', 3, 'This course introduces students to basic concepts in sociology. It is designed to make students understand what makes sociology a different discipline from other social sciences. It covers basic topics including, but not limited to: groups, communities and society, evolution of societies, social structure and social change, communication in society, social stratification, youth and subculture, family and kin relations, social inequality and social mobility, social integration and solidarity, culture and social values. Examples are drawn from Lebanon and elsewhere to clarify the discussion.', 22),
(987, 'Introduction to Sociology', 'SOC 201', 3, 'The course introduces students to the basic concepts and processes governing social relationships as well as scientific approaches dealing with and explaining social phenomena. Various social institutions are examined.', 22),
(988, 'Citizenship, Leadership and Civic Engagement', 'SOC 203', 3, 'This course covers the basic concepts of leadership, active citizenship and public involvement in a democratic society.  It also examines the theories and approaches that link together these three concepts. The course will cover the principles and skills that leaders and citizens should acquire to be civically engaged in different social, political and economic contexts. Students will propose and implement a civic engagement project. Exclusion: Students who take POL230 Citizenship (1 cr.) AND  POL / 237 Basics of Leadership (1 cr.) cannot take this course for credit.', 22),
(989, 'Social Psychology', 'SOC 204', 3, 'Social Psychology focuses on how individual motives, cognitions, attitudes are affected by groups, organizations and institutes. These influences will be explored in domains such as interpersonal attraction, prejudice, conformity, attitudes, aggression and motivation.', 22),
(990, 'Media and Society', 'SOC 212', 3, 'Pre-requisite(s): ENG102 Academic English II', 22),
(991, 'Introduction to Gender Studies', 'SOC 215', 3, 'This course examines what it means to be a man or a woman, from a variety of interdisciplinary perspectives. It explores the construction of masculinities and femininities in a variety of cultural contexts. Special attention is given to gender differences, and gender inequalities.', 22),
(992, 'Urban Sociology', 'SOC 303', 3, 'This course is a survey of the city as a historical development, in relation to economic, social, and political factors, from the early settlements to the development of contemporary urbanism. It deals with a broad overview of the current planning theories, from the context of modernist ideals to the social studies of planners and sociologists. Pre-requisite: SOC201 Introduction to Sociology Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 22),
(993, 'Sociology of Religion', 'SOC 304', 3, 'Pre-requisite: SOC201 Introduction to Sociology', 22),
(994, 'Social Problems: Stratification & Marginalization', 'SOC 311', 3, 'The course surveys key political ideas primarily from the Renaissance through the Enlightenment up to the beginning of the 20th century. Analysis and discussion of original texts and political ideas related to the general philosophy of each author’s historical and political background. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 22),
(995, 'Women in the Arab World', 'SOC 313', 3, 'This course examines the roles and status of Arab women in relation to various societal factors, including a brief overview of the legal rights as stated in the personal status code. Class discussions will analyze the changes by identifying determinants and patterns of change. Students are also introduced to basic gender, and feminist, perspectives on the status of women in Arab societies.', 22),
(996, 'Sociology of the Arab World', 'SOC 321', 3, 'A seminar for students interested in understanding the Arab world’s social structures with emphasis on major institutions and values, viewed from a three-dimensional perspective, namely: habitat, ethnic compositions and history.', 22),
(997, 'Politics of Multiculturalism', 'SOC 335', 3, 'Multiculturalism is a buzz word in current political debates and popular discussions of ethnicity and migrant communities. This course explores why multicultural policy has become important, what kinds of minorities need to be accommodated and what kinds of policy contexts are important for multiculturalism in different countries. The course examines sociological evidence for cultural diversity, its linkages with inter-generational socio-economic disadvantage and the political arguments for and against multiculturalism.', 22),
(998, 'Civic Engagement', 'SOC 390', 1, 'This course provides a platform to address issues of social concern across disciplines. It briefly presents the concepts of civic engagement/community service. The major component of the course is a guided community service experience based on a plan designed by the students and the course supervisor, in cooperation with the Outreach and Civic Engagement office, where applicable. Students will engage in community projects that draw upon the student’s academic discipline or that is designed to fit the student’s interest. Students will present a report that documents the said project. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 22),
(999, 'Sociological Theories', 'SOC 401', 3, 'The course is an advanced study of classical and modern sociological theories including, but not restricted to, the works of Durkheim, Marx, Weber, Bourdieu, Giddens, Hall and Norbert Elias. Pre-requisite: SOC201 Introduction to Sociology Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 22),
(1000, 'Topics in Sociology', 'SOC 488', 3, 'Pre-requisite: SOC201 Introduction to Sociology', 22),
(1001, 'Fundamentals of Gender Discrimination', 'SOC 488D', 3, 'This course is not about women. This course is not about men. This is a course about the discriminatory practices that women and men experience in various settings – public and private. Discrimination can take many forms: Racial, Economic, Political, Religious and Gendered. Arguably, we have all experienced some form of discrimination in our lifetime, and we have also been agents of perpetuating discrimination (whether we have done this consciously or not). This course introduces the fundamentals of Gender Discrimination: What does it look like? What factors perpetuate it? What is its impact on men and women? What can I do to avoid being complicit in discriminatory practices? The course engages students in active learning using Game Theory, Problem-Based Learning and Case studies of real scenarios. Students are challenged to question their own practices and perspectives, and they will be expected to contribute to the active formulation of positive and forward-looking solutions.', 22),
(1002, 'Topics in Sociology: Gender Equality in the Workplace', 'SOC 488E', 3, 'This course examines the nature of contemporary workplaces and the extent to which equal opportunities are afforded for individuals regardless of their gendered identification or their sexual orientation. We study the politics of the corporate world, the dynamics of scientific careers, the changing nature of leadership in society and politics. Our aim is to understand the ways in which the absence of gender equality impacts a country’s economic prosperity, on its ability to formulate sustainable and scientifically sound strategies that cope with fragile environments, and on its potential to participate in democratic transitions. The course covers issues of global and regional import, and focuses attention on the challenges faced in the professional cultures of the MENA region. The course engages students in active learning using Problem-Based Learning, Debates, and Case Studies of real scenarios. Students are challenged to question their own practices and perspectives, and they will be', 22),
(1003, 'Survey of Economics', 'ECO 101', 3, 'This course is a survey of main areas of economics. It introduces students to national income accounting, market mechanisms and structures, the banking and monetary systems, public finance, foreign trade, economic systems, growth and development, economic fluctuations, and economic policies. Course used for transfer of credits for BACC II holders.', 23),
(1004, 'Microeconomics', 'ECO 201', 3, 'This course is an introductory course dealing with the nature and scope of economics, consumer behavior, theory of the firm, price determination, and allocation of resources.', 23),
(1005, 'Macroeconomics', 'ECO 202', 3, 'This course is an introductory course dealing with the principles of national income accounting, national income determination, macroeconomics’ objectives and policy instruments, and the relative effectiveness of fiscal and monetary policies in stabilizing the economy.', 23),
(1006, 'Mathematical Methods for Economics', 'ECO 304', 3, 'This course covers advanced mathematical methods and tools used in modern economics. The course includes a brief calculus review, matrix theory, con- strained optimization, and elements of game theory and dynamical systems.', 23),
(1007, 'Intermediate Microeconomics', 'ECO 305', 3, 'This course covers in depth the theory and applications of consumer and producer behavior. It covers topics such as price/wage determination under various market structures, estimation of demand for a given product, analysis of a firm’s pricing strategies, levels of price discrimination, comparison of the welfare effects of different policies, and externalities and public goods.', 23),
(1008, 'Intermediate Macroeconomics', 'ECO 306', 3, 'This course uses the latest theoretical techniques and models in macroeconomics to address the measurement and determination of income, prices, employment, interest rates, and aggregate demand and supply. The course also stresses stabilization, fiscal and monetary policies, various schools of macroeconomic thought and the sources of instability in the private economy.', 23),
(1009, 'Economic Development', 'ECO 311', 3, 'This course covers the theories of economic development, planning and policies. The course also discusses the building of institutional mechanisms to achieve development.', 23),
(1010, 'Environmental, Resource, and Energy Economics', 'ECO 320', 3, 'This course introduces students to the basics of environmental and natural resource economics and the fundamentals of environmental policymaking. The first part of the course will discuss environmental pollution and policy solutions, the second part will discuss natural resource exploitation, sustainability and keys issues in energy economics. The course also highlights scientific facts that shape environmental policy debates.', 23),
(1011, 'Introductory Econometrics', 'ECO 332', 4, 'This course introduces students to the theory and practice of econometric analysis. The course will include simple regression models, multiple regression models, regression with discrete random variables, and topics in time series analysis.', 23),
(1012, 'Comparative Economic Systems', 'ECO 333', 3, 'This course will examine the basic principles and institutions of past and contemporary economies, with a special emphasis on capitalist, socialist and mixed economic systems. The course provides information on the methodology to be employed in making economic and social comparisons across countries and regions, by exploring differences in institutions, policy and performance. In addition to comparing capitalist and socialist systems, the course will study the contemporary experience of transition from one economic system to another. The course will also devote attention to the growing interest in the comparative analysis of institutions in capitalist societies, and to the historical evolution of these institutions. The course introduces students to recent comparative research on globalization and varieties of capitalism.', 23),
(1013, 'International Economics', 'ECO 335', 3, 'This course deals with the principles of trade, resource allocation among nations, international monetary and exchange rate arrangements, and trade restriction problems.', 23),
(1014, 'Economics of Organizations and Management', 'ECO 340', 3, 'This course is an introduction to the economics of organizations and management. The course focuses on decision-making within a firm and strategic inter- actions among firms in industries. The objective is to develop the knowledge and strategies useful in making efficient business or managerial decisions both within firms and between firms in different market settings. The course will also study the application of economic models to address the effectiveness of organizations.', 23),
(1015, 'Labor and Human Resource Economics', 'ECO 342', 3, 'This course introduces students to the economic analysis of labor markets and theories of human resources economics. The course includes topics in labor demand and supply, human capital accumulation, wage determination, inequality in earnings, unions and collective bargaining, training and human-resource development, productivity and pay, and labor discriminations.', 23),
(1016, 'Economics, Ethics and Philosophy', 'ECO 344', 3, 'This course is an exploration of some topics at the intersection of economics, ethics and philosophy. The course will examine the ethical and philosophical foundations of normative economics, by seeking to understand the role of efficiency and equity considerations in economic behavior and policy-making. It seeks to investigate the role of ethical theories and concepts in comprehending economic life. The course will also examine questions concerning the methodology of economics, and the distinct nature of economics as a science. Some of the topics to be explored include rationality, self-interest, value, welfare, justice, optimality, models, causality and reductionism.', 23),
(1017, 'Foundations of Political Economy', 'ECO 346', 3, 'The course will address the fundamentals of political economy: production, exchange, value, and distribution. The course mainly is an exploration of the ideas of Adam Smith, Thomas Malthus, David Ricardo, Karl Marx and John Maynard Keynes. In addition, the marginalist theory will be studied within the context of the evolution of economic thought. The basic ideas of Veblen, Hayek and Schumpeter will also be briefly discussed. The course will draw lessons for the understanding of modern capitalism, in relation to issues such as technological change, market competition, wealth creation, income distribution, instability, long-run capitalist development, morality and class conflict.', 23),
(1018, 'Special Topics in Economics', 'ECO 402', 3, 'This course deals with selected topics in economic theory.', 23),
(1019, 'Special Topics in Economics', 'ECO 402H', 3, 'This course deals with selected topics in economic theory.', 23),
(1020, 'Monetary Theory and Policy', 'ECO 420', 3, 'This course covers money and the banking system’s nature and functions. It also covers the interaction between the monetary and real sectors, money supply and demand analysis, and the theory of transmission mechanisms of monetary policy, and central banking.', 23),
(1021, 'Public Finance', 'ECO 422', 3, 'This course addresses government intervention under conditions of market failure. Topics covered include public debt, government expenditure patterns, and tax structures. These are considered from the perspective of government services provision and as public policy instruments.', 23),
(1022, 'Remedial Economics', 'ECO 511', 3, 'This course includes essential material in ECO201, ECO202. It is open as a remedial course for accepted students in the M.B.A program.', 23),
(1023, 'Applied Economics for Executives', 'ECO 710', 5, 'This course equips executives and professionals with the economic tools needed for business decision making. It provides an overview of macroeconomic and microeconomic fundamentals.  Topics include the determination of national income, economic fluctuations and economic growth. The course covers also market structures and strategic positioning of firms.', 23),
(1024, 'Monetary Theory and Policy', 'ECO 716', 5, 'The objective of this course is to provide an overview of how monetary policy interacts with financial markets. It covers the basic functioning of monetary policies in stabilizing economic activities. Topics include the role of central banks in managing and controlling monetary aggregates.', 23),
(1025, 'Fiscal Theory and Policy', 'ECO 717', 5, 'The objective of this course is to provide an overview of how fiscal policy interacts with the aggregate economy. It covers the basic functioning of fiscal policy in stabilizing economic activities. Topics include the different methods of financing government expenditures and the study of the economic basis for, and the impact of, government activity.', 23),
(1026, 'Econometrics and Forecasting', 'ECO 726', 5, 'This course introduces students to the methodology and applications of econometrics and forecasting techniques.  Students will learn how to decompose a time series into its logical elements, to assess forecasting accuracy, and to implement forecasting procedures using professional software.', 23),
(1027, 'Selected Topics in Economics', 'ECO 781', 5, 'This course discusses contemporary issues in Economics.', 23),
(1028, 'Business Economics', 'ECO 811', 3, 'This course is an overview of microeconomics from a managerial decision-making standpoint, emphasizing and applying the basic concepts to selected problems. Topics include the firm’s behavioral and managerial theories, determination of national income, demand estimation, cost determination, forecasting, and government regulation.', 23),
(1029, 'Business Economics', 'ECO 811O', 3, NULL, 23),
(1030, 'Advanced Microeconomics', 'ECO 821', 3, 'This is an introductory graduate course in microeconomic theory. Topics cover consumption theory, including choice under uncertainty, production theory, partial equilibrium, and general equilibrium in perfectly competitive markets. The course also includes a treatment of game theory. The covered material will equip students with essential microeconomic tools needed for further coursework.', 23),
(1031, 'Advanced Macroeconomics', 'ECO 822', 3, 'The course will cover advanced models of short-run economic fluctuations and long-term economic growth in modern economies. Elements of fiscal and monetary policies will also be discussed.', 23),
(1032, 'Applied Econometrics I: Cross Section and Panel Data', 'ECO 831', 3, 'This course provides students with an advanced understanding of the principles of the econometric techniques for analyzing cross-section and panel data. Topics covered include multiple regressions model, instrumental variables, discrete choice models, limited dependent variable models, and panel data methods. Emphasis will be placed on examples in applied microeconomics fields to tackle a number of current economic issues whereby students learn how to conduct empirical research.', 23),
(1033, 'Applied Econometrics II: Time Series Data', 'ECO 832', 3, 'The aim of this course is to introduce students to a comprehensive theoretical framework of time series econometrics and its applications. Topics covered include stationary univariate time series processes, non-stationary processes, multivariate processes, systems of simultaneous equations, and cointegration and error-correction models. The course involves frequent use of time series datasets with an emphasis on applications in the field of macroeconomics.', 23),
(1034, 'Applied Econometrics III: Empirical Strategies for Applied Microeconomics', 'ECO 833', 3, 'This course examines empirical strategies used in applied microeconomics with an emphasis on identification and causality. Topics include randomized trials, regression, instrumental variables, regression discontinuity designs, differences-in-differences and matching. Special emphasis will be put on real-world policy evaluation..', 23),
(1035, 'International Monetary Theory and Policy', 'ECO 835', 3, 'The course will study monetary policy models that are at the forefront of theoretical and empirical research in addition to those utilized by central banks to evaluate policies and various exchange rate arrangements. The relationship between policies and economic outcomes such as unemployment, inflation, stabilization and growth will be investigated in an open-macroeconomic setting.', 23),
(1036, 'Mathematical and Computational Models in Applied Economics', 'ECO 840', 3, 'The course will introduce mathematical and computational modeling problems of applied economics. The course will cover optimization and dynamic models. The course will include implementation of the models in computer algebra systems GAMS and MATHEMATICA.', 23),
(1037, 'Environmental and Resource Economics', 'ECO 850', 3, 'This course provides a treatment of fundamental issues in the economic approach to resource and environmental problems management. Topics covered include the economy-environment linkage, sustainable development, the theory of public goods and externalities, environmental pollution targets and instruments, and renewable and non-renewable natural resource exploitation.', 23),
(1038, 'Public Economics', 'ECO 852', 3, 'This course is a microeconomic examination of the economic role of government. The course covers theory and evidence on government expenditure and taxation policy. In the expenditure component, we examine the theories of public goods, externalities and social insurance, and applications of these theories in various sectors such as education, welfare programs, and health care. In the taxation component, topics include: tax incidence, optimal tax theory, and the effect of taxation on labor markets and corporate behavior.', 23),
(1039, 'Growth, Business Cycles and Economic Policy', 'ECO 855', 3, 'This course will study the interplay between economic policy, economic growth and business cycles in developed and developing economies. Fiscal policies aimed at stabilization and growth will be introduced from theoretical and empirical perspectives. The role of economic policy in engendering economic growth and development in developing countries will also be studied utilizing traditional and structural macroeconomic models. Examples from Great Depression, Great Recession, postwar capitalist development and developing countries experiences will be introduced.', 23),
(1040, 'Economic Policies in the Middle East', 'ECO 861', 3, 'The first part of the course studies the macroeconomic situation in the MENA region. An overview of fiscal and monetary policies, in addition to the choice of exchange rate regimes, is conducted.  The second part of the course studies public economics and policies in Middle East countries. The course investigates the provision of public goods, social security systems, health provision, and tax structures. The issues of efficiency and equity are given prime importance.', 23),
(1041, 'Challenges of Economic Development in the Middle East', 'ECO 863', 3, 'This course discusses current economic issues in the Middle East. Applying economic theory together with the institutional framework in the MENA region, important problems and challenges are analysed. Under experienced supervision, students analyse specific economic issues and present potential theoretical explanations and policy recommendations. The analysis is based on theoretical and empirical methods commonly used in economics, taking into account the relevant institutional framework in the economies under investigation.', 23),
(1042, 'Special Topics in Economics', 'ECO 880', 3, 'This course deals with selected topics in economics.', 23),
(1043, 'Applied Economics Project', 'ECO 898', 3, 'The course is a research project written under the supervision of a faculty member. Students are required to use economic models and tools to tackle an applied economics problem. Students are then required to present their work in a forum open for economics faculty and graduate students. The project may involve work outside LAU with external constituents (e.g., research institutes, specialized regional and international agencies, banks, or government entities).', 23),
(1044, 'Introduction to Environmental Science', 'ENV 200', 3, 'This is an introduction to the environmental problems and challenges facing humankind. Global problems will be directly related to issues facing the regional and local environment. The course covers environmental problems and their causes, ecosystems and how they work, deforestation, loss of biodiversity, species extinction, air pollution, global warming, ozone depletion, solid waste disposal, renewable energy technologies, and applications to alleviate environmental problems. Case studies will be presented and potential solutions will be attempted. The course includes field trips.', 24),
(1045, 'Introduction to Environmental Science', 'ENV 200H', 3, NULL, 24),
(1046, 'Climate Change Risks to Ecosystems and Biodiversity', 'ENV 210', 3, 'This course investigates climate change risks to ecosystems and biodiversity and explores methods and tools for assessing climate impacts to ecosystems, species and human livelihoods. Course topics include the climate system and greenhouse effect; changes in palaeoclimate and their impacts on ecosystems and species distributions; more recent climate changes and their observed impacts; mechanisms by which climate affects ecosystems; projections of future climate change and potential impacts on ecosystems, ecosystem goods and services, and human livelihoods; ecological niche modelling; biogeography models; dynamic vegetation models; and social science methods for assessing human consequences of ecosystem changes and biodiversity losses. At the end of the course, the students will work in teams to develop and present case studies of climate change threats to the biodiversity around the world. Note: This course has not been thought since Fall 2023  and will not be taught in this academic y', 24),
(1047, 'Conserving Biodiversity in a Changing Climate', 'ENV 211', 3, 'Students of the course will examine current conservation strategies in terms of their effectiveness in addressing changing risks under a changing climate and will learn to develop new and/or modified strategies where necessary to address these risks. Students will also learn to use methods and tools that can assess ecosystem responses to climate variability and change and thus guide the development of new/modified conservation strategies. Course topics include: The role of ecosystems and biodiversity in sustaining the planet and major stresses; traditional approaches to biodiversity conservation including legal and policy aspects as well as community scale strategies; effectiveness of traditional approaches; approaches to designing landscapes for protecting ecosystems and biodiversity under climate change; use of spatial analysis tools to guide landscape design; management strategies; policies and tools for protecting matrix areas; community participation; planning for long term monito', 24),
(1048, 'Social Aspects of Renewable Energy for Rural Development', 'ENV 222', 3, '“Rich are getting richer while the poor are getting poorer”. This can be described as the most commonly used phrase in the 21st century. This situation gets worse with the increasing prices of basic human needs such as food, clothing, and energy supply. Energy has become a critical issue in both urban and rural areas. While the first appears to have enough resources to cover up their demand and avoid economic drops, rural regions remain poor at resources and potential, and mainly suffer from shortage in energy supply leading to a deterioration in their social and economic standing. The course offers students a deep understanding of the role renewable energy plays in sustainable rural development, cleaner technology incorporation and the potential for mitigating climate change impacts on the poor. It allows students to study the various renewable energy applications that can be utilized in rural regions at low cost for improved social standing. During the course, students will examine t', 24),
(1049, 'Financing Renewable Energy', 'ENV 223', 3, 'With frequent increasing fluctuation of oil prices, the shift towards renewable energy is becoming more and more realistic. Nations are adopting renewable energy strategies to avoid remaining hand-tied and improve energy security, always with environmental concerns in mind. With the remarkable technical advancements and the growing target market, renewable energy has become an option that every community and every family discuss going for it and reducing fossil fuel consumption. But the major barrier remains, which is the financing requirements of renewable energy projects. There is no doubt that renewables do have less operating expenses compared to conventional energy, and less maintenance as well in so many conditions, but the capital investment is still too high to compare to a fuel oil or natural gas power plants. This requires a well-structured financing mechanism, a sustainable mechanism that would promote the use of clean energy and reduce the human impact on the environment. T', 24),
(1050, 'World Ocean Solutions', 'ENV 224', 3, 'More than 70% of earth surface is water, leaving less than 30% for human utilization for various activities. Around 361,130,976 square kilometers is the total surface area of water on earth that has proven to be rich in resources and potential. Human have started benefiting from these resources mainly focusing on fishing and oil extraction, but there is more potential than just this. The terrifyingly growing population that is expected to exceed 9 billion in2050, and the depletion of resources, together put a lot of pressure on food, water, and energy supplies, thus threaten biodiversity and contribute to climate deterioration. This course explores untapped potential within the world ocean (oceans and seas) and studies its capacity in providing human basic needs to reduce food, water, and energy supply stress. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 24),
(1051, 'Energy in Buildings', 'ENV 225', 3, 'Buildings are reported to share more than 40% of the global energy consumption, and emitting large amounts of greenhouse gases that are contributing to climate change and global warming. Buildings are the highest electricity consuming sector, especially residential buildings that are occupied 24/7, consuming electricity mainly for lighting, air conditioning, and water heating purposes. The course presents the concept of energy conservation in buildings and the role it plays in reducing greenhouse gas emissions. It illustrates the different green building design systems and shows the economic and environmental benefits behind efficient building design and operation. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 24),
(1052, 'Sustainability in Practice', 'ENV 230', 3, 'Defined as “meeting the needs of the present without compromising the ability of future generations to meet their own needs”, sustainability has become one of the hottest topics in the 21st century. International agencies and organizations have clearly declared their commitment to establish more sustainable processes and operations in which a future for our kids and grandkids is guaranteed. This course tackles sustainability from its practical perspective, and studies human actions and capabilities to handle global change, climatic deterioration, ecosystem degradation, and resource depletion. It covers the millennium development goals and the factors directly linked to achieving them. Factors such as growing population, energy demand, water scarcity, climate change, and environmental economics will be discussed. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 24),
(1053, 'Environmental Policy and  Management', 'ENV 402', 3, 'This course explores human made problems in the environment parallel with concepts in environmental ethics, management and policies so as solutions are provided concerning preservation of the environment. Topics covered include toxic and solid wastes; pollution of air, water, food and soil; and international and national environmental ethics, management and policies. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 24),
(1054, 'Environmental Impact Assessment', 'ENV 422', 3, 'This course is the study and evaluation of the impacts of large scale projects on the quality of the physical, biological, and socio-economic environment taking into account environmental laws and regulations, and EIA guidelines. The course also addresses the identification of impact, quantification methods, mitigation measures, and monitoring plans as well as a case study involving the preparation of an EIA REPORT. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 24),
(1055, 'Environmental Microbiology', 'ENV 423', 3, 'This ecologically based course discusses the relationship of microorganisms with one another and with their environment. It stresses the three major domains of life – Eucaryota, Archaea and Bacteria and studies their diversity, interactions and physiology in their natural environments. Biodegradation of organic matter, bio-geo-cycling of minerals and waste bio-treatment are emphasized. The course also deals with metagenomic, metaproteomic techniques and applications as well as the use of microarrays in Microbial Ecology. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 24),
(1056, 'Environmental Remediation', 'ENV 426', 3, 'This course deals with processes employing microorganisms, fungi, plants or their enzymes to return contaminated environments, such as polluted waters and soils, to their natural condition. The control, optimization and monitoring of bioremediation is discussed as well as the environmental factors and microbial populations involved. In-situ, ex-situ applications and genetic engineering approaches are emphasized. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 24),
(1057, 'Environmental Physics', 'ENV 427', 3, 'The course comprises aspects of atmospheric physics, soil physics and many aspects of applied physics.   It introduces the essentials in environmental physics, and describes the basics in environmental spectroscopy e.g. black body radiation and the solar UV and Life.  It also addresses the global climate, energy balance, energy available for human use, transport of pollutants, and noise pollution.  The course also discusses risk estimations, energy saving and nature and future thinking in the context of the global society. Note: This course has not been thought since Fall 2023  and will not be taught in this academic year 2025–2026.', 24),
(1058, 'Data Science and its Applications', 'CYS 610', 3, NULL, 25),
(1059, 'Design and Analysis of Algorithms', 'CYS 611', 3, NULL, 25),
(1060, 'AI for Cybersecurity', 'CYS 612', 2, NULL, 25),
