(1067, 'Fundamentals of Database Systems', 'CYS 619', 3, NULL, 25),
(1068, 'Information Security', 'CYS 621', 3, NULL, 25),
(1069, 'Deep Learning and its Applications', 'CYS 622', 3, NULL, 25),
(1070, 'Natural Language Processing with Deep Learning', 'CYS 623', 2, NULL, 25),
(1071, 'Reinforcement Learning', 'CYS 624', 2, NULL, 25),
